-- Poems batch 195
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('b81b9076-3d0c-46a7-9ce8-f79202aa2daa','偈頌一百三十三首  其六三','釋法薰','宋','宋诗','song-poetry','','[]','慧日峰高，門庭壁立。',20,'全唐诗/poet.song.186000.json','["慧日峰高，門庭壁立。", "放一線開，從這裏入。"]'),
('2ba9c646-f73d-4a90-a46b-b3db8656389f','偈頌一百三十三首  其六四','釋法薰','宋','宋诗','song-poetry','','[]','一徑直，二周遮。',24,'全唐诗/poet.song.186000.json','["一徑直，二周遮。", "擒虎兕，辨龍蛇。", "白玉無瑕却有瑕。"]'),
('e341cd78-1c03-4b76-a1d5-5ffd6dced664','偈頌一百三十三首  其六五','釋法薰','宋','宋诗','song-poetry','','[]','九重降旨，闔國咸知。',36,'全唐诗/poet.song.186000.json','["九重降旨，闔國咸知。", "一句當頭，諸人未委。", "只如新長老，寧可截舌，不犯國諱。"]'),
('1c15f2a0-7f5a-40b1-86c0-16cf52d9dd1f','偈頌一百三十三首  其六六','釋法薰','宋','宋诗','song-poetry','','[]','向上一路，千聖不然。',22,'全唐诗/poet.song.186000.json','["向上一路，千聖不然。", "目前無異草，脚下有青天。"]'),
('4011a52d-f99a-400f-be2b-187598998e25','偈頌一百三十三首  其六七','釋法薰','宋','宋诗','song-poetry','','[]','衆流成海，衆毛成毬。',32,'全唐诗/poet.song.186000.json','["衆流成海，衆毛成毬。", "一棚俊鶻，儒雅風流。", "石田無一事，坐地看楊州。"]'),
('96bcfd09-04f6-4e92-a56a-f88e922912c0','偈頌一百三十三首  其六八','釋法薰','宋','宋诗','song-poetry','','[]','石田乍到，人事紛紛。',38,'全唐诗/poet.song.186000.json','["石田乍到，人事紛紛。", "拈得鼻孔，失却眼睛。", "佛法二字，不怕爛却，且聽諸方行棒喝。"]'),
('d0c5e938-2382-4698-bddb-3979e72a2d65','偈頌一百三十三首  其六九','釋法薰','宋','宋诗','song-poetry','','[]','千五百人善知識，不念吾宗正岑寂。',50,'全唐诗/poet.song.186000.json','["千五百人善知識，不念吾宗正岑寂。", "五峰趯倒浪翻空，大地山河俱失色。", "金風體露，葉落歸根，只堪惆悵不堪陳。"]'),
('dd3dd1f2-ad9e-4a7b-82a8-8f61a23f5276','偈頌一百三十三首  其七○','釋法薰','宋','宋诗','song-poetry','','[]','不結毗盧印，那弘古佛心。',24,'全唐诗/poet.song.186000.json','["不結毗盧印，那弘古佛心。", "明月照幽谷，寒濤助夜砧。"]'),
('e5e254dc-697b-4033-8310-72e4d490a731','偈頌一百三十三首  其七一','釋法薰','宋','宋诗','song-poetry','','[]','至人變化，體妙難名。',50,'全唐诗/poet.song.186000.json','["至人變化，體妙難名。", "去來不以象，動靜不以形。", "通途自寥邈，何處不稱尊。", "更無一法可當情，直踏毗盧頂上行。"]'),
('8006a16d-d785-4d7e-9baf-8f3f4c66ec80','偈頌一百三十三首  其七二','釋法薰','宋','宋诗','song-poetry','','[]','獨能崗上，慧日峰前。',44,'全唐诗/poet.song.186000.json','["獨能崗上，慧日峰前。", "雲月是同，溪山各異。", "正法眼，破沙盆。", "勸君更盡一杯酒，西出陽關無故人。"]'),
('2b2e12ef-e512-48c6-8c3b-eaaeec27f535','偈頌一百三十三首  其七三','釋法薰','宋','宋诗','song-poetry','','[]','風蕭蕭，雨蕭蕭，絲毫不動，平步丹霄。',33,'全唐诗/poet.song.186000.json','["風蕭蕭，雨蕭蕭，絲毫不動，平步丹霄。", "便恁麽去，南山門下，土亦難消。"]'),
('1c40f9c4-18ed-4a4e-a4d5-f8591d45781a','偈頌一百三十三首  其七四','釋法薰','宋','宋诗','song-poetry','','[]','赤肉團上，壁立萬仞。',42,'全唐诗/poet.song.186000.json','["赤肉團上，壁立萬仞。", "臨濟德山，因邪打正。", "羅紋結角，百匝千重。", "等閑拋一釣，驚起碧潭龍。"]'),
('ea0e9218-0fda-42c7-9225-ee44f3b41d44','偈頌一百三十三首  其七五','釋法薰','宋','宋诗','song-poetry','','[]','寸絲不掛，赤肉猶存。',32,'全唐诗/poet.song.186000.json','["寸絲不掛，赤肉猶存。", "黄頭碧眼，叫屈無門。", "我行荒草裏，汝又入深村。"]'),
('6e0ee54c-b094-45e8-9d6e-eff250d27bc5','偈頌一百三十三首  其七六','釋法薰','宋','宋诗','song-poetry','','[]','萬古長空，一朝風月。',36,'全唐诗/poet.song.186000.json','["萬古長空，一朝風月。", "有祖以來，話作兩橛。", "石田好是明明說，八十翁翁嚼生鐵。"]'),
('8abf3bb2-1866-43e2-88af-719366e14394','偈頌一百三十三首  其七七','釋法薰','宋','宋诗','song-poetry','','[]','古今日月，依舊山河。',28,'全唐诗/poet.song.186000.json','["古今日月，依舊山河。", "新年佛法，特地干戈。", "水到滄溟不是波。"]'),
('c2f215b4-38ec-45cb-a9af-79c1da8ae86a','偈頌一百三十三首  其七八','釋法薰','宋','宋诗','song-poetry','','[]','盡大地不是自己，參天荆棘。',50,'全唐诗/poet.song.186000.json','["盡大地不是自己，參天荆棘。", "盡大地總是自己，滿目塵埃。", "橫三豎四，捏聚放開。", "要與南山相見，還我第一籌來。"]'),
('1cdf2756-5d4c-43ae-ba5f-7f890fda033c','偈頌一百三十三首  其七九','釋法薰','宋','宋诗','song-poetry','','[]','明如日，黑如漆。',32,'全唐诗/poet.song.186000.json','["明如日，黑如漆。", "通天大路，萬重鐵壁。", "南山口似血盆，爭敢妄通消息。"]'),
('a9965c11-c74e-47b9-85c2-19c033065784','偈頌一百三十三首  其八○','釋法薰','宋','宋诗','song-poetry','','[]','至道無難，惟嫌揀擇。',42,'全唐诗/poet.song.186000.json','["至道無難，惟嫌揀擇。", "山河大地，日月星辰。", "草木叢林，鳥獸人畜。", "不是龍門客，切忌遭點額。"]'),
('35441127-63c4-4c0f-90c4-2ca66a856d86','偈頌一百三十三首  其八一','釋法薰','宋','宋诗','song-poetry','','[]','一生空拽露布，末後又把不住。',50,'全唐诗/poet.song.186000.json','["一生空拽露布，末後又把不住。", "滅度不滅度，總非吾弟子，破布囊盡底翻出。", "蒼天中更添冤苦，可惜黄金成糞土。"]'),
('eaf80c99-8e93-4753-9b02-67b1f2687dcc','偈頌一百三十三首  其八二','釋法薰','宋','宋诗','song-poetry','','[]','不著佛求，不著法求，不著僧求。',37,'全唐诗/poet.song.186000.json','["不著佛求，不著法求，不著僧求。", "春花爛熳，春事綢繆。", "若將春意會，特地惹春愁。"]'),
('cb5c6872-57d7-4412-90b1-353f8e494ab1','偈頌一百三十三首  其八三','釋法薰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','悉達今朝出母胎，無端滿目是塵埃。',32,'全唐诗/poet.song.186000.json','["悉達今朝出母胎，無端滿目是塵埃。", "山僧傾倒西湖水，索性從頭洗一回。"]'),
('de7413bd-68a1-4cc3-8221-ebc178825fa4','偈頌一百三十三首  其八四','釋法薰','宋','宋诗','song-poetry','','[]','四月十五同結，此土西天不別。',32,'全唐诗/poet.song.186000.json','["四月十五同結，此土西天不別。", "殺盡安居，只得一橛，楊花不是天邊雪。"]'),
('bee29c7b-f348-48d1-bfa3-8f57915253c0','偈頌一百三十三首  其八五','釋法薰','宋','宋诗','song-poetry','','[]','是句亦剗，非句亦剗。',36,'全唐诗/poet.song.186000.json','["是句亦剗，非句亦剗。", "公案見成，打疊不辨。", "瞎馿趁隊過新羅，臨濟德山空眨眼。"]'),
('28c9df01-05d5-424e-87de-1c4bc2f81c33','偈頌一百三十三首  其八六','釋法薰','宋','宋诗','song-poetry','','[]','眼似流星，機如掣電。',32,'全唐诗/poet.song.186000.json','["眼似流星，機如掣電。", "過得南山門，未見南山面。", "天氣稍熱，別時相見。"]'),
('0b4f99e5-fccc-457f-9070-b0814e888fc1','偈頌一百三十三首  其八七','釋法薰','宋','宋诗','song-poetry','','[]','摩耶佛母，現女主身。',54,'全唐诗/poet.song.186000.json','["摩耶佛母，現女主身。", "退藏於密，得一以寧。", "貴無敵，富無倫。", "節逢壽慶，四海歡聲。", "願將西祖真消息，仰祝皇齡萬萬春。"]'),
('1b348ff4-da40-41a5-a140-4afe3d843fc7','偈頌一百三十三首  其八八','釋法薰','宋','宋诗','song-poetry','','[]','一不成，二不是。',18,'全唐诗/poet.song.186000.json','["一不成，二不是。", "建立乖宗，掃除失旨。"]'),
('d12714e4-49d4-42e2-b6aa-99dc9ebd4b6e','偈頌一百三十三首  其八九','釋法薰','宋','宋诗','song-poetry','','[]','佛法二字，不怕爛却。',30,'全唐诗/poet.song.186000.json','["佛法二字，不怕爛却。", "俊快衲僧，隔牆見角。", "臨濟德山，蹉過一著。"]'),
('81b0a967-533f-4d8a-8106-b91ec531215e','偈頌一百三十三首  其九○','釋法薰','宋','宋诗','song-poetry','','[]','巧盡拙出，水到渠成。',34,'全唐诗/poet.song.186000.json','["巧盡拙出，水到渠成。", "舉足下足，十字縱橫。", "三千里外，已被南山換却眼睛。"]'),
('4f4b8733-4e6a-41e7-921e-0da91ad6748c','偈頌一百三十三首  其九一','釋法薰','宋','宋诗','song-poetry','','[]','雪峰輥毬，禾山打皷。',20,'全唐诗/poet.song.186000.json','["雪峰輥毬，禾山打皷。", "要覓旨歸，月不破五。"]'),
('4549d4fc-13b7-49c2-8462-1e58e2945112','偈頌一百三十三首  其九二','釋法薰','宋','宋诗','song-poetry','','[]','取不得，捨不得，狀不得。',38,'全唐诗/poet.song.186000.json','["取不得，捨不得，狀不得。", "西天碧眼胡，盡力道不識。", "識不識，臨際德山，太平姦賊。"]'),
('8c8b3c8b-7b22-40c9-967e-0111c3e465dc','偈頌一百三十三首  其九三','釋法薰','宋','宋诗','song-poetry','','[]','息慮迷源，明機自昧。',50,'全唐诗/poet.song.186000.json','["息慮迷源，明機自昧。", "祖師知有處，諸人不知。", "諸人知有處，祖師不會。", "知不知，會不會，國有憲章，三千條罪。"]'),
('d2b2afb5-5416-412e-b9b3-3bf95897eed7','偈頌一百三十三首  其九四','釋法薰','宋','宋诗','song-poetry','','[]','有祖以來，遞相欺誑。',36,'全唐诗/poet.song.186000.json','["有祖以來，遞相欺誑。", "兩兩三三，隔靴抓癢。", "山僧有口未曾開，早已龜毛長數丈。"]'),
('ea2d7e71-d801-4714-8cf3-65c8d2318e3c','偈頌一百三十三首  其九五','釋法薰','宋','宋诗','song-poetry','','[]','見得徹，用得親。',36,'全唐诗/poet.song.186000.json','["見得徹，用得親。", "陽春不同調，入水見長人。", "可惜黄金如糞土，撒向閻浮人不顧。"]'),
('f4fbe137-cc42-4380-bc7a-eefe62558a24','偈頌一百三十三首  其九六','釋法薰','宋','宋诗','song-poetry','','[]','飽叢林，沒量漢，法戰當先，清機歷掌。',32,'全唐诗/poet.song.186000.json','["飽叢林，沒量漢，法戰當先，清機歷掌。", "假饒千佛出頭，也下一槌定當。"]'),
('132b98ee-f873-4a3b-bd9b-ebd0aa0d8037','偈頌一百三十三首  其九七','釋法薰','宋','宋诗','song-poetry','','[]','深聞淺悟，淺聞深悟。',20,'全唐诗/poet.song.186000.json','["深聞淺悟，淺聞深悟。", "只知貪程，不覺蹉路。"]'),
('28321eb4-f2a4-4e58-89ca-907c276d84e1','偈頌一百三十三首  其九八','釋法薰','宋','宋诗','song-poetry','','[]','天無門，地無戶。',36,'全唐诗/poet.song.186000.json','["天無門，地無戶。", "文殊維摩，撒手歸去。", "衲僧向這裏插得嘴，南山分半院與你住。"]'),
('f0f59eff-663b-49e8-8932-c11ac4b49516','偈頌一百三十三首  其九九','釋法薰','宋','宋诗','song-poetry','','[]','深固幽遠，無人能到。',32,'全唐诗/poet.song.186000.json','["深固幽遠，無人能到。", "山前一片閑田，松竹清風浩浩，缺齒老胡不得妙。"]'),
('6699434b-b2bc-4613-a652-8447de3f65fe','偈頌一百三十三首  其一○○','釋法薰','宋','宋诗','song-poetry','','[]','九年坐兀兀，胡僧無妙訣。',24,'全唐诗/poet.song.186000.json','["九年坐兀兀，胡僧無妙訣。", "長安路坦然，夜行人不絕。"]'),
('c195de37-9abd-43b3-b985-69049fb52812','偈頌一百三十三首  其一○一','釋法薰','宋','宋诗','song-poetry','','[]','布袋頭結，聖凡路絕。',28,'全唐诗/poet.song.186000.json','["布袋頭結，聖凡路絕。", "蠟人冰，鵝護雪。", "西天恁麽，此土還別。"]'),
('d03f131f-c039-4efb-a160-13a0fc9b2bb7','偈頌一百三十三首  其一○二','釋法薰','宋','宋诗','song-poetry','','[]','直下是，直下是，沒量大人，擡脚不起。',34,'全唐诗/poet.song.186000.json','["直下是，直下是，沒量大人，擡脚不起。", "可憐伎死杜禪和，猶是嘵嘵掛唇齒。"]'),
('c9caf907-7143-45b0-8133-11cccc7ce054','偈頌一百三十三首  其一○三','釋法薰','宋','宋诗','song-poetry','','[]','前佛紀綱，後佛性命。',34,'全唐诗/poet.song.186000.json','["前佛紀綱，後佛性命。", "衲僧腰間古曆日，定是三年逢一閏，不知東平打破鏡。"]'),
('d36a77c5-1865-4656-939e-95475bdaaf1c','偈頌一百三十三首  其一○四','釋法薰','宋','宋诗','song-poetry','','[]','溪東溪西水牯，四海五湖皇化。',54,'全唐诗/poet.song.186000.json','["溪東溪西水牯，四海五湖皇化。", "俱胝指頭禪，一生受用不盡，趙州無揀擇，五年分疎不下。", "南山忍俊不禁，今日輕酬重價。"]'),
('e4590822-93fe-4978-83b3-4023e7e5a1ff','偈頌一百三十三首  其一○五','釋法薰','宋','宋诗','song-poetry','','[]','肥儱俑，無腹孔。',16,'全唐诗/poet.song.186000.json','["肥儱俑，無腹孔。", "不識字，有錢用。"]'),
('5792e820-a319-4888-a6b3-0f6cef87a597','偈頌一百三十三首  其一○六','釋法薰','宋','宋诗','song-poetry','','[]','一夏過半，久參事慢。',20,'全唐诗/poet.song.186000.json','["一夏過半，久參事慢。", "伶俐衲僧，一咬便斷。"]'),
('3cde5014-785e-4506-ae48-317d14288251','偈頌一百三十三首  其一○七','釋法薰','宋','宋诗','song-poetry','','[]','不坐空王殿，不掛本來衣。',24,'全唐诗/poet.song.186000.json','["不坐空王殿，不掛本來衣。", "何須便恁麽，切忌未生時。"]'),
('3138c188-daa8-465e-a4b0-a80e20780856','偈頌一百三十三首  其一○八','釋法薰','宋','宋诗','song-poetry','','[]','三通皷罷，簇簇上來。',26,'全唐诗/poet.song.186000.json','["三通皷罷，簇簇上來。", "諸人減却多少威光，南山入地三尺。"]'),
('b4f123a6-02df-4480-9fbd-eecbde54601f','偈頌一百三十三首  其一○九','釋法薰','宋','宋诗','song-poetry','','[]','當頭一句，無過直與。',25,'全唐诗/poet.song.186000.json','["當頭一句，無過直與。", "南山有口，不敢錯舉，笑破露柱。"]'),
('126cf4d0-b128-47f8-93f7-019a76607907','偈頌一百三十三首  其一一○','釋法薰','宋','宋诗','song-poetry','','[]','祖師門下，尺水丈波。',58,'全唐诗/poet.song.186000.json','["祖師門下，尺水丈波。", "若也覷得破，輪王髻中珠分文不直。", "若覷不破，迦葉糞掃衣價重娑婆。", "千箇萬箇伎死禪和，臨濟德山將奈何。"]'),
('9e06a14b-0d30-4ed8-b370-4d2ddbc86a7f','偈頌一百三十三首  其一一一','釋法薰','宋','宋诗','song-poetry','','[]','禁足護生，西天此土。',20,'全唐诗/poet.song.186000.json','["禁足護生，西天此土。", "盡是死門，終非活路。"]'),
('3ca0009d-e30b-48f0-a72b-f5173e0d03b7','偈頌一百三十三首  其一一二','釋法薰','宋','宋诗','song-poetry','','[]','從上佛祖逆風揚塵，後代兒孫日中迷路。',34,'全唐诗/poet.song.186000.json','["從上佛祖逆風揚塵，後代兒孫日中迷路。", "却憶禾山老古錐，逢人偏道解打皷。"]'),
('2be19b8c-d3d1-423e-8838-8482fbbaa030','偈頌一百三十三首  其一一三','釋法薰','宋','宋诗','song-poetry','','[]','東頭貴買，西頭賤賣。',24,'全唐诗/poet.song.186000.json','["東頭貴買，西頭賤賣。", "田地穩密衲僧，不妨遊戲自在。"]'),
('5ae137e7-8e1c-47e6-b127-eddaa74c807d','偈頌一百三十三首  其一一四','釋法薰','宋','宋诗','song-poetry','','[]','和尚子，莫妄想。',37,'全唐诗/poet.song.186000.json','["和尚子，莫妄想。", "懷州牛喫禾，益州馬腹脹。", "南山饒你七穿八穴，也未免手中痛棒。"]'),
('ffa56d44-d448-49fc-8a2f-4d57eee5e217','偈頌一百三十三首  其一一五','釋法薰','宋','宋诗','song-poetry','','[]','相見不須瞋，君窮我亦貧。',24,'全唐诗/poet.song.186000.json','["相見不須瞋，君窮我亦貧。", "謂言侵早起，更有夜行人。"]'),
('a2a0bdda-02a2-4b12-b4cb-af9b186bd2cf','偈頌一百三十三首  其一一六','釋法薰','宋','宋诗','song-poetry','','[]','南斗七，北斗八。',36,'全唐诗/poet.song.186000.json','["南斗七，北斗八。", "風來樹動，魚行水濁。", "諸人三十年後眼開，莫道南山有口無舌。"]'),
('07931c6d-2d3f-4d37-a9e3-915bda21440c','偈頌一百三十三首  其一一七','釋法薰','宋','宋诗','song-poetry','','[]','九十日安居，徧地無行路。',44,'全唐诗/poet.song.186000.json','["九十日安居，徧地無行路。", "意不停玄，眼不掛戶。", "布袋頭開，乾坤獨露。", "萬里寸草無，踏著不相似。"]'),
('8524476a-211c-4a06-9f35-040c4aacad2f','偈頌一百三十三首  其一一八','釋法薰','宋','宋诗','song-poetry','','[]','推不進前，約不退後。',36,'全唐诗/poet.song.186000.json','["推不進前，約不退後。", "臨濟白拈，未是好手。", "南山不惜兩莖眉，玉筯空將撐虎口。"]'),
('d893424d-62ff-47f4-a807-a7ec4875954f','偈頌一百三十三首  其一一九','釋法薰','宋','宋诗','song-poetry','','[]','吾常於此切，密意在汝邊。',24,'全唐诗/poet.song.186000.json','["吾常於此切，密意在汝邊。", "麟龍不爲瑞，鶴龜自成僊。"]'),
('961c7d9f-d6e8-4530-afb1-0a123522078e','偈頌一百三十三首  其一二○','釋法薰','宋','宋诗','song-poetry','','[]','東西南北，𡎺著磕著，四維上下，天平地平。',76,'全唐诗/poet.song.186000.json','["東西南北，𡎺著磕著，四維上下，天平地平。", "佛法大有在，只是無人證明。", "咄，我行荒草裏，你又入深村。", "長者長法身，短者短法身。", "袖頭打領，腋下剜襟，即不問你諸人。"]'),
('facaf3fc-8bf9-4ead-940e-79e9f1d1fe99','偈頌一百三十三首  其一二一','釋法薰','宋','宋诗','song-poetry','','[]','棒喝交馳如雷掣，顛言倒語三寸舌。',32,'全唐诗/poet.song.186000.json','["棒喝交馳如雷掣，顛言倒語三寸舌。", "南州打到北州頭，甕裏何曾失却鱉。"]'),
('d165be1c-7059-4a7c-855f-5d5b0b48a130','偈頌一百三十三首  其一二二','釋法薰','宋','宋诗','song-poetry','','[]','養子不及父，家門一世衰。',39,'全唐诗/poet.song.186000.json','["養子不及父，家門一世衰。", "過山尋蟻跡，能有幾人知。", "老和尚你知我知，莫教漏泄天機。"]'),
('cfe21dce-b600-46bc-8cfb-697b79ba9416','偈頌一百三十三首  其一二三','釋法薰','宋','宋诗','song-poetry','','[]','冷水點沸鍋，舌頭不出口。',24,'全唐诗/poet.song.186000.json','["冷水點沸鍋，舌頭不出口。", "可惜老巖頭，慈悲成過咎。"]'),
('1f795459-90d4-4a7a-9812-6ba11e5a86bb','偈頌一百三十三首  其一二四','釋法薰','宋','宋诗','song-poetry','','[]','秋風凋敗葉，遊子未歸家。',40,'全唐诗/poet.song.186000.json','["秋風凋敗葉，遊子未歸家。", "直饒歸得後，無處立生涯。", "白蘋紅蓼對蘆花，令人長憶老玄沙。"]'),
('767f0c66-fe69-4a42-8d09-359ab1fbc81e','偈頌一百三十三首  其一二五','釋法薰','宋','宋诗','song-poetry','','[]','指天指地，討甚巴鼻。',34,'全唐诗/poet.song.186000.json','["指天指地，討甚巴鼻。", "釘釘膠粘，刀刮水洗。", "兒孫一杓香湯，大似恭而無禮。"]'),
('adf2d123-a5c4-4915-bc54-4d60468bcb8c','偈頌一百三十三首  其一二六','釋法薰','宋','宋诗','song-poetry','','[]','古人一期恁麽道，白玉無瑕却有瑕。',26,'全唐诗/poet.song.186000.json','["古人一期恁麽道，白玉無瑕却有瑕。", "路途之樂，終不到家。"]'),
('b3324f5c-e2a9-4844-89f2-3500f110a1eb','偈頌一百三十三首  其一二七','釋法薰','宋','宋诗','song-poetry','','[]','釋迦已往，彌勒未生。',34,'全唐诗/poet.song.186000.json','["釋迦已往，彌勒未生。", "正當無佛世界，大地共樂昇平。", "不圖打草，只要蛇驚。"]'),
('7cf2d085-2f57-4057-ac5f-ada011c6e535','偈頌一百三十三首  其一二八','釋法薰','宋','宋诗','song-poetry','','[]','九十日飯錢且置，漿水錢教誰還。',31,'全唐诗/poet.song.186000.json','["九十日飯錢且置，漿水錢教誰還。", "若是眼生三角，衲僧便解乘時豹變。"]'),
('be1c6f06-ce95-4e97-a135-90d490bc74e4','偈頌一百三十三首  其一二九','釋法薰','宋','宋诗','song-poetry','','[]','妙旨迅速，言說來遲。',20,'全唐诗/poet.song.186000.json','["妙旨迅速，言說來遲。", "龍門上客，未舉先知。"]'),
('59bd1830-a36f-4925-9c9c-cd5719d5d7c7','偈頌一百三十三首  其一三○','釋法薰','宋','宋诗','song-poetry','','["\u8861\u5c71"]','九夏安居畢，布袋結頭開。',43,'全唐诗/poet.song.186000.json','["九夏安居畢，布袋結頭開。", "衲僧無定度，南嶽與天台。", "中路𡎺著脚指頭，方知南山一夏不辜負你。"]'),
('28e24b9e-cdf4-4200-999f-f6aa0598b4fc','偈頌一百三十三首  其一三一','釋法薰','宋','宋诗','song-poetry','','[]','通天大路，鐵壁萬重。',28,'全唐诗/poet.song.186000.json','["通天大路，鐵壁萬重。", "全機拶透，笑破虛空，羚羊掛角不留跡。"]'),
('8a1dd1a4-0b61-49e4-864b-c09f5c5edcc2','偈頌一百三十三首  其一三二','釋法薰','宋','宋诗','song-poetry','','[]','尋常顛說倒說，何曾開口動舌。',28,'全唐诗/poet.song.186000.json','["尋常顛說倒說，何曾開口動舌。", "不妨雪上加霜，更與諸人一決。"]'),
('3b50576b-abf1-47f8-b4a0-4c118ad29de0','偈頌六十八首  其一','釋法薰','宋','宋诗','song-poetry','','[]','無門之門，七通八達。',20,'全唐诗/poet.song.186000.json','["無門之門，七通八達。", "入之一字，也不消得。"]'),
('5d823f6d-8ed3-4822-a04a-50be175e927b','偈頌六十八首  其二','釋法薰','宋','宋诗','song-poetry','','[]','有路可行，更高也上。',20,'全唐诗/poet.song.186000.json','["有路可行，更高也上。", "須彌燈王，退身合掌。"]'),
('266463f3-48a8-4bae-a121-cbe33183bb52','偈頌六十八首  其三','釋法薰','宋','宋诗','song-poetry','','[]','十八十九，癡人夜走。',32,'全唐诗/poet.song.186000.json','["十八十九，癡人夜走。", "十九二十，人信不及。", "信得及，觀音院裏有彌勒。"]'),
('3c921104-b873-4e9d-87d3-0384ec14322b','偈頌六十八首  其四','釋法薰','宋','宋诗','song-poetry','','[]','臘月燒山，火勢炎炎。',46,'全唐诗/poet.song.186000.json','["臘月燒山，火勢炎炎。", "目前包裹，借手行拳。", "若是衲衣下事，猶較十萬八千。", "御樓看射獵，不是刈茆田。"]'),
('127989c0-0988-4d26-bc93-3a826faf6aa9','偈頌六十八首  其五','釋法薰','宋','宋诗','song-poetry','','[]','大雪滿長安，春來特地寒。',24,'全唐诗/poet.song.186000.json','["大雪滿長安，春來特地寒。", "新年頭佛法，一點不相瞞。"]'),
('b418b69a-2d3d-4e41-9470-e8fd878e4ff5','偈頌六十八首  其六','釋法薰','宋','宋诗','song-poetry','','[]','折脚鐺子，大家知有。',36,'全唐诗/poet.song.186000.json','["折脚鐺子，大家知有。", "左提右挈，勞煩衆手。", "山僧贏得百無憂，一向面南看北斗。"]'),
('a07cd379-a69a-4681-b08f-42e0c015b3a6','偈頌六十八首  其七','釋法薰','宋','宋诗','song-poetry','','[]','乾峰錦包特石，雲門鐵裹泥團。',36,'全唐诗/poet.song.186000.json','["乾峰錦包特石，雲門鐵裹泥團。", "築著磕著，言端語端。", "不是任公子，徒勞話釣竿。"]'),
('fa030ce2-8858-497b-a916-7e198de48cd7','偈頌六十八首  其八','釋法薰','宋','宋诗','song-poetry','','[]','不問有言，不問無言。',32,'全唐诗/poet.song.186000.json','["不問有言，不問無言。", "靈山拄杖，斜靠壁邊。", "風光都占盡，不費一文錢。"]'),
('9d1d2c11-d909-486b-ac4c-25741fb40b00','偈頌六十八首  其九','釋法薰','宋','宋诗','song-poetry','','[]','古人一指頭禪，一生受用不盡。',42,'全唐诗/poet.song.186000.json','["古人一指頭禪，一生受用不盡。", "得恁麽明白，得恁麽簡徑。", "靈山這裏不較多，三尺杖子攪黄河。"]'),
('47f5e190-c1f3-4335-bb4a-80293b169520','偈頌六十八首  其一○','釋法薰','宋','宋诗','song-poetry','','[]','日遷月化，又見中夏。',45,'全唐诗/poet.song.186000.json','["日遷月化，又見中夏。", "衲僧那事，如何問著，人人口啞。", "有誵訛，不借借。", "六月賣松風，人間恐無價。"]'),
('697cd8db-e1a7-4fa8-9dd6-e8558de153eb','偈頌六十八首  其一一','釋法薰','宋','宋诗','song-poetry','','[]','祖師門下，討甚巴鼻，滿耳春風浩浩地。',47,'全唐诗/poet.song.186000.json','["祖師門下，討甚巴鼻，滿耳春風浩浩地。", "草木叢林，燈籠露柱，心空及第。", "汝等諸人，因甚却來這裏瞌睡。"]'),
('627eee6e-5609-4f73-9e47-a343615ccb79','偈頌六十八首  其一二','釋法薰','宋','宋诗','song-poetry','','[]','巴陵三轉語，鈍置老僧門。',24,'全唐诗/poet.song.186000.json','["巴陵三轉語，鈍置老僧門。", "靈山無半句，報盡破菴恩。"]'),
('c750cc9b-deb1-4440-89f4-23ec08e149f6','偈頌六十八首  其一三','釋法薰','宋','宋诗','song-poetry','','[]','秘魔老兒，擎箇叉子，不肯放下。',32,'全唐诗/poet.song.186000.json','["秘魔老兒，擎箇叉子，不肯放下。", "靈山這裏，凈躶躶，赤灑灑，沒可把。"]'),
('df31d277-f654-44e8-bac9-e1459468bc0a','偈頌六十八首  其一四','釋法薰','宋','宋诗','song-poetry','','[]','不是琅琊，洎被這僧惑亂。',46,'全唐诗/poet.song.186000.json','["不是琅琊，洎被這僧惑亂。", "若非這僧，琅琊令不虛行。", "末後棒頭賣峭，更向露柱藏身，笑殺毗耶杜口人。"]'),
('038999e3-d9c9-498f-9fe9-e11ab2d92484','偈頌六十八首  其一五','釋法薰','宋','宋诗','song-poetry','','[]','水流濕，火就燥。',18,'全唐诗/poet.song.186000.json','["水流濕，火就燥。", "臨安紙貴，一狀領過。"]'),
('e388f750-8aab-4aac-b130-5a2517e6d251','偈頌六十八首  其一六','釋法薰','宋','宋诗','song-poetry','','[]','節令不相饒，陽生第一爻。',30,'全唐诗/poet.song.186000.json','["節令不相饒，陽生第一爻。", "諸佛道長，衆生道消。", "拄杖子，獨孤標。"]'),
('f87100de-c95b-43f9-a26e-266f679d7a58','偈頌六十八首  其一七','釋法薰','宋','宋诗','song-poetry','','[]','世尊拈花，迦葉微笑。',54,'全唐诗/poet.song.186000.json','["世尊拈花，迦葉微笑。", "正法眼藏，永永流通。", "古佛今佛，心同道同。", "風從虎，雲從龍。", "節啟天基伸祝頌，壽齊南北兩高峰。"]'),
('e559d09a-4d65-4d9b-a912-330495cb68c8','偈頌六十八首  其一八','釋法薰','宋','宋诗','song-poetry','','[]','我若坐時汝須立，同坐同立成瞎漢。',28,'全唐诗/poet.song.186000.json','["我若坐時汝須立，同坐同立成瞎漢。", "非瞎漢，把手大家行那畔。"]'),
('e5b1a2bb-f59e-47c1-af07-d0fda8e608a7','偈頌六十八首  其一九','釋法薰','宋','宋诗','song-poetry','','[]','海上明公秀，趙州東院西。',24,'全唐诗/poet.song.186000.json','["海上明公秀，趙州東院西。", "不移毫髮許，平步上雲梯。"]'),
('1d3b8b78-401f-4d27-967b-df4e4aa6510d','偈頌六十八首  其二○','釋法薰','宋','宋诗','song-poetry','','[]','趙州老漢，心如蘗，口如蜜。',37,'全唐诗/poet.song.186000.json','["趙州老漢，心如蘗，口如蜜。", "一埦粗茶，多虛少實。", "院主兩眼瞇𥊚，畢竟何曾得喫。"]'),
('326e4f1c-5786-49e9-9898-0e9fb1e899bf','偈頌六十八首  其二一','釋法薰','宋','宋诗','song-poetry','','[]','不在內，不在外，不在中間。',25,'全唐诗/poet.song.186000.json','["不在內，不在外，不在中間。", "朝看雲冉冉，暮聽水潺潺。"]'),
('d1abcc03-faf5-4516-8ad4-285b094c16b1','偈頌六十八首  其二二','釋法薰','宋','宋诗','song-poetry','','[]','直如絃，曲如鈎。',34,'全唐诗/poet.song.186000.json','["直如絃，曲如鈎。", "易見難識，老倒趙州。", "世事但將公道斷，人心難似水長流。"]'),
('7b0692bb-a441-45ae-adf9-54cad5e4b798','偈頌六十八首  其二三','釋法薰','宋','宋诗','song-poetry','','[]','釋迦慳，彌勒富。',38,'全唐诗/poet.song.186000.json','["釋迦慳，彌勒富。", "甘草甜，黄連苦。", "法法小相干，人人各自度。", "咄，莫來攔我毬門路。"]'),
('2762be7a-e2f7-4636-af86-0ba0b65af23a','偈頌六十八首  其二四','釋法薰','宋','宋诗','song-poetry','','[]','盲禪暗證，日中迷路。',28,'全唐诗/poet.song.186000.json','["盲禪暗證，日中迷路。", "深聞淺悟，未入正流，不到烏江不肯休。"]'),
('f013b03f-1e8f-4170-b3a6-918162729560','偈頌六十八首  其二五','釋法薰','宋','宋诗','song-poetry','','[]','登天不假梯，徧地無行路。',24,'全唐诗/poet.song.186000.json','["登天不假梯，徧地無行路。", "可憐杜衲僧，邯鄲學唐步。"]'),
('4c58d79c-501a-4950-bcc4-c32448d127c8','偈頌六十八首  其二六','釋法薰','宋','宋诗','song-poetry','','[]','動容揚古路，不墮悄然機。',44,'全唐诗/poet.song.186000.json','["動容揚古路，不墮悄然機。", "承言者喪，滯句者迷。", "不承言，不滯句，蝦𢋙跳上梵天，燈籠吞却露柱。"]'),
('1f06c0d6-c7dc-459c-8225-aa77ffb6cdad','偈頌六十八首  其二七','釋法薰','宋','宋诗','song-poetry','','[]','百尺竿頭行闊步，紫羅帳裏撒真珠。',32,'全唐诗/poet.song.186000.json','["百尺竿頭行闊步，紫羅帳裏撒真珠。", "山僧贏得呵呵笑，未審諸人會也無。"]'),
('1984fc1c-6b65-4edf-bc25-eac11ff7e996','偈頌六十八首  其二八','釋法薰','宋','宋诗','song-poetry','','[]','東山正脈，不絕如線。',22,'全唐诗/poet.song.186000.json','["東山正脈，不絕如線。", "睡虎去無蹤，一斑今復見。"]'),
('e64f2e01-b289-48a7-8684-97f52eb03285','偈頌六十八首  其二九','釋法薰','宋','宋诗','song-poetry','','[]','若論此事，何必多言。',31,'全唐诗/poet.song.186000.json','["若論此事，何必多言。", "不在內，不在外，不在中間，離婁行處浪滔天。"]'),
('109394db-8f6b-40c2-88ff-a36119571afd','偈頌六十八首  其三○','釋法薰','宋','宋诗','song-poetry','','[]','識得一，萬事畢。',57,'全唐诗/poet.song.186000.json','["識得一，萬事畢。", "秘魔擎叉，魯祖面壁。", "臨際三玄三要，洞山五位君臣，雲門念七，是一不是一。", "昨夜新州老盧，失却腰間特石。"]'),
('6945ac1d-0565-44f3-9abb-c83fee50337b','偈頌六十八首  其三一','釋法薰','宋','宋诗','song-poetry','','[]','不參禪，不論義，拖箇破席日裏睡。',52,'全唐诗/poet.song.186000.json','["不參禪，不論義，拖箇破席日裏睡。", "賺他伎死禪和，至今坐在冷地。", "靈山不然，因行掉臂。", "買石得雲饒，移花兼蝶至。"]'),
('4b1eb500-4149-4a3d-b346-6f7178b51d1e','偈頌六十八首  其三二','釋法薰','宋','宋诗','song-poetry','','[]','喝如雷，棒如雨。',39,'全唐诗/poet.song.186000.json','["喝如雷，棒如雨。", "大地絕纖塵，回頭無覓處。", "無覓處，昨日有人從天台來，却往徑山去。"]'),
('f963a695-b5ff-494f-9e07-44f1ebe9c07f','偈頌六十八首  其三三','釋法薰','宋','宋诗','song-poetry','','[]','七十九年間，大地遭欺誑。',34,'全唐诗/poet.song.186000.json','["七十九年間，大地遭欺誑。", "且喜葛藤根，今朝嚗地斷。", "後代兒孫，三馬九亂。"]'),
('fb374ef0-a802-401a-833a-1c6f5cd89bd8','偈頌六十八首  其三四','釋法薰','宋','宋诗','song-poetry','','[]','佛來也打，祖來也打，德山老人，甚生風彩。',57,'全唐诗/poet.song.186000.json','["佛來也打，祖來也打，德山老人，甚生風彩。", "靈山這裏，佛來也著，祖來也著，手中拄杖，權且架閣。", "擎茶掃地，也要一箇半箇。"]'),
('3ee63230-ffa1-455c-8f2a-4f6fb860c2ef','偈頌六十八首  其三五','釋法薰','宋','宋诗','song-poetry','','[]','兔馬有角，牛羊無角。',38,'全唐诗/poet.song.186000.json','["兔馬有角，牛羊無角。", "不知不會，事同一家。", "多見多聞，千差萬別，畢竟天無第二月。"]'),
('9478b891-238f-46e8-9519-63bbe28dd5f8','偈頌六十八首  其三六','釋法薰','宋','宋诗','song-poetry','','[]','昨宵困倒床上，直至五皷方甦。',34,'全唐诗/poet.song.186000.json','["昨宵困倒床上，直至五皷方甦。", "今日陞堂，言句都無。", "且望大衆，智不責愚。"]'),
('594cf4ed-839b-44bb-8d40-0a9148f758e8','偈頌六十八首  其三七','釋法薰','宋','宋诗','song-poetry','','[]','網細魚稠，藥多病甚。',36,'全唐诗/poet.song.186000.json','["網細魚稠，藥多病甚。", "棒喝交馳，一品二品。", "山僧恁麽逞馿唇，癡客徒勞勸主人。"]'),
('b03b97e4-e1ff-4a28-9393-2c340dd8cd47','偈頌六十八首  其三八','釋法薰','宋','宋诗','song-poetry','','[]','春光冉冉，春日遲遲。',36,'全唐诗/poet.song.186000.json','["春光冉冉，春日遲遲。", "春風包裹，上下四維。", "黄鶑聲在柳陰西，此意明明說向誰。"]'),
('aa8e2f7f-1794-4406-9c0d-9de0347fb414','偈頌六十八首  其三九','釋法薰','宋','宋诗','song-poetry','','[]','欲得見前，莫存順逆。',20,'全唐诗/poet.song.186000.json','["欲得見前，莫存順逆。", "築著磕著，無處尋覓。"]'),
('02918925-a22a-4ac3-bffc-10e7179a2795','偈頌六十八首  其四○','釋法薰','宋','宋诗','song-poetry','','[]','鐵壁鐵壁復鐵壁，那邊那邊更那邊。',32,'全唐诗/poet.song.186000.json','["鐵壁鐵壁復鐵壁，那邊那邊更那邊。", "事到極頭須倒斷，瞎馿𨁝跳過西天。"]'),
('9d5eef08-2b05-4851-8315-0dacb02a522d','偈頌六十八首  其四一','釋法薰','宋','宋诗','song-poetry','','[]','靈隠雖則無能，要與花藥相見。',46,'全唐诗/poet.song.186000.json','["靈隠雖則無能，要與花藥相見。", "十七十八，證龜成鱉。", "十九二十，半夜潑墨。", "直須枯木生花，胡餠出汁。"]'),
('9985e1cf-8714-43c3-8bf9-3390594673f7','偈頌六十八首  其四二','釋法薰','宋','宋诗','song-poetry','','[]','海上明公秀，衲僧不知有。',42,'全唐诗/poet.song.186000.json','["海上明公秀，衲僧不知有。", "冷地忽相逢，尋常無處討。", "無處討，莫草草，龍王宮殿，有誰親到。"]'),
('2d704f18-b132-47c3-bb69-4dca6318f68f','偈頌六十八首  其四三','釋法薰','宋','宋诗','song-poetry','','[]','臨際頂中髓，楊岐眼裏筋。',49,'全唐诗/poet.song.186000.json','["臨際頂中髓，楊岐眼裏筋。", "欲明這箇事，須還這箇人。", "風前有路，秤尾無星。", "大家贏得笑忻忻，笑道秤尾無星。"]'),
('3e94015c-3ade-4af0-b039-c50bcd42e942','偈頌六十八首  其四四','釋法薰','宋','宋诗','song-poetry','','[]','刀不自割，水不自洗。',25,'全唐诗/poet.song.186000.json','["刀不自割，水不自洗。", "山僧拄杖化爲龍，吞却乾坤大地。"]'),
('f01bb248-7ea9-4ada-a551-0be0b229c079','偈頌六十八首  其四五','釋法薰','宋','宋诗','song-poetry','','[]','春花爛漫，春光欲暮。',32,'全唐诗/poet.song.186000.json','["春花爛漫，春光欲暮。", "杜宇聲聲，送春歸去。", "諸人何不向這裡眼明心悟。"]'),
('61822dd2-1381-433e-9184-537f9cdc23f8','偈頌六十八首  其四六','釋法薰','宋','宋诗','song-poetry','','[]','明如鏡，黑如漆。',28,'全唐诗/poet.song.186000.json','["明如鏡，黑如漆。", "四七二三，多虛少實。", "靈山拄杖，且拈靠壁。"]'),
('90a495a5-7072-48c2-b923-53fc5c51628e','偈頌六十八首  其四七','釋法薰','宋','宋诗','song-poetry','','[]','非不非，是不是。',34,'全唐诗/poet.song.186000.json','["非不非，是不是。", "建立則乖張，掃除則失旨。", "德山臨際出來，換却髑髏裏底。"]'),
('50e62432-fc41-4ed7-a903-18b8eafd855f','偈頌六十八首  其四八','釋法薰','宋','宋诗','song-poetry','','[]','九十日已過半，那事畢竟如何。',26,'全唐诗/poet.song.186000.json','["九十日已過半，那事畢竟如何。", "直饒窮到底，終是涉風波。"]'),
('48804728-90ae-4568-ba27-2426361a2638','偈頌六十八首  其四九','釋法薰','宋','宋诗','song-poetry','','[]','不識字却識字，合識字却不識字。',41,'全唐诗/poet.song.186000.json','["不識字却識字，合識字却不識字。", "石田恁麽判斷，且道意在於何。", "萬人爭仰處，一箭落雙鵰。"]'),
('d1834e56-e800-4c05-9194-ce3642f30b1e','偈頌六十八首  其五○','釋法薰','宋','宋诗','song-poetry','','[]','青山不舉步，日下不挑燈。',38,'全唐诗/poet.song.186000.json','["青山不舉步，日下不挑燈。", "黄頭碧眼，臭肉生蠅。", "諸人三十年後悟去，不得錯怪老僧。"]'),
('cc613ac4-3b88-4f01-901f-000d88a7f525','偈頌六十八首  其五一','釋法薰','宋','宋诗','song-poetry','','[]','德山雨點棒，臨際雷奔喝。',44,'全唐诗/poet.song.186000.json','["德山雨點棒，臨際雷奔喝。", "收拾將來，七零八落。", "靈山咬定牙關，盡力也難提掇，睦州拶折雲門脚。"]'),
('25f1fe28-f015-4232-b3e5-93734506fbb2','偈頌六十八首  其五二','釋法薰','宋','宋诗','song-poetry','','[]','時時九夏，日日三秋。',32,'全唐诗/poet.song.186000.json','["時時九夏，日日三秋。", "閙市裏，百草頭。", "夾山老子賣峭，重價未有輕酬。"]'),
('7add69bf-e5d4-4ad5-8f73-d9db68f4d1e9','偈頌六十八首  其五三','釋法薰','宋','宋诗','song-poetry','','[]','目前無法，意在目前。',48,'全唐诗/poet.song.186000.json','["目前無法，意在目前。", "從上若佛若祖，天下老和尚罪過彌天。", "天，天，昨夜山僧針線囊中，打失一文古老錢。"]'),
('77051584-e63d-4afc-8f6d-23a352de4e94','偈頌六十八首  其五四','釋法薰','宋','宋诗','song-poetry','','[]','西來無意，直指無旨。',20,'全唐诗/poet.song.186000.json','["西來無意，直指無旨。", "引得癡兒，盡卧冷地。"]'),
('1c6758c2-72a4-49fa-a094-b2b04a1918bb','偈頌六十八首  其五五','釋法薰','宋','宋诗','song-poetry','','[]','月旦陞堂，無可垂示。',52,'全唐诗/poet.song.186000.json','["月旦陞堂，無可垂示。", "便恁麽散去，諸人未必靈利。", "且向秤鎚上，捏出些子汁，貴圖有箇滋味。", "見之不取，思之千里。"]'),
('ec745795-4534-42ab-8135-0fa1563c75e2','偈頌六十八首  其五六','釋法薰','宋','宋诗','song-poetry','','[]','曲曲彎彎，平平坦坦。',44,'全唐诗/poet.song.186000.json','["曲曲彎彎，平平坦坦。", "七穿八穴，十字縱橫。", "是汝諸人，不妨東行西行，第一莫教撞著跛脚老雲門。"]'),
('139d4e62-3464-4bf5-9f6f-371b807787a5','偈頌六十八首  其五七','釋法薰','宋','宋诗','song-poetry','','[]','意到句到，宗通說通。',54,'全唐诗/poet.song.186000.json','["意到句到，宗通說通。", "一品二品，百匝千重。", "推倒面前案山子，長衫大袖舞春風。", "窮鬼子，莫莫莫，更須知有朱頂王菩薩。"]'),
('fca130b3-0812-41d7-afb2-69dd209f639e','偈頌六十八首  其五八','釋法薰','宋','宋诗','song-poetry','','[]','靈隠門下，不犯之令。',41,'全唐诗/poet.song.186000.json','["靈隠門下，不犯之令。", "九十日中，頭正尾正。", "衲僧路活，脚下生煙，老僧終不學雲門索飯錢。"]'),
('970d0d5e-3aa7-451f-9b99-d4976b018ac5','偈頌六十八首  其五九','釋法薰','宋','宋诗','song-poetry','','[]','大小大香巖，尾巴拖地。',31,'全唐诗/poet.song.186000.json','["大小大香巖，尾巴拖地。", "靈隠一機，全無所示。", "若也不會，投子道底。"]'),
('9ae6fac6-cb1c-461d-9f75-2efb7c7f8a29','偈頌六十八首  其六○','釋法薰','宋','宋诗','song-poetry','','[]','入室陞堂，門庭施設。',36,'全唐诗/poet.song.186000.json','["入室陞堂，門庭施設。", "無途轍中，翻成途轍。", "百丈老常得一橛，解道喫茶珍重歇。"]'),
('93e4e29f-01ac-45fa-a1f9-be028bf0703d','偈頌六十八首  其六一','釋法薰','宋','宋诗','song-poetry','','[]','放下覓無蹤，盡力提不起。',30,'全唐诗/poet.song.186000.json','["放下覓無蹤，盡力提不起。", "寸鐵未施，刀鏘滿地，明眼衲僧失巴鼻。"]'),
('7458b3df-cb59-46cb-b1d5-266622f46fe2','偈頌六十八首  其六二','釋法薰','宋','宋诗','song-poetry','','[]','德山棒頭短，臨濟喝聲低。',24,'全唐诗/poet.song.186000.json','["德山棒頭短，臨濟喝聲低。", "不傷物義句，趙州東院西。"]'),
('c9ca389c-0840-4900-9cea-bf61bfadbf18','偈頌六十八首  其六三','釋法薰','宋','宋诗','song-poetry','','[]','全提半提，向上向下，冷泉直是口啞。',27,'全唐诗/poet.song.186000.json','["全提半提，向上向下，冷泉直是口啞。", "真人面前，不得說假。"]'),
('d495e2a6-2676-4ecd-9704-8cb8519f33bb','偈頌六十八首  其六四','釋法薰','宋','宋诗','song-poetry','','[]','說短說長，自起自倒。',38,'全唐诗/poet.song.186000.json','["說短說長，自起自倒。", "跛脚老雲門，慈悲成過咎。", "長安一路坦然平，往來曾不禁人行。"]'),
('16488b00-273c-4d35-adfd-f718bb7a0554','偈頌六十八首  其六五','釋法薰','宋','宋诗','song-poetry','','[]','秋聲滿林壑，秋雨滴梧桐。',40,'全唐诗/poet.song.186000.json','["秋聲滿林壑，秋雨滴梧桐。", "門外未歸客，飄泊在途中。", "歸也，歸也，通身白汗，下載清風。"]'),
('0c530ec3-541e-48e3-9145-4efc2da3d517','偈頌六十八首  其六六','釋法薰','宋','宋诗','song-poetry','','[]','趙州禪，口皮邊。',38,'全唐诗/poet.song.186000.json','["趙州禪，口皮邊。", "牆外底，透長安。", "𡎺著磕著，言端語端。", "不是釣鰲手，徒勞把釣竿。"]'),
('0e30ee3a-1211-4a0d-9a2c-efe5ae55e7b1','偈頌六十八首  其六七','釋法薰','宋','宋诗','song-poetry','','[]','松柏千年青，不入時人意。',24,'全唐诗/poet.song.186000.json','["松柏千年青，不入時人意。", "牡丹一日紅，滿城公子醉。"]'),
('2425b842-8abd-4951-b8ef-a462ebe44051','偈頌六十八首  其六八','釋法薰','宋','宋诗','song-poetry','','[]','採藥與用藥，相逢一會家。',28,'全唐诗/poet.song.186000.json','["採藥與用藥，相逢一會家。", "殺人活人不眨眼，白玉無瑕却有瑕。"]'),
('2dd3fe11-571d-4ee6-b4f7-d4acda133e0e','拈古十四首  其一','釋法薰','宋','宋诗','song-poetry','','[]','即心即佛，甜瓜甜徹蒂。',62,'全唐诗/poet.song.186000.json','["即心即佛，甜瓜甜徹蒂。", "非心非佛，苦瓠苦連根。", "不是心，不是佛，不是物，斫却月中桂，清光迸海門。", "箇裏若能開正眼，一毫頭上定乾坤。"]'),
('e8f2f95a-6503-49d3-87af-4d569b61b4db','拈古十四首  其二','釋法薰','宋','宋诗','song-poetry','','[]','聞聲悟道，見色明心。',32,'全唐诗/poet.song.186000.json','["聞聲悟道，見色明心。", "林鴆砧，井底種林擒。", "今年桃李貴，一顆直千金。"]'),
('d6d05808-081b-40a7-8422-03339c2bfb40','拈古十四首  其三','釋法薰','宋','宋诗','song-poetry','','[]','昨日定，今日不定。',29,'全唐诗/poet.song.186000.json','["昨日定，今日不定。", "大小瞿曇，因邪打正。", "更問如何，鉢盂安柄。"]'),
('88cfdf49-ab32-4eb5-8828-09c79afd4c63','拈古十四首  其四','釋法薰','宋','宋诗','song-poetry','','[]','大家在這裏，廓徹無依倚。',24,'全唐诗/poet.song.186000.json','["大家在這裏，廓徹無依倚。", "有口難分疎，凍破一雙耳。"]'),
('442dfe88-7ffb-4ac0-bb91-fa6763b435a6','拈古十四首  其五','釋法薰','宋','宋诗','song-poetry','','[]','這僧已是露出眼睛，雲門更與揭却腦蓋。',28,'全唐诗/poet.song.186000.json','["這僧已是露出眼睛，雲門更與揭却腦蓋。", "若是佛法，未夢見在。"]'),
('87f9c535-661f-4aa8-9a80-45d26a3b57e4','拈古十四首  其六','釋法薰','宋','宋诗','song-poetry','','[]','來風可辨，駟馬難追。',20,'全唐诗/poet.song.186000.json','["來風可辨，駟馬難追。", "若無後語，討甚大悲。"]'),
('ad583c9e-1cee-4659-ab09-cdc09fa0aa43','拈古十四首  其七','釋法薰','宋','宋诗','song-poetry','','[]','南山不會禪，一向外邊走。',24,'全唐诗/poet.song.186000.json','["南山不會禪，一向外邊走。", "臘月三十日，舌頭不出口。"]'),
('36fb70ba-29c1-4a79-aaea-6606e9973044','拈古十四首  其八','釋法薰','宋','宋诗','song-poetry','','[]','氈拍板，無孔笛。',34,'全唐诗/poet.song.186000.json','["氈拍板，無孔笛。", "狹路相逢，五音六律。", "流落叢林知幾年，至今誰敢通消息。"]'),
('e97fff4e-b102-489b-b6b6-c9c148b65a4e','拈古十四首  其九','釋法薰','宋','宋诗','song-poetry','','[]','鏡清摇頭，這僧擺尾。',24,'全唐诗/poet.song.186000.json','["鏡清摇頭，這僧擺尾。", "雖則一期可觀，爭奈玄沙道底。"]'),
('78c2c20d-f80f-46ad-a863-1f79b92e3c86','拈古十四首  其一○','釋法薰','宋','宋诗','song-poetry','','[]','馬師智藏，病痛一般。',46,'全唐诗/poet.song.186000.json','["馬師智藏，病痛一般。", "海兄不會，當面熱瞞。", "頭白頭黑，言端語端。", "衲僧不用空啗啄，秤在星兮不在盤。"]'),
('ae100a31-bcd7-4ef7-9b09-c901d22e4010','拈古十四首  其一一','釋法薰','宋','宋诗','song-poetry','','[]','雲居打草驚蛇，雪峰開口見膽。',28,'全唐诗/poet.song.186000.json','["雲居打草驚蛇，雪峰開口見膽。", "保福獨上高臺，要且衆眼難瞞。"]'),
('6cddae6b-31c8-4537-80ad-bcfd286d2450','拈古十四首  其一二','釋法薰','宋','宋诗','song-poetry','','[]','父子至親，心眼無二。',36,'全唐诗/poet.song.186000.json','["父子至親，心眼無二。", "築著磕著，透頂透底。", "傍觀只把當兒戲，蒼龍攪動澄潭水。"]'),
('45032c33-5f6c-4ce2-9a5d-4947230644ea','拈古十四首  其一三','釋法薰','宋','宋诗','song-poetry','','[]','這老漢，手頭短。',35,'全唐诗/poet.song.186000.json','["這老漢，手頭短。", "靈隠即不然，見成公案，與汝三十棒。", "棒頭有眼，龍蛇易辨。"]'),
('52c170d7-3633-486e-82fa-1de841561729','拈古十四首  其一四','釋法薰','宋','宋诗','song-poetry','','[]','開田甚難，難中却易。',44,'全唐诗/poet.song.186000.json','["開田甚難，難中却易。", "展手甚易，易中却難。", "說難說易，轉見顢頇。", "自己若無僊骨，謾言九轉還丹。"]'),
('d80c4cf1-29b5-442f-ad41-505bdb92c539','頌古十首  其一','釋法薰','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','道人相見問如何，舉手寒溫事已多。',32,'全唐诗/poet.song.186000.json','["道人相見問如何，舉手寒溫事已多。", "潦倒趙州呈漆器，岳陽船子洞庭波。"]'),
('fba664c1-6d26-473a-8dcb-5761bdacef4d','頌古十首  其二','釋法薰','宋','宋诗','song-poetry','','[]','百丈機先疾似風，巍巍獨坐大雄峰。',32,'全唐诗/poet.song.186000.json','["百丈機先疾似風，巍巍獨坐大雄峰。", "要知奇特中奇特，明月難教下碧空。"]'),
('abeb3d8b-08e6-4661-87f0-4003791dbe54','頌古十首  其三','釋法薰','宋','宋诗','song-poetry','','[]','東村王老夜燒錢，鼻孔依稀露半邊。',32,'全唐诗/poet.song.186000.json','["東村王老夜燒錢，鼻孔依稀露半邊。", "武帝求仙求不得，王喬端坐却昇天。"]'),
('2f9988d5-adf0-4f41-9242-b3b1c950690f','頌古十首  其四','釋法薰','宋','宋诗','song-poetry','','[]','百千諸佛在何居，黄鶴樓詩錦不如。',32,'全唐诗/poet.song.186000.json','["百千諸佛在何居，黄鶴樓詩錦不如。", "問汝秀才題也未，一篇題取莫躊躇。"]'),
('aa3dba74-8808-4bf2-adae-9d9ede8f354e','頌古十首  其五','釋法薰','宋','宋诗','song-poetry','','[]','萬法歸一一何歸，海口難酬這一問。',32,'全唐诗/poet.song.186000.json','["萬法歸一一何歸，海口難酬這一問。", "不得青州一領衫，幾乎喪却窮性命。"]'),
('986343ed-f727-4743-aa64-aa156952493e','頌古十首  其六','釋法薰','宋','宋诗','song-poetry','','[]','天地根元與我同，撥波求水謾勞功。',32,'全唐诗/poet.song.186000.json','["天地根元與我同，撥波求水謾勞功。", "時人見此花如夢，坐斷須彌信不通。"]'),
('a9699842-deb5-48f5-9c1d-ad843ffb03f6','頌古十首  其七','釋法薰','宋','宋诗','song-poetry','','[]','冬來底事要商量，向道京師出大黄。',32,'全唐诗/poet.song.186000.json','["冬來底事要商量，向道京師出大黄。", "多少病貓餐死鼠，日中擡首眼無光。"]'),
('ebcad980-23f8-4f71-bf15-a25ba75cd34d','頌古十首  其八','釋法薰','宋','宋诗','song-poetry','','[]','無賓主話意深深，流落叢林古到今。',32,'全唐诗/poet.song.186000.json','["無賓主話意深深，流落叢林古到今。", "火冷灰寒口挂壁，衲僧凍死不知心。"]'),
('c18fbe28-67f3-4403-8cd0-980dd5b66378','頌古十首  其九','釋法薰','宋','宋诗','song-poetry','','[]','安居三月不論玄，水牯朝昏痛著鞭。',32,'全唐诗/poet.song.186000.json','["安居三月不論玄，水牯朝昏痛著鞭。", "拽脫鼻繩無覓處，山童走得脚皮穿。"]'),
('b5f08b70-13cb-43ee-b8ce-667b63315423','頌古十首  其一○','釋法薰','宋','宋诗','song-poetry','','[]','曾到未到俱喫茶，爲君抉出眼中花。',32,'全唐诗/poet.song.186000.json','["曾到未到俱喫茶，爲君抉出眼中花。", "犀因翫月紋生角，象被雷驚花入牙。"]'),
('6fd3d535-e5d0-4ddf-9bf4-d9973513058a','偈頌十五首  其一','釋法薰','宋','宋诗','song-poetry','','[]','莫行心處路，不挂本來衣。',24,'全唐诗/poet.song.186000.json','["莫行心處路，不挂本來衣。", "何須更恁麽，切忌未生時。"]'),
('c67256fa-c738-4742-b2e2-2ca858374027','偈頌十五首  其二','釋法薰','宋','宋诗','song-poetry','','[]','床窄先卧，粥稀後坐。',22,'全唐诗/poet.song.186000.json','["床窄先卧，粥稀後坐。", "耳聵要聲高，眼昏宜字大。"]'),
('cfd53212-1fc2-4dde-bfd8-db39d7c644c9','偈頌十五首  其三','釋法薰','宋','宋诗','song-poetry','','[]','以大圓覺，爲我伽藍。',30,'全唐诗/poet.song.186000.json','["以大圓覺，爲我伽藍。", "望雲上樹，身心安居。", "平等性智，熟睡寐語。"]'),
('e62afb51-71fb-402a-8368-42b9e7e83725','偈頌十五首  其四','釋法薰','宋','宋诗','song-poetry','','[]','飛來峰高攀不上，冷泉水深飲不竭。',32,'全唐诗/poet.song.186000.json','["飛來峰高攀不上，冷泉水深飲不竭。", "衲僧到此擬奚爲，盡力神疲好休歇。"]'),
('d5613f98-7f16-451e-b142-77cd623f67fb','偈頌十五首  其五','釋法薰','宋','宋诗','song-poetry','','[]','透骨霜風入戶庭，日南長至又逢迎。',32,'全唐诗/poet.song.186000.json','["透骨霜風入戶庭，日南長至又逢迎。", "衲僧不解論時節，只麽堆堆過此生。"]'),
('11bcd2cf-e3fd-459f-a1ec-99e41e9603e3','偈頌十五首  其六','釋法薰','宋','宋诗','song-poetry','','[]','烏兔東西疾，一年時序畢。',24,'全唐诗/poet.song.186000.json','["烏兔東西疾，一年時序畢。", "竇八布衫穿，烏龜眼睛赤。"]'),
('3d6fd212-eee2-49e5-a610-9bd739d929d9','偈頌十五首  其七','釋法薰','宋','宋诗','song-poetry','','[]','以大圓覺，爲我伽藍。',40,'全唐诗/poet.song.186000.json','["以大圓覺，爲我伽藍。", "頭上著枷，脚下著杻。", "身心安居，平等性智。", "困魚止瀝，病鳥栖蘆。"]'),
('b842b5d4-ccd1-4cdd-aa26-7a99d8a8729c','偈頌十五首  其八','釋法薰','宋','宋诗','song-poetry','','[]','保福借水獻花，這僧白日迷路。',38,'全唐诗/poet.song.186000.json','["保福借水獻花，這僧白日迷路。", "南山門下，總是粗心底。", "只是不敢說著，小慈妨大慈。"]'),
('903c3a3f-09bb-4450-988c-9c8d697dc3d4','偈頌十五首  其九','釋法薰','宋','宋诗','song-poetry','','[]','洞山前施妙略，這僧暗透重關。',42,'全唐诗/poet.song.186000.json','["洞山前施妙略，這僧暗透重關。", "若不得後著，前話也難圓。", "將軍但有嘉聲在，不得封侯也是關。"]'),
('80775728-fc7d-432e-ad86-b395334e6576','偈頌十五首  其一○','釋法薰','宋','宋诗','song-poetry','','[]','趙老應機，如風吹水。',25,'全唐诗/poet.song.186000.json','["趙老應機，如風吹水。", "第一座香烟起，馿年夢見汗臭氣。"]'),
('1461d11a-c192-49e6-b5a1-e61c4104cf3f','偈頌十五首  其一一','釋法薰','宋','宋诗','song-poetry','','[]','夏末秋初萬萬千，石頭路滑脚皮穿。',32,'全唐诗/poet.song.186000.json','["夏末秋初萬萬千，石頭路滑脚皮穿。", "這僧劍刃翻身疾，也被雲門索飯錢。"]'),
('9d1f091e-c4d8-49d8-81e8-68ffb1a2191d','偈頌十五首  其一二','釋法薰','宋','宋诗','song-poetry','','[]','吾家那事苦無多，不在頻搜故紙籮。',32,'全唐诗/poet.song.186000.json','["吾家那事苦無多，不在頻搜故紙籮。", "未解語言先作賦，却參鍾阜問如何。"]'),
('18bfa6f7-33b5-4295-83ed-7cd4ecf68dba','偈頌十五首  其一三','釋法薰','宋','宋诗','song-poetry','','[]','大海波濤湧，于江水逆流。',24,'全唐诗/poet.song.186000.json','["大海波濤湧，于江水逆流。", "龍王宮殿裡，不見一人遊。"]'),
('28740495-f26a-48a8-bf22-17bac47c2db2','偈頌十五首  其一四','釋法薰','宋','宋诗','song-poetry','','[]','夫子不識字，達磨不會禪。',24,'全唐诗/poet.song.186000.json','["夫子不識字，達磨不會禪。", "御樓看射獵，不是刈茅田。"]'),
('ebc3a96b-20f5-4e80-8401-716ac7160ecb','偈頌十五首  其一五','釋法薰','宋','宋诗','song-poetry','','[]','解用不須雙刃劍，延齡何必九還丹。',32,'全唐诗/poet.song.186000.json','["解用不須雙刃劍，延齡何必九還丹。", "尉遲□不在家死，獅子那能食兔錢。"]'),
('e92f3d21-defc-499c-b47d-4d9af86a08ba','出山相贊  其一','釋法薰','宋','宋诗','song-poetry','','[]','未出山時，四方風悄悄。',55,'全唐诗/poet.song.186000.json','["未出山時，四方風悄悄。", "纔出山來，平地洪波湧。", "箇般醜舉止，邈得將何用。", "也好長時展起，隨分爇三錢兜樓香，薰他鼻孔。"]'),
('8c43db42-9364-4ac3-bc14-523085cec40e','出山相贊  其二','釋法薰','宋','宋诗','song-poetry','','[]','健即經行，倦即打坐。',50,'全唐诗/poet.song.186000.json','["健即經行，倦即打坐。", "思惟四十九年，做得許多口過。", "開眼堂堂，只成話墮。", "浩浩清風樹杪來，直下知機能幾箇。"]'),
('f82c4237-75dd-4cc9-a550-011b534007a1','觀音贊  其一','釋法薰','宋','宋诗','song-poetry','','[]','入正定，作正觀。',34,'全唐诗/poet.song.186000.json','["入正定，作正觀。", "衆生受苦，我心何安。", "隨類現身無處覓，天風卷海夜濤寒。"]'),
('9d3f804e-ec08-4c2e-bbf3-772cae492a56','觀音贊  其二','釋法薰','宋','宋诗','song-poetry','','[]','聞聲聞無所聞，見色見非是見。',40,'全唐诗/poet.song.186000.json','["聞聲聞無所聞，見色見非是見。", "燕坐盤陀，不定不亂。", "盡大地悉證圓通，我方滿度生悲願。"]'),
('e1e9bb96-1928-4c70-aaa8-4b097608669b','觀音思惟像贊','釋法薰','宋','宋诗','song-poetry','','[]','苦海深，悲願廣。',26,'全唐诗/poet.song.186000.json','["苦海深，悲願廣。", "作是思惟，云何方便。", "普使群生登彼岸。"]'),
('f9f171a6-b5c2-47a2-b6c4-874047d1de9d','馬郎婦贊','釋法薰','宋','宋诗','song-poetry','','[]','聲色純真，見聞不礙。',36,'全唐诗/poet.song.186000.json','["聲色純真，見聞不礙。", "宴坐經行，得大自在。", "脚頭脚底黑漫漫，又逐春風婦馬郎。"]'),
('926f882e-b5e3-45b8-8b0e-695fa2c2dc2e','達磨贊  其一','釋法薰','宋','宋诗','song-poetry','','[]','白璧暗投，遭他按劍。',36,'全唐诗/poet.song.186000.json','["白璧暗投，遭他按劍。", "折得莖蘆，還衝巨浪。", "闔國人追亦不回，掩羞頼有閑和尚。"]'),
('4e9046e5-a2c0-478a-b84a-a32a530b7657','達磨贊  其二','釋法薰','宋','宋诗','song-poetry','','[]','我東土人，一性純真。',44,'全唐诗/poet.song.186000.json','["我東土人，一性純真。", "被他明破，不直半文。", "皮肉骨髓，狼藉分爭。", "當時若藥得死，今日定見太平。"]'),
('bb197b08-784f-4b79-87eb-512b010d3b3a','達磨贊  其三','釋法薰','宋','宋诗','song-poetry','','[]','孟浪到梁朝，不契梁朝意。',36,'全唐诗/poet.song.186000.json','["孟浪到梁朝，不契梁朝意。", "放過一著，走入魏地。", "神光謾說安心，未免失却一臂。"]'),
('6985686f-8047-418f-adec-057ccd4a3035','初祖贊','釋法薰','宋','宋诗','song-poetry','','[]','航海越漠來，幾度藥不殺。',24,'全唐诗/poet.song.186000.json','["航海越漠來，幾度藥不殺。", "壞我震旦人，至今廝淈𣸩。"]'),
('43d72dfd-4205-4566-95f6-49a0090df133','二祖贊','釋法薰','宋','宋诗','song-poetry','','[]','覓心無處覓，當下便心安。',24,'全唐诗/poet.song.186000.json','["覓心無處覓，當下便心安。", "早知冰是水，兩臂定完全。"]'),
('8446bf65-63f4-480e-bd3d-48f4eff8b676','三祖贊','釋法薰','宋','宋诗','song-poetry','','[]','覓罪不可得，更於何處懺。',24,'全唐诗/poet.song.186000.json','["覓罪不可得，更於何處懺。", "雲翳豁然開，青天孤月上。"]'),
('75594410-98eb-4792-8c71-d5af69b995db','四祖贊','釋法薰','宋','宋诗','song-poetry','','[]','誰縛無人縛，何更求解脫。',24,'全唐诗/poet.song.186000.json','["誰縛無人縛，何更求解脫。", "未必右軍鵝，便是支郎鶴。"]'),
('6018c560-0660-4063-95cd-97b77ab81428','五祖贊','釋法薰','宋','宋诗','song-poetry','','[]','栽遍滿山松，暗地翻身轉。',24,'全唐诗/poet.song.186000.json','["栽遍滿山松，暗地翻身轉。", "雖然得信衣，何曾識爺面。"]'),
('3ad03759-fe2f-4809-9f53-91772dd6399f','六祖贊','釋法薰','宋','宋诗','song-poetry','','[]','腰石碓坊舂，不識一丁字。',24,'全唐诗/poet.song.186000.json','["腰石碓坊舂，不識一丁字。", "無樹亦無臺，猶傳鉢袋子。"]'),
('d023f176-8c64-4f44-b6c5-a9b03268a94e','布袋贊  其一','釋法薰','宋','宋诗','song-poetry','','[]','杖挑布袋，雲生脚下。',46,'全唐诗/poet.song.186000.json','["杖挑布袋，雲生脚下。", "前街後巷，渾無顧籍。", "拊背喚得回，幾人能領話。", "也且只得奈煩，鐵奉化人難化。"]'),
('e78809ed-9d0b-4494-8d1b-b64caa29be46','布袋贊  其二','釋法薰','宋','宋诗','song-poetry','','[]','辭兜率，混凡塵。',41,'全唐诗/poet.song.186000.json','["辭兜率，混凡塵。", "閉眼昨夜，肚裏惺惺。", "何如起來，提却拄杖子，東行西行，忽然等看箇人。"]'),
('b53840c3-3e3e-456e-bb18-be50a4d709f7','布袋贊  其三','釋法薰','宋','宋诗','song-poetry','','[]','乞錢錢又無，等人人不見。',34,'全唐诗/poet.song.186000.json','["乞錢錢又無，等人人不見。", "不知兜率天，何如奉化懸。", "拍手呵呵，天回地轉。"]'),
('4dc04393-c092-4d43-ba60-a5b1e4f0a0c1','豐干寒山拾得圖贊','釋法薰','宋','宋诗','song-poetry','','[]','三人必有我師，臭肉元同一味。',61,'全唐诗/poet.song.186000.json','["三人必有我師，臭肉元同一味。", "把手聚頭，蘇盧悉里。", "只因一等饒舌，兩箇隠身無地。", "可惜當初國清寺裏，一隊懞憧師僧，更沒些子意智。"]'),
('39eeb47e-a9bf-4286-90b0-8b04ea739214','四睡圖贊','釋法薰','宋','宋诗','song-poetry','','[]','一等騎虎來，兩箇挨肩去。',52,'全唐诗/poet.song.186000.json','["一等騎虎來，兩箇挨肩去。", "松門外聚頭，輥作一處睡。", "夢蝶栩栩不知，孰爲人孰爲虎。", "待渠眼若開時，南山有一轉語。"]'),
('05271153-1525-437f-9f79-64978d39a2d6','言法華贊','釋法薰','宋','宋诗','song-poetry','','[]','脚踏木履，手指虛空。',44,'全唐诗/poet.song.186000.json','["脚踏木履，手指虛空。", "法華三昧，舌本玲瓏。", "連書十三，如蟲蝕木。", "引得一類邪徒，至今胡卜亂卜。"]'),
('31f2c543-849b-42c8-9881-86f9d1f62a28','寒山拾得望月贊','釋法薰','宋','宋诗','song-poetry','','[]','木葉題詩，寺厨執爨。',52,'全唐诗/poet.song.186000.json','["木葉題詩，寺厨執爨。", "遇夜乘閑，林間舒散。", "一片冰壺無影像，分明照破渠肝膽。", "堪笑當時天台山中，也無一箇具眼。"]'),
('68806b0d-a80c-4618-b0cb-cbd9b3b8fbc6','豬頭和尚贊','釋法薰','宋','宋诗','song-poetry','','[]','手把豬頭，易見難識。',20,'全唐诗/poet.song.186000.json','["手把豬頭，易見難識。", "莫教說破，分文不直。"]'),
('a8ac4159-1df3-4522-b9f9-584e93f669d8','蜆子和尚贊','釋法薰','宋','宋诗','song-poetry','','[]','把箇里撈波，做盡窮伎倆。',24,'全唐诗/poet.song.186000.json','["把箇里撈波，做盡窮伎倆。", "推出酒臺盤，至今收不上。"]'),
('732bb091-00af-47f8-a78d-8ec24a7534c3','楊岐和尚贊','釋法薰','宋','宋诗','song-poetry','','[]','不會禪，也住院。',48,'全唐诗/poet.song.186000.json','["不會禪，也住院。", "旨的全無，種田博飯。", "大笑接□白雲瞎漢，無端带累徧地兒孫。", "至今東西不分，南北不辨。"]'),
('b5257e61-5b7d-4afb-a749-e426f98ea9ce','贊五祖演和尚','釋法薰','宋','宋诗','song-poetry','','[]','參錄公猶未，瞥見白雲方始徹果。',91,'全唐诗/poet.song.186000.json','["參錄公猶未，瞥見白雲方始徹果。", "有超師之作，敢道端師翁語拙。", "一生居淮不入浙，獨弄單提這一著。", "至於接三佛，控南堂，以一大藏，切入囉孃。", "夫是之謂東山正續，毫髮不移，亙千萬世，源深流長者也。"]'),
('cd6fa72d-f7a5-4b7b-8118-666a7de065ce','普化和尚贊','釋法薰','宋','宋诗','song-poetry','','[]','走城郭，摇鈴鐸。',50,'全唐诗/poet.song.186000.json','["走城郭，摇鈴鐸。", "堂前喫生菜，觸著馿性發。", "勘破河陽木塔，擒下臨濟小卒。", "賺却鎮州一城人，鐸聲已遠青天闊。"]'),
('3aa094ab-96ca-4372-98db-5d881b2c88e0','臨濟和尚贊','釋法薰','宋','宋诗','song-poetry','','[]','空拳捺定，喝聲雷震。',44,'全唐诗/poet.song.186000.json','["空拳捺定，喝聲雷震。", "閃電光中，要分邪正。", "駕大脫空，賣無主贓。", "似恁落頼心腸，至今却有兒郎。"]'),
('780cb835-a932-46c5-96a4-61673dc70ca4','維摩贊','釋法薰','宋','宋诗','song-poetry','','[]','據坐胡床，風悄悄地。',48,'全唐诗/poet.song.186000.json','["據坐胡床，風悄悄地。", "四八癡人夜走，未免落他圈樻。", "七佛之師，也遭連累。", "石田當時在傍，只消打箇噴嚏。"]'),
('7c215932-2407-49b2-b824-b1460eca2361','靈照女贊','釋法薰','宋','宋诗','song-poetry','','[]','惡種草，生冤家。',30,'全唐诗/poet.song.186000.json','["惡種草，生冤家。", "笊籬定價，分文不差。", "末梢猶尀耐，機先不讓爺。"]'),
('11019b73-0c2c-4234-b8fb-c778f736e998','破庵和尚贊','釋法薰','宋','宋诗','song-poetry','','[]','百無能，得人憎。',46,'全唐诗/poet.song.186000.json','["百無能，得人憎。", "火中釣鱉，日裏藏冰。", "養子不曾教，繩上更安繩。", "谷孤古東山正脈，烏戶呼真本川僧。"]'),
('3397bea5-11a7-4c83-87b8-5274d42042be','贊水月觀音','釋法薰','宋','宋诗','song-poetry','','[]','現自在端嚴相，起利他悲憫心。',42,'全唐诗/poet.song.186000.json','["現自在端嚴相，起利他悲憫心。", "水茫茫，月沉沉。", "衆生無盡，我願方興。", "曉而復昏，泯去來今。"]'),
('60c4bb7f-b5f8-4344-9b11-e8b2d840676c','贊豐干','釋法薰','宋','宋诗','song-poetry','','[]','走松門，尋寒拾。',30,'全唐诗/poet.song.186000.json','["走松門，尋寒拾。", "虎斑易見，人斑難識。", "識不識，惡聲惡跡成狼藉。"]'),
('34e8f56a-49b8-4fcb-9a63-f482ce71bbbd','贊布袋','釋法薰','宋','宋诗','song-poetry','','[]','掣風顛，走市廛。',42,'全唐诗/poet.song.186000.json','["掣風顛，走市廛。", "回頭顧盼，拄杖橫肩。", "山僧既見，不可無言。", "㘞，放下破布袋，與你一文錢。"]'),
('aa3d74b8-9748-4f7b-ad87-8d7c3ece43a8','贊三教圖','釋法薰','宋','宋诗','song-poetry','','[]','警世昏，三老翁，服雖殊，心亦同。',28,'全唐诗/poet.song.186000.json','["警世昏，三老翁，服雖殊，心亦同。", "於中議優劣，蒿箭射虛空。"]'),
('27556b3d-d70d-4624-94ad-87efa77cfbaa','贊政黄牛','釋法薰','宋','宋诗','song-poetry','','[]','不解倒騎，惟牛所之。',36,'全唐诗/poet.song.186000.json','["不解倒騎，惟牛所之。", "郊原平衍，鞭索不施。", "山黯黯，水漪漪。", "知我者，白鷺鷥。"]'),
('cb6c0a34-f1e9-4901-90aa-e371fcd3f7cd','仙人望月濯足','釋法薰','宋','宋诗','song-poetry','','[]','夜靜山空月半彎，挽衣垂足滌潺湲。',32,'全唐诗/poet.song.186000.json','["夜靜山空月半彎，挽衣垂足滌潺湲。", "無人領此深深意，別向壺中更覓天。"]'),
('2977e723-1af8-4011-ad12-121dad6a0b8e','贊宗道者','釋法薰','宋','宋诗','song-poetry','','[]','走下桐城赤脚歸，半風顛又半憨癡。',32,'全唐诗/poet.song.186000.json','["走下桐城赤脚歸，半風顛又半憨癡。", "草鞋却把袈裟裹，二虎雙鴉笑殺伊。"]'),
('08d2c591-e36f-4ee0-a6a9-f7186db981d9','贊黄檗和尚','釋法薰','宋','宋诗','song-poetry','','[]','破布裹真珠，古寺甘守拙。',52,'全唐诗/poet.song.186000.json','["破布裹真珠，古寺甘守拙。", "與裴國安名，對百丈吐舌。", "棒頭敲出小廝兒，却向大愚言下瞥。", "瞥不瞥，返遭一掌如何雪。"]'),
('ec58c519-cb24-48c8-bc0c-c4fd9e88650a','贊蓑衣道人','釋法薰','宋','宋诗','song-poetry','','[]','佯狂混跡養天和，上界其如官府多。',32,'全唐诗/poet.song.186000.json','["佯狂混跡養天和，上界其如官府多。", "暑了又寒寒又暑，一蓑衣外更無他。"]'),
('702f9132-91bb-42de-862f-9c29ebe2399d','贊朝陽穿破衲待月了殘經  其一','釋法薰','宋','宋诗','song-poetry','','[]','一衲三冬，千針萬線。',22,'全唐诗/poet.song.186000.json','["一衲三冬，千針萬線。", "日影上三竿，眼力增一半。"]'),
('3e4504a6-65d2-426e-8129-38f6e1af005a','贊朝陽穿破衲待月了殘經  其二','釋法薰','宋','宋诗','song-poetry','','[]','日晷已殂，我經未了。',22,'全唐诗/poet.song.186000.json','["日晷已殂，我經未了。", "掩卷立須臾，冰壺挂林杪。"]'),
('79228219-c84c-492a-ac50-99186e8d7fe5','福長老繪師像請贊','釋法薰','宋','宋诗','song-poetry','','[]','施不犯令，用無病藥。',58,'全唐诗/poet.song.186000.json','["施不犯令，用無病藥。", "笑有祖已來，錯會者多。", "將衲僧珍財，盡底籍沒。", "空腹高心，有年無德。", "就中一處最堪憐，車子橫推向途轍。"]'),
('63c759c6-6a45-46bb-8902-8d505c01ab84','潮州禮長老請贊','釋法薰','宋','宋诗','song-poetry','','[]','面如死灰，匙挑不上。',58,'全唐诗/poet.song.186000.json','["面如死灰，匙挑不上。", "祖翁活業，盡情破蕩。", "無星秤子拈來，也解分斤定兩。", "禮長老，少思算。", "鱷魚幸自徙化方，勾引渠歸成禍患。"]'),
('9b4aa645-2e94-4d26-8285-ef3e717ccee6','自贊','釋法薰','宋','宋诗','song-poetry','','[]','處世昏昏，臨事草草。',52,'全唐诗/poet.song.186000.json','["處世昏昏，臨事草草。", "太近實頭，人謂古老。", "是非到耳，風吹石臼。", "只有一般，最不恰好。", "解騎三脚馿，來往長安道。"]'),
('73bb3d50-f0b5-4366-b5a7-8d843060bd38','總長老請贊','釋法薰','宋','宋诗','song-poetry','','[]','百種無能，面冷如冰。',65,'全唐诗/poet.song.186000.json','["百種無能，面冷如冰。", "與世落落，任運騰騰。", "愛將一字禪，靠倒杜衲僧。", "厨山長老，却要稟承。", "谷孤古，林鴆砧。", "各自有響音，又何必書此處無金。"]'),
('7f46484e-bee7-4a94-be52-c036cafdf5fe','炬長老請贊','釋法薰','宋','宋诗','song-poetry','','[]','刀不自截，水不自洗。',40,'全唐诗/poet.song.186000.json','["刀不自截，水不自洗。", "我真我贊，成何道理。", "請之既堅，却之不已。", "有一句子，玄沙道底。"]'),
('ec4c9e2c-bdc1-45c7-bdc1-93b38176d770','清菴主請贊','釋法薰','宋','宋诗','song-poetry','','[]','以石爲田，舉世怪笑。',48,'全唐诗/poet.song.186000.json','["以石爲田，舉世怪笑。", "一粒入土，不耘自秀。", "也無禪，也無道。", "衲僧未跨門，早已勘破了。", "頂門自有通天竅。"]'),
('e3a3d3e4-1343-43ae-910e-88f07c165acc','昭長老請贊','釋法薰','宋','宋诗','song-poetry','','[]','全無孔竅，指桑駡柳。',46,'全唐诗/poet.song.186000.json','["全無孔竅，指桑駡柳。", "瞎衲僧正眼，破東山暗號。", "三點前，三點後。", "起模畫樣已無端，一任傍人論好醜。"]'),
('bcc840d2-5a35-490d-b7a0-2954da724572','寒岩居士請贊','釋法薰','宋','宋诗','song-poetry','','[]','末法無知老比丘，虛空尋縫陸行舟。',32,'全唐诗/poet.song.186000.json','["末法無知老比丘，虛空尋縫陸行舟。", "寒岩可謂心腸毒，寫出令人駡不休。"]'),
('7f7b96d5-c9d4-46f9-afb9-cb91acf4dec8','尼長老請贊','釋法薰','宋','宋诗','song-poetry','','[]','住山三十載，潦倒福緣微。',52,'全唐诗/poet.song.186000.json','["住山三十載，潦倒福緣微。", "全提一著，衲子攢眉。", "我無溈山之作，汝有鐵磨之機。", "自知水底難撈月，却倩丹青染污伊。"]'),
('c2d257c1-8f2e-4d73-ae62-d600816d8046','秀長老請贊','釋法薰','宋','宋诗','song-poetry','','[]','飛來峰下，龍床角畔。',68,'全唐诗/poet.song.186000.json','["飛來峰下，龍床角畔。", "用沒意志一著，師僧遭他惑亂。", "胡笳忽轉陽春調，也有知音來合伴。", "描邈將來，未得一半。", "直饒即今此話大行，已是彼此兩不著便。"]'),
('5c0cf335-ef11-45e1-9c71-4d3ba6a77e37','贊李源圓澤圖','釋法薰','宋','宋诗','song-poetry','','[]','昭昭靈靈，未脫生死。',40,'全唐诗/poet.song.186000.json','["昭昭靈靈，未脫生死。", "等閑狹路相逢，無奈這冤家子。", "天竺山前招角歌，至今餘韵在松蘿。"]'),
('d7f5caaa-e434-4e22-b632-41feeedc4bce','贊呂先生','釋法薰','宋','宋诗','song-poetry','','[]','爲儒儒不達，學仙仙非真。',44,'全唐诗/poet.song.186000.json','["爲儒儒不達，學仙仙非真。", "黄龍門下過，秋蚊咬鐵釘。", "回先生，回先生。", "岳陽人不識，老樹却成精。"]'),
('88cba58c-6fc7-471e-8627-c6ad4385d521','覺城居士請贊師頂相','釋法薰','宋','宋诗','song-poetry','','[]','全無寸長，但據馿性。',56,'全唐诗/poet.song.186000.json','["全無寸長，但據馿性。", "不行深深海底，不立高高峰頂。", "問佛法，今日困。", "瞎衲僧眼，識毗耶病。", "素與覺城無冤，何事圖形畫影。"]'),
('73cd9591-5621-40e5-894a-da66e5bf9e0f','受業師孫請贊','釋法薰','宋','宋诗','song-poetry','','[]','削髮村院裡，僻陋少見聞。',66,'全唐诗/poet.song.186000.json','["削髮村院裡，僻陋少見聞。", "信脚到南地，也作住山人。", "龍床角畔脫空話，引得衲子如蜂屯。", "思歸未得，故國夢頻。", "慇懃藉汝將予去，且看梨花二月春。"]'),
('b9cb7300-a068-4067-9f08-899d6c0d7870','自贊  其一','釋法薰','宋','宋诗','song-poetry','','[]','人棄我取，人奪我與。',52,'全唐诗/poet.song.186000.json','["人棄我取，人奪我與。", "涉世全乖，獨行無侶。", "超佛越祖當頭句，冷泉日夜滔滔舉。", "歛手忌言坐閑處，可憐也被丹青污。"]'),
