('04e4f3bc-3d56-4142-a327-a5cd94872966','贈通禪客','釋法薰','宋','宋诗','song-poetry','','[]','龍墀問法動天顔，天贈黄金一萬錢。',32,'全唐诗/poet.song.186000.json','["龍墀問法動天顔，天贈黄金一萬錢。", "打得衲僧公驗正，通禪依舊是通禪。"]'),
('2b28eade-4cce-4869-94c4-5aa3e48605e4','送師孫昧禪人','釋法薰','宋','宋诗','song-poetry','','[]','十五爲僧二十歸，途中莫比在家時。',32,'全唐诗/poet.song.186000.json','["十五爲僧二十歸，途中莫比在家時。", "老僧留浙汝回蜀，三昧從來古不知。"]'),
('06f64eb4-0934-4e1c-86b1-afe0ebd44b21','辭浄慈赴靈隠','釋法薰','宋','宋诗','song-poetry','','[]','湖上牢牢把一關，孤危獨立絕躋攀。',32,'全唐诗/poet.song.186000.json','["湖上牢牢把一關，孤危獨立絕躋攀。", "老無定力隨風轉，又向南山過北山。"]'),
('b411ca83-6be0-4049-8701-37ba9ad4c95e','題參政樓公二圓相圖','釋法薰','宋','宋诗','song-poetry','','[]','皎然書平定字，攻媿寫二圓相，引得多少平人望雲上樹。',44,'全唐诗/poet.song.186000.json','["皎然書平定字，攻媿寫二圓相，引得多少平人望雲上樹。", "且喜兩沒交涉，要知的實，却須親見石田。"]'),
('a4fc424d-be86-48b5-b181-c04a159a66b7','題卍菴墨蹟','釋法薰','宋','宋诗','song-poetry','','[]','卍菴空裏採花，諸人石上種藕。',42,'全唐诗/poet.song.186000.json','["卍菴空裏採花，諸人石上種藕。", "三點前三點后，動南星蹉北斗。", "山僧口似磉盤，舜若多神失笑。"]'),
('5d036148-1a92-4cb9-a944-a4220140249d','頌古','釋法薰','宋','宋诗','song-poetry','','[]','胡鬚赤，赤鬚胡。',32,'全唐诗/poet.song.186000.json','["胡鬚赤，赤鬚胡。", "珠走盤兮盤走珠。", "狹路相逢誇好手，兩邊雪刃血模糊。"]'),
('bef1aa1a-9d0d-4e02-9fe2-5cc3d3475186','山中','喻峙','宋','宋诗','song-poetry','','[]','我是山中萬戶侯，明知騎馬勝騎牛。',32,'全唐诗/poet.song.186000.json','["我是山中萬戶侯，明知騎馬勝騎牛。", "晚來馬上看山色，不似騎牛得自由。"]'),
('7cdf9342-57ae-45a8-aba4-3b462daa276b','晚坐','丁伯桂','宋','宋诗','song-poetry','','[]','小雨流花急，香風隨晚荷。',48,'全唐诗/poet.song.186000.json','["小雨流花急，香風隨晚荷。", "清天聞野磬，高木亂秋波。", "人度紅橋少，燈來溪徑多。", "幽冥間一坐，深恐負蒼蘿。"]'),
('fdb72274-29e1-4df1-9100-e4d24733685a','呈陳紫微','劉天益','宋','宋诗','song-poetry','','[]','欲下未下屬玉雙，喧瀑飛雪明石矼。',176,'全唐诗/poet.song.186000.json','["欲下未下屬玉雙，喧瀑飛雪明石矼。", "扁舟激瀝蒼雪淙，斷岸菰柳穿蓬窗。", "舟程未達君子邦，心源直指如湍瀧。", "後生薄俗邪說哤，老成砥柱回淳龐。", "雄文翼道寶鼎扛，日月旂常九仞杠。", "急流勇退挂冠逄，飲水嚙雪嗤羊腔。", "孤輪絕翳空吠尨，飛蛾眇影捉明釭。", "翻思解纜鹿城江，寸莛不揣洪鐘撞。", "八年喬嶽勞心悾，北望雲迷翠羽幢。", "袖裏虹霓氣不降，珍儲未辨珉與玒。", "借公大扣聲樅樅，庶幾蚊蝱附奔駹。"]'),
('dcc9ea3f-d1b9-46a0-bab7-eb3e212c3e62','遺鏡','劉天益','宋','宋诗','song-poetry','','[]','親去鏡亦去，鏡還親不還。',48,'全唐诗/poet.song.186000.json','["親去鏡亦去，鏡還親不還。", "從今磨積垢，終不對慈顔。", "明月掛臺上，白雲生匣間。", "洪恩何以報，羞見鬢毛斑。"]'),
('0a9bd81b-8b71-47fe-9445-c7e33b2e4a87','題招提院靜照堂','吳振','宋','宋诗','song-poetry','','[]','古剎深沉一水邊，清虛疑是翠微間。',64,'全唐诗/poet.song.186000.json','["古剎深沉一水邊，清虛疑是翠微間。", "門前滾滾紅塵閙，堂上翛翛白日閒。", "燕坐不知增夏臘，冥心安在更雲山。", "靜中別有真消息，於此誰何合往還。"]'),
('94008c6a-6eda-4035-8fd3-620ab260bdd0','題蘭亭帖','王容','宋','宋诗','song-poetry','','[]','昭陵永閟千年迹，定武相傳幾樣碑。',64,'全唐诗/poet.song.186000.json','["昭陵永閟千年迹，定武相傳幾樣碑。", "此是中原舊時本，石今焉往落東夷。", "君家何處得此紙，刻畫爛然猶可喜。", "六丁神物好護持，更有諸君題姓字。"]'),
('a9ce957f-2d0d-4f31-87ee-3312ec1cfd16','絕句','徐文卿','宋','宋诗','song-poetry','','[]','紙衣竹几一蒲團，閉戶然萁自屈盤。',32,'全唐诗/poet.song.186000.json','["紙衣竹几一蒲團，閉戶然萁自屈盤。", "誦徹離騷二千五，不知月落夜深寒。"]'),
('57e20354-58f2-4823-9714-5553b50b9b7a','遊洞巖','徐文卿','宋','宋诗','song-poetry','','[]','跨馬絕風煙，夜與雲俱宿。',120,'全唐诗/poet.song.186000.json','["跨馬絕風煙，夜與雲俱宿。", "彈琴向窗間，微月挂森木。", "曉行巖上路，一溪緣浄綠。", "路窮入其中，溪流貫山腹。", "巖開類天設，石亂疑鬼伏。", "水從何自來，乃爾瑩心目。", "巖前野僧居，種桃滿空谷。", "惜已過芳時，不見花芬馥。", "平生青霞志，恥受紅塵辱。", "老我茅三間，茲山疑可卜。"]'),
('5704d15c-1531-4a91-84f2-3db8c37b01b0','南澗小飲夜過景德次仲止韵','徐文卿','宋','宋诗','song-poetry','','[]','嫩柳行邊行未匝，落梅香裏立多時。',32,'全唐诗/poet.song.186000.json','["嫩柳行邊行未匝，落梅香裏立多時。", "一杯徑醉歸來晚，江上伶俜瘦影隨。"]'),
('baa677a9-9d22-412c-b49c-74754c3cd3e6','秋後二首  其一','徐文卿','宋','宋诗','song-poetry','','[]','種豆山園中，土瘠豆不實。',72,'全唐诗/poet.song.186000.json','["種豆山園中，土瘠豆不實。", "攟收能幾何，倚杖三歎息。", "況此山下田，旱久苗葉赤。", "無豆尚猶可，無禾孰供食。", "已孤豐稔望，徒費耘耕力。", "官吏更索租，真爾從何出。"]'),
('5a771415-d5c7-4b2d-84b4-acd4a229bbe6','秋後二首  其二','徐文卿','宋','宋诗','song-poetry','','[]','劇暑不易摧，屢雨方肯低。',96,'全唐诗/poet.song.186000.json','["劇暑不易摧，屢雨方肯低。", "曉行殘月裏，秋意乃忽淒。", "習習風攪樹，曳曳雲出溪。", "伴我塵外躅，更有白鷺兒。", "節往四敘改，人老百慮非。", "策世竟莫售，勤身復奚爲。", "徘徊發詠歎，蒼茫度荒陂。", "且歸煮香秔，解此腹中饑。"]'),
('f2dfe4a4-8a3b-49a9-adbc-9d52cd366e3a','感興','徐文卿','宋','宋诗','song-poetry','','[]','百穀所成就，乃在摇落時。',48,'全唐诗/poet.song.186000.json','["百穀所成就，乃在摇落時。", "天欲金玉汝，乃有寒與饑。", "寒饑天所賜，勿遽令心悲。", "草玄寂寞濱，可與古人歸。"]'),
('585aecaf-2fdc-4a1f-969a-def22b4ea8dc','送春','徐文卿','宋','宋诗','song-poetry','','[]','綠陰青子漸能佳，楊柳深藏三四鴉。',32,'全唐诗/poet.song.186000.json','["綠陰青子漸能佳，楊柳深藏三四鴉。", "春有餘情無處著，林邊野草亦開花。"]'),
('4b5bb230-5c11-4a4d-81fd-35a91cbc2f2a','偶題','徐文卿','宋','宋诗','song-poetry','','[]','綠樹何稠疊，清風稍羨餘。',48,'全唐诗/poet.song.186000.json','["綠樹何稠疊，清風稍羨餘。", "枕縈雲片片，簾透雨疏疏。", "修筧通泉壑，殘碑出野鉏。", "丘陵知幾變，耕稼雜陶漁。"]'),
('609fca3c-7180-4710-8a9d-9e9df0db29af','雨後到南山村家','徐文卿','宋','宋诗','song-poetry','','[]','衝雨入窮山，山民猶閉關。',48,'全唐诗/poet.song.186000.json','["衝雨入窮山，山民猶閉關。", "橘垂茅屋畔，梅映竹籬間。", "奇石依林立，清泉繞舍灣。", "吾思隠茲地，凝立未知還。"]'),
('beb50238-e6e1-45ed-a4b8-b11f79b8a2e4','因放翁以劍南詩稿爲贈詠歎之餘賦短歌以謝','徐文卿','宋','宋诗','song-poetry','','[]','半生誦公流傳詩，每恨收拾多所遺。',103,'全唐诗/poet.song.186000.json','["半生誦公流傳詩，每恨收拾多所遺。", "豈知二千五百二十有四首，一旦俱爲吾得之。", "長松駕壑風烟老，春花嫣然動碧草。", "祇今忠憤欲白頭，四海但推言語好。", "有文如此何所憂，世間萬事元悠悠。", "君不見李杜千載名不休，豈不勝彼公與侯。"]'),
('c36d328b-503a-4e4a-8e4c-79abfba25465','廬陵劉氏以仲立於枕上和余韵夜半得詩句敲門喚余余攝衣而起相對語于野航橋上殊爲勝絕因再用韵','徐文卿','宋','宋诗','song-poetry','','[]','夜半詩壇喜解圍，楚天雲淡玉繩低。',64,'全唐诗/poet.song.186000.json','["夜半詩壇喜解圍，楚天雲淡玉繩低。", "撞鐘自得興不淺，泣鬼初成人未知。", "踏月過橋驚鶴睡，犯霜對語伴烏啼。", "蕭條此意欣重見，絕勝圍紅醉玉巵。"]'),
('971d5f74-7dbc-4eaa-95fe-4726652c5a9b','九鎖步虛詞 第一天關鎖','陳洵直','宋','宋诗','song-poetry','','[]','仙人十二樓，緲緲垂重鐶。',48,'全唐诗/poet.song.186000.json','["仙人十二樓，緲緲垂重鐶。", "志士憫幽阻，鬰觀何繇攀。", "棲真歷幾塵，洞戶方孱顔。", "一鎖度靈鑰，九虎開天關。"]'),
('a49bb55a-7f4c-49e4-8ecf-d3aeee45a4a5','九鎖步虛詞 第二藏雲鎖','陳洵直','宋','宋诗','song-poetry','','[]','圓象默交感，序氣翔氛氳。',48,'全唐诗/poet.song.186000.json','["圓象默交感，序氣翔氛氳。", "飆欻偃華蓋，貫絡百寶熏。", "八景非真遥，款扣虛皇君。", "二鎖度靈鑰，松風卷藏雲。"]'),
('13478303-ddb5-4b62-b685-e1ea1cc4fd9b','九鎖步虛詞 第三飛鸞鎖','陳洵直','宋','宋诗','song-poetry','','[]','琅軒列朱房，風露峨高寒。',48,'全唐诗/poet.song.186000.json','["琅軒列朱房，風露峨高寒。", "森羅九宮道，隠約八卦壇。", "春酣酌金漿，徹視揮外丹。", "三鎖度靈鑰，悠悠控飛鸞。"]'),
('82099049-6402-4f0e-ba17-8dba574a72df','九鎖步虛詞 第四凌虛鎖','陳洵直','宋','宋诗','song-poetry','','[]','太虛本非有，團塊何迂疎。',48,'全唐诗/poet.song.186000.json','["太虛本非有，團塊何迂疎。", "一旬更五日，風乎駛軒如。", "神馭兩腋輕，絳霞理襟裾。", "四鎖度靈鑰，八表當淩虛。"]'),
('9841990a-be63-46bb-941e-d1e59cae6be8','九鎖步虛詞 第五通真鎖','陳洵直','宋','宋诗','song-poetry','','[]','神氣化虛晃，太上尊玉宸。',48,'全唐诗/poet.song.186000.json','["神氣化虛晃，太上尊玉宸。", "鍊此沈下質，感彼元上春。", "靈液反流用，偃息崑閬津。", "五鎖度靈鑰，滯散潛通真。"]'),
('8bd8da65-16ee-415c-a77a-8b43050993bd','九鎖步虛詞 第六龍吟鎖','陳洵直','宋','宋诗','song-poetry','','[]','崿嶂洞陰窅，嶕嶢鬰千尋。',48,'全唐诗/poet.song.186000.json','["崿嶂洞陰窅，嶕嶢鬰千尋。", "中有不測淵，蜿蜒伏蕭森。", "作霈待時舉，妙化通天心。", "六鎖度靈鑰，綜御歸龍吟。"]'),
('b9f09350-8194-4547-ad9f-860a8d77f438','九鎖步虛詞 第七洞微鎖','陳洵直','宋','宋诗','song-poetry','','[]','嘉遁仰靈範，世道何韁鞿。',48,'全唐诗/poet.song.186000.json','["嘉遁仰靈範，世道何韁鞿。", "長生昔對面，皇皇昧玄機。", "沆瀣不足吞，正一知所歸。", "七鎖度靈鑰，進力行洞微。"]'),
('df97b276-daa6-4ec8-9aec-86f7c0c7f9ad','九鎖步虛詞 第八雲璈鎖','陳洵直','宋','宋诗','song-poetry','','[]','犖确玉峰矗，真朋夐遨遊。',48,'全唐诗/poet.song.186000.json','["犖确玉峰矗，真朋夐遨遊。", "洗耳發清響，躡蹻瑲鸞高。", "飛泉落松杪，節奏風蕭騷。", "八鎖度靈鑰，鏗鏗引雲璈。"]'),
('5b6f641c-ab95-46e9-8793-c0f35af718d7','九鎖步虛詞 第九朝元鎖','陳洵直','宋','宋诗','song-poetry','','[]','矯首太霞真，飛忱紫微垣。',48,'全唐诗/poet.song.186000.json','["矯首太霞真，飛忱紫微垣。", "委蛻速霞舉，脫灑人命門。", "羽葆交芝雲，琳琅飆神旛。", "九鎖度靈鑰，五氣身朝元。"]'),
('6ce69348-8e71-4ee4-885c-d4833523f97e','游大滌假宿鳴玉館偶成','陳洵直','宋','宋诗','song-poetry','','[]','風動歸雲清，日落衆山楚。',48,'全唐诗/poet.song.186000.json','["風動歸雲清，日落衆山楚。", "重來興彌深，託宿此何所。", "浪浪鳴玉泉，恍恍對床雨。", "夢斷身高低，塵勞深夜語。"]'),
('6cad1973-d084-4f54-a24a-225d40952f0a','茶嶺','陳洵直','宋','宋诗','song-poetry','','[]','絕頂方知天柱雲，早芽先破禁宮春。',32,'全唐诗/poet.song.186000.json','["絕頂方知天柱雲，早芽先破禁宮春。", "琳罌入貢無多種，附隴鎗旗盡得珍。"]'),
('7a9c0c7d-017f-4d43-8c2e-61462716d387','石床','陳洵直','宋','宋诗','song-poetry','','[]','洞君一榻爲誰懸，雲帳苔茵不外傳。',32,'全唐诗/poet.song.186000.json','["洞君一榻爲誰懸，雲帳苔茵不外傳。", "我醉欲眠非有地，也應重應寢虛緣。"]'),
('bf3f3953-761a-44e1-a689-5d4395178141','天壇','陳洵直','宋','宋诗','song-poetry','','[]','峰頂侵雲法象寒，遠遊虛唱肅天官。',32,'全唐诗/poet.song.186000.json','["峰頂侵雲法象寒，遠遊虛唱肅天官。", "松吟泉漱人仙去，猶想簫聲落舊壇。"]'),
('fab7a0ad-f459-4bcf-bd63-1359a536758e','翠蛟亭','陳洵直','宋','宋诗','song-poetry','','[]','老樹根深絡石頑，危簷飛棟插高寒。',32,'全唐诗/poet.song.186000.json','["老樹根深絡石頑，危簷飛棟插高寒。", "爲誰洗盡蒼龍骨，成嶺成峰上上看。"]'),
('49b6d011-1005-45b4-bc00-97f771cdaf3f','盤天柱絕峰','陳洵直','宋','宋诗','song-poetry','','[]','洞天三釂碧琳腴，大滌峰高躡太虛。',32,'全唐诗/poet.song.186000.json','["洞天三釂碧琳腴，大滌峰高躡太虛。", "落日寒山宮闕近，恨無人寄絕家書。"]'),
('4779fd65-2c53-412b-a2f0-6f0124bda6ea','大滌洞','陳洵直','宋','宋诗','song-poetry','','[]','籙簡深投幾井函，金堂玉室指空巖。',32,'全唐诗/poet.song.186000.json','["籙簡深投幾井函，金堂玉室指空巖。", "不須騎氣求林屋，一柱縣虛政隔凡。"]'),
('42f0e588-f79b-407a-8c00-56cee964b865','放水澗','陳洵直','宋','宋诗','song-poetry','','[]','碧澗淙流繚一源，閘機不露暗驚湍。',32,'全唐诗/poet.song.186000.json','["碧澗淙流繚一源，閘機不露暗驚湍。", "李翶千載濤江興，猛跨鼇頭立足看。"]'),
('b41aca79-ef33-44b0-a8a6-1e29147d704f','歸雲洞','陳洵直','宋','宋诗','song-poetry','','[]','衆真霞珮上三天，誰見回飈□駕旋。',32,'全唐诗/poet.song.186000.json','["衆真霞珮上三天，誰見回飈□駕旋。", "洞府後門人不信，片雲鶴鶴是歸仙。"]'),
('460ffa70-c909-4093-b87d-f402eb0fbabd','鳴風洞','陳洵直','宋','宋诗','song-poetry','','[]','朱鳥何年作瑞來，豈緣梧竹劃山開。',32,'全唐诗/poet.song.186000.json','["朱鳥何年作瑞來，豈緣梧竹劃山開。", "醴泉只在嵌巖裏，醉入幽棲更不迴。"]'),
('5f9d6432-3222-4822-827f-2b2abd3b7626','雲根','陳洵直','宋','宋诗','song-poetry','','[]','朵雲朝起北山陰，暮入西崗散莫尋。',32,'全唐诗/poet.song.186000.json','["朵雲朝起北山陰，暮入西崗散莫尋。", "誰謂植根元不動，自從歸後出無心。"]'),
('1d069f4f-1050-4dfb-bf4f-c222fd34f0e4','藥圃','陳洵直','宋','宋诗','song-poetry','','[]','不發藏丹採石英，蘼蕪昌歜預芬榮。',32,'全唐诗/poet.song.186000.json','["不發藏丹採石英，蘼蕪昌歜預芬榮。", "五山瑶草無人見，爲問靈苗種得成。"]'),
('3f57392a-9f6d-4088-98d5-b10161ad27ec','白茅洞','陳洵直','宋','宋诗','song-poetry','','[]','茅君職守屢經年，懸竇回中坐幾仙。',32,'全唐诗/poet.song.186000.json','["茅君職守屢經年，懸竇回中坐幾仙。", "酒甕若盈吾欲客，不須靈竅仰觀天。"]'),
('d7090494-8c8e-44f0-b031-c46b21806426','馴虎巖','陳洵直','宋','宋诗','song-poetry','','[]','骨橫虎口孰當雄，處士臨壇風自從。',32,'全唐诗/poet.song.186000.json','["骨橫虎口孰當雄，處士臨壇風自從。", "猛伏丹成俱解化，至今靈草記沉蹤。"]'),
('a2511b35-1900-4108-abc1-d1ad2034b2a5','龍蛻洞','陳洵直','宋','宋诗','song-poetry','','[]','一穴中通百尺湫，骨寒空蛻洞門秋。',32,'全唐诗/poet.song.186000.json','["一穴中通百尺湫，骨寒空蛻洞門秋。", "鱗潛變化疑相近，貝闕珠宮入海求。"]'),
('73ee8a33-81c9-4873-947c-09523e1eb142','無骨箬','陳洵直','宋','宋诗','song-poetry','','[]','山中紺箬元無脊，爐裏金丹日月開。',32,'全唐诗/poet.song.186000.json','["山中紺箬元無脊，爐裏金丹日月開。", "不是潛藏杜塵世，有人曾見碧蟾來。"]'),
('150c8517-ad9d-4599-acbf-2105cdc9177b','祥光亭','陳洵直','宋','宋诗','song-poetry','','[]','金色輝祥發洞靈，是中日月久分精。',32,'全唐诗/poet.song.186000.json','["金色輝祥發洞靈，是中日月久分精。", "煌煌燁燁常如在，却笑時人不眼明。"]'),
('6b65ea9d-9f0b-427d-9adb-8ca439dc80b0','石室  其一','陳洵直','宋','宋诗','song-poetry','','[]','雲廣翛閑失故宮，泓泉虬木古今同。',32,'全唐诗/poet.song.186000.json','["雲廣翛閑失故宮，泓泉虬木古今同。", "詩仙羽化無蹤跡，後世何人識此風。"]'),
('e158c9d0-c397-4b58-a058-2b14a2b2e737','石室  其二','陳洵直','宋','宋诗','song-poetry','','[]','石梯之字上青峰，碧玉琅玕掃碧空。',32,'全唐诗/poet.song.186000.json','["石梯之字上青峰，碧玉琅玕掃碧空。", "內隠一壺塵外室，夜吞明月曉吞風。"]'),
('1428ad38-1eaa-456f-8d9b-d388662bcbe6','石室  其三','陳洵直','宋','宋诗','song-poetry','','[]','琅玕蘂笈藏幽谷，唯見白雲三五幅。',32,'全唐诗/poet.song.186000.json','["琅玕蘂笈藏幽谷，唯見白雲三五幅。", "昔日天師其姓吳，巖前遺下雲中屋。"]'),
('9bbb0062-011b-4ea0-a0e7-62d32400a8e2','石室  其四','陳洵直','宋','宋诗','song-poetry','','[]','紫靄丹霓磨壁金，巖橋跨麓橫青陰。',32,'全唐诗/poet.song.186000.json','["紫靄丹霓磨壁金，巖橋跨麓橫青陰。", "陸先生事今何在，石室雲深無客尋。"]'),
('56b3546c-b927-4495-867a-d83ed6a0eb92','清音亭','陳洵直','宋','宋诗','song-poetry','','[]','水石何曾有古今，如絲如竹度高深。',32,'全唐诗/poet.song.186000.json','["水石何曾有古今，如絲如竹度高深。", "自疑扁榜通塵聽，百代潺潺無賞音。"]'),
('8fdfbc50-1aab-4274-9513-bcee335d9064','冷泉亭','陳洵直','宋','宋诗','song-poetry','','[]','泯泯長流徹底清，石間松下倦心情。',32,'全唐诗/poet.song.186000.json','["泯泯長流徹底清，石間松下倦心情。", "洞天咫尺樞衣便，抖擻精神爲濯纓。"]'),
('714f1ccb-f661-4c1b-a941-8f1c87faf7a6','石門','陳洵直','宋','宋诗','song-poetry','','[]','神力何年揭此門，破雲穿月扣天閽。',32,'全唐诗/poet.song.186000.json','["神力何年揭此門，破雲穿月扣天閽。", "平生不得朝天路，猿鶴相招試與言。"]'),
('a0e0bc15-4dbd-463f-8e06-cecb5f65aa11','舞翠亭','陳洵直','宋','宋诗','song-poetry','','[]','老木槎牙罨澗深，翠蛟舞處一庭陰。',32,'全唐诗/poet.song.186000.json','["老木槎牙罨澗深，翠蛟舞處一庭陰。", "響泉不住流佳句，想見坡仙筆外心。"]'),
('5be32cfe-5c2d-416b-b933-c99bdfdbdfb9','歸雲庵','陳洵直','宋','宋诗','song-poetry','','[]','聚散空中不可期，虛含五色豈多姿。',32,'全唐诗/poet.song.186000.json','["聚散空中不可期，虛含五色豈多姿。", "歸來便合沈蹤跡，却是行人見出時。"]'),
('f3ba4cf1-3874-438d-8960-7c4fc9ab71b2','判幸倅求免稅丁','郢州太守','宋','宋诗','song-poetry','','[]','松垣筆力破蒼溟，欲援任濤免稅丁。',32,'全唐诗/poet.song.186000.json','["松垣筆力破蒼溟，欲援任濤免稅丁。", "一段風流好公案，錦江重寫入圖經。"]'),
('cc85d960-dc43-485e-ae5b-9c0713e3bbe3','龍潭禱雨記事','楊幼輿','宋','宋诗','song-poetry','','[]','戴星躡履謁靈祠，俯瞰龍宮映綠漪。',276,'全唐诗/poet.song.186000.json','["戴星躡履謁靈祠，俯瞰龍宮映綠漪。", "鏡樣清潭三百尺，峰巒環繞聳蒼碧。", "道旁野老忽長噓，昔也原爲安民居。", "嫂笑小姑借梳掠，插梳橫耳走送却。", "姑嗔大嫂方作喧，迅雷陷宅變深潭。", "是時水底猶存屋，入夜人聞尚舂粟。", "歷年既久已無形，神龍守護稱安靈。", "呼吸風雷作雲雨，爰與人間茂禾黍。", "大觀邦人因禱祈，沛然甘澍滿郊圻。", "人皆懷惠頌靈迹，侯爵初封助懽懌。", "近時響應達朝廷，屢頒顯號莫與京。", "我來假守三逢夏，每遇乾枯叩祠下。", "靈湫一滴漲塞天，衝倒天河頻有年。", "終始恩波如一日，躬趨端拜感何極。", "肅容親炷一瓣香，稽首皈依謝休祥。", "潭心水面跳雙鯉，已覺威靈示人喜。", "南遊行矣歸故鄉，更願神兮長久與民作豐穰。"]'),
('e807c1d6-f7bc-4254-bfb2-7acd3c219dbb','遊老君洞','楊幼輿','宋','宋诗','song-poetry','','[]','陰陽無端更去流，世間盛福難全收。',160,'全唐诗/poet.song.186000.json','["陰陽無端更去流，世間盛福難全收。", "古人一麾耻外郡，今我半刺來邊州。", "到官未久出按縣，滿眼猺獞森戈矛。", "誰知造化默相補，玉融山水何清幽。", "蒼崖翠壁老君洞，健非巧宦能兼遊。", "萬歲乳成滴白柱，一卷溪畔眠青牛。", "真仙遺迹覽不盡，散髮坐石臨清流。", "灑然形質已自失，欲釀溟滓觴浮邱。", "襟懷浩浩隘八極，身外何物非輕漚。", "數聲長笑下山去，幾點白雲天際頭。"]'),
('6797dc12-55f5-4d6d-9f72-52516d9cf80b','遊越山','幸元龍','宋','宋诗','song-poetry','','[]','上得越山半，方壺紫翠環。',48,'全唐诗/poet.song.186000.json','["上得越山半，方壺紫翠環。", "山幽春溜響，花落午陰閑。", "梵剎依松外，仙家在竹間。", "小窗借高枕，風定鳥綿蠻。"]'),
('e9b7b328-5bfa-4d50-932a-619b81521fb6','宴黄狀元大任','史彌堅','宋','宋诗','song-poetry','','[]','月色花光正可人，笙歌會處喜津津。',64,'全唐诗/poet.song.186000.json','["月色花光正可人，笙歌會處喜津津。", "跨鰲海上文章客，攬轡天隅禮樂臣。", "丹碧屏間三月暮，玻璃杯裏一團春。", "暫聽紫燕黄鸝語，更捧紅雲侍玉宸。"]'),
('eeb5d2f5-dbf8-4b50-b62b-3ee8cc1ad02d','草堂','周端朝','宋','宋诗','song-poetry','','[]','上林不花一水凈，游魚姿媚翻寒景。',64,'全唐诗/poet.song.186000.json','["上林不花一水凈，游魚姿媚翻寒景。", "釣簑風冷天欲霜，惟有白鷗雙對影。", "北隣白幘南烏巾，暮鴉共集無行人。", "草堂老翁喚不醒，孤照野梅消息新。"]'),
('d2a714ba-dc46-46b8-b023-c76ebc45ed4b','擬古','周端朝','宋','宋诗','song-poetry','','[]','穠桃復穠李，照影落春水。',84,'全唐诗/poet.song.186000.json','["穠桃復穠李，照影落春水。", "渡頭看青楊，剪剪從風起。", "裁書寫連環，殷勤問行李。", "一籠幺鳳翼，一繫青鸞尾。", "江南三月天，羣英爛如綺。", "開到蕪菁花，春事良未已。", "何當緩緩歸，蕩漾綠波裏。"]'),
('6c41b9c4-bfb1-418c-9707-2b6a20d5ede8','客去','周端朝','宋','宋诗','song-poetry','','[]','客去深閉門，晏坐支其頤。',48,'全唐诗/poet.song.186000.json','["客去深閉門，晏坐支其頤。", "門前車馬喧，而此不及知。", "獨鼓無絃琴，自着一色棋。", "鳥啼花含笑，相對亦怡怡。"]'),
('23c0f57d-086c-4162-9c26-c17be860270e','黄田禹廟','周端朝','宋','宋诗','song-poetry','','[]','越人猶績禹，疏鑿此江邊。',49,'全唐诗/poet.song.186000.json','["越人猶績禹，疏鑿此江邊。", "地合秦城水，門浮楚客船。", "蔭槐爲帝里，種稻屬徭田。", "嘲异常巫言罷，寒雲又慘然。"]'),
('8c7d5bf6-b424-4595-ba37-45a65b2bd889','三江口','周端朝','宋','宋诗','song-poetry','','[]','吳門臺北竹樓隅，三日追陪漫叟居。',64,'全唐诗/poet.song.186000.json','["吳門臺北竹樓隅，三日追陪漫叟居。", "曉夢驚辭赤壁鶴，夜棲看打武昌魚。", "橫洲遥溆分燈影，落月斜河運斗車。", "回伏三江問漢口，陸離蘭葉響環琚。"]'),
('dbf85c42-d624-42a7-8798-b69482a0e8d6','遊寶蓋巖','鄒應龍','宋','宋诗','song-poetry','','[]','夙有斯巖約，今朝喜踐盟。',48,'全唐诗/poet.song.186000.json','["夙有斯巖約，今朝喜踐盟。", "路從支澗入，人在半空行。", "六月如霜候，四時長雨聲。", "願求容膝地，著我過浮生。"]'),
('c502205f-bbae-4841-a310-30803152958c','遊寶林寺','鄒應龍','宋','宋诗','song-poetry','','[]','乳燕啼鳩三月暮，淡雲疎雨午時天。',32,'全唐诗/poet.song.186000.json','["乳燕啼鳩三月暮，淡雲疎雨午時天。", "金雀花落無人管，斷送韶光又一年。"]'),
('5f9fd9f3-e357-4c79-a670-2da51551c9fc','廣寒遊','趙汝鐩','宋','宋诗','song-poetry','','[]','九秋半矩月團團，瓊瑶世界夜氣寒。',160,'全唐诗/poet.song.186000.json','["九秋半矩月團團，瓊瑶世界夜氣寒。", "羽士躍身導阿瞞，麾斥八極青雲端。", "老柯擲桂香不死，銀橋跨空一萬里。", "飛步抽簪扣玉扃，中有素娥三千人。", "綠瞳翦水鬢堆霧，風卷縞袖條脫露。", "琅璈雲笛廣庭舞，笑乘白鸞弄蟾兔。", "歸裁仙曲作霓裳，天音盡洗凡絲簧。", "霞裾星珮羅兩行，玉環垂手春風場。", "樽前盡日看未足，絳膏泣鳳夜繼燭。", "宮商忽變不可聽，馬嵬斜谷雨霖鈴。"]'),
('199e0411-e639-4eab-bd2c-d98741bbcf13','古別離','趙汝鐩','宋','宋诗','song-poetry','','[]','妾離父母來從君，相期百年終此身。',150,'全唐诗/poet.song.186000.json','["妾離父母來從君，相期百年終此身。", "初合鸞凰席未煖，熟視眉目識未真。", "兵符捉人夜調遣，丁寧尅日到邊面。", "紅旗在手弓在腰，花驄一躍迅於箭。", "回頭語我勿慘傷，歸來印斗金带黄。", "我聞軍功未易就，膏血紫塞十八九。", "嫁狗逐狗雞逐雞，耿耿不寐展轉思。", "吠月啼曉喧孤幃，淚雨千行心肝摧。", "與其眼穿萬里見無日，何如同赴沙場戰死俱白骨。"]'),
('25b5394b-ab25-45a5-83f1-fad41e1f3577','迎仙引','趙汝鐩','宋','宋诗','song-poetry','','[]','羽人窟宅壓滄溟，崑崙閬風天墉城。',226,'全唐诗/poet.song.186000.json','["羽人窟宅壓滄溟，崑崙閬風天墉城。", "紫蘭絳節跨彩鳳，殷勤傳命邀同盟。", "七月七日凉秋霽，千官鏘珮森幢衛。", "王母雲車九色龍，上元霜袍三角髻。", "劉徹屏息迎兩仙，兜香塗門高馥天。", "星裳黼衮自酬酢，方朔窺窗不敢前。", "金漿玉醴濯凡腹，紅顆絢飣蟠桃熟。", "宴酣樂奏瑶池音，琅璈子登笛雙成。", "乞憐請藥承華殿，教戒丁寧先自反。", "三尸欲脫毋淫亂，五性盡捨更勤儉。", "各出數語鍼膏肓，此是長生度世方。", "徹心未悟益猖狂，萬八千里周遐荒。", "少翁欒大誅相繼，海上何日無方士。", "五柞宮中夢斷時，銅盤玉露胡爲不起死。"]'),
('31b0b768-2864-4f76-bfe7-a201ce377c33','纏頭曲','趙汝鐩','宋','宋诗','song-poetry','','[]','阿蠻妙舞翠袖長，臂韝珠絡带寶裝。',192,'全唐诗/poet.song.186000.json','["阿蠻妙舞翠袖長，臂韝珠絡带寶裝。", "春風按試清元殿，粉白黛綠立兩傍。", "三郎老手打羯鼓，太真纖指彈龍香。", "箜篌野狐拍懷智，觱篥龜年笛寧王。", "中有八姨坐綺席，淡掃蛾眉壓宮粧。", "醉看阿蠻小垂手，飛燕輕盈驚鴻翔。", "八姨指揮三郎聽，頒賚豈惜傾篚箱。", "纏頭一局三百萬，莫遣傍人笑大唐。", "尾聲方斷地衣卷，忽聞鼙鼓喧漁陽。", "播遷纔出望賢路，玉食未進日卓午。", "糲飯胡餠能幾許，不飽皇孫及妃主。", "阿蠻知是何處去，但見豬龍胡旋舞。"]'),
('379749ff-22c0-4a16-af62-0a2d4807a821','飲馬長城窟','趙汝鐩','宋','宋诗','song-poetry','','[]','烏騅馬，紫游韁，戍夫一鞭天一方。',160,'全唐诗/poet.song.186000.json','["烏騅馬，紫游韁，戍夫一鞭天一方。", "揆程想過長城下，思古築役摧人腸。", "白骨如雪浸水窟，骨上猶带秦時血。", "雨打風吹宇宙腥，君渴莫飲救馬渴。", "衣適寒暄飯加餐，省酒戒勿離軍門。", "鴈來不惜數行字，鴈回我亦寄平安。", "自從君出與君別，怕聽砧聲怕見月。", "細思人生能幾何，未卜彼此俱白髮。", "官有好爵與爾靡，萬死一生方得之。", "不如更戍聞早歸，百年鄰里誇齊眉。"]'),
('29e1a026-e3f3-448d-8f34-e3c7d2897217','妾薄命','趙汝鐩','宋','宋诗','song-poetry','','[]','冶容麗質世鮮比，擇對年少風流子。',166,'全唐诗/poet.song.186000.json','["冶容麗質世鮮比，擇對年少風流子。", "並欄觀魚雙戲水，妾心郎心誓如此。", "一朝結束萬里行，東欲到海西到秦。", "醉中慷慨躍馬去，出門十年無信音。", "或傳淫蕩歸不得，或傳已作泉下客。", "郎兮郎兮奈若何，恨淚徹夜孤枕滴。", "君不聞鶑鶑錦字寄西遊，玉環綵絲意綢繆。", "郎心忍向他人笑，下床徒自爲郎羞。", "又不聞盼盼樽前小垂手，燕子樓深情獨厚。", "豈期紅粉遽成灰，怨句空吟三百首。"]'),
('3d077d0d-1550-4a72-b44f-74ae2748fc01','瑶娥曲','趙汝鐩','宋','宋诗','song-poetry','','[]','一二三四月如眉，積累如梳截半規。',128,'全唐诗/poet.song.186000.json','["一二三四月如眉，積累如梳截半規。", "玉斧晝夜修不徹，修成團鏡當空垂。", "十眉有樣列象几，梳裁春冰鏡涵水。", "瑶娥睡起拂菱花，掃黛插鬢雲繞指。", "歛袂亭亭天上妝，環珮隠體璆琳鏘。", "驂鸞跨鶴舞仙譜，子登彈璈飛瓊簧。", "天風颼飂冷到骨，銀河澎浪濺羅襪。", "一輪千古廣寒深，折盡桂花應白髮。"]'),
('c141bbb4-50a1-42c7-bf09-10fe0a06c36c','昭君曲','趙汝鐩','宋','宋诗','song-poetry','','[]','禦戎豈別無經綸，婁敬作俑言和親。',162,'全唐诗/poet.song.186000.json','["禦戎豈別無經綸，婁敬作俑言和親。", "或結或絕患不已，至呼韓邪朝竟寧。", "稽首願得壻漢氏，秭歸有女王昭君。", "臨時失捐畫工賂，蛾眉遠嫁單于庭。", "玉容慘淡落紫塞，粉淚闌干揮黄雲。", "下馬穹廬移步澀，彈絲誰要胡兒聽。", "年年兩軍苦爭戰，殺人如麻盈邊城。", "若藉此行贖萬骨，甘忍吾恥縻一身。", "聞笳常使夢魂驚，倚樓惟恐烽火明。", "狼子野心何可憑，嗚呼狼子野心何可憑。"]'),
('02159cac-0c27-46fd-b050-6f469d5eb103','斷腸曲','趙汝鐩','宋','宋诗','song-poetry','','[]','凭欄日日望歸騶，書來又報瀟湘遊。',144,'全唐诗/poet.song.186000.json','["凭欄日日望歸騶，書來又報瀟湘遊。", "卷書默坐淚自雨，彈向花上花替愁。", "想郎快意楊州鶴，風光何地非行樂。", "妾腸寸斷郎豈知，獨步苔階空聽鵲。", "風濾碧紗夜窗深，弄針燈下無心情。", "蜀羅一段茸五色，看定鴛鴦繡不成。", "妾貌留春春要去，妝鏡孤鸞無力舞。", "轆轤吚啞殘夢驚，曉嘶似是郎馬聲。", "卷簾無人簾再下，遣童水東占打瓦。"]'),
('d736b56d-7e23-4acd-8696-7396b0a430c4','銅雀臺辭','趙汝鐩','宋','宋诗','song-poetry','','[]','屋一百間臺十丈，岧嶢突兀九霄上。',98,'全唐诗/poet.song.186000.json','["屋一百間臺十丈，岧嶢突兀九霄上。", "明月空照八尺床，幾點酸風摇繐帳。", "離宮金鎖掣不開，美人紅粉今成灰。", "蘭麝分恩銷餘馥，銅雀飛去無時回。", "太官朝暮薦酒脯，迷魂尚愛殘歌舞。", "戀戀西陵一抔土，上馬橫槊平日詫英武。"]'),
('94e00f35-064c-42b2-9e23-44d703fadef3','三閣曲','趙汝鐩','宋','宋诗','song-poetry','','[]','叔寶沉迷建鄴宮，厭厭夜飲清晝同。',114,'全唐诗/poet.song.186000.json','["叔寶沉迷建鄴宮，厭厭夜飲清晝同。", "金碧三閣插晴漢，沉檀十里聞香風。", "疊石爲山水爲沼，後庭萬花坼春叢。", "狎客倡酬女學士，污詞媚句爭新工。", "被之弦歌恣酣樂，千娥行列紛青紅。", "將軍忽遇韓擒虎，江神今識清河公。", "憑欄璧月詞未終，誰知携手兩妃遊井中。"]'),
('77fd96ab-ae92-4a3f-ab47-540456bfba82','出處辭','趙汝鐩','宋','宋诗','song-poetry','','[]','太公嚴子陵，皤然兩漁人。',88,'全唐诗/poet.song.186000.json','["太公嚴子陵，皤然兩漁人。", "文王尚西伯，光皇已中興。", "太公所以竟卷餌，子陵所以歸垂綸。", "趨向固異轍，出處同一心。", "當日遭逢儻易地，兩翁亦必隨時而屈伸。", "釣臺高兮渭水清，或隠或顯俱彰千古名。"]'),
('5865371b-8d47-46eb-b149-98a8b8fba924','漢離宮四時詞','趙汝鐩','宋','宋诗','song-poetry','','[]','東風飄花誰共惜，暑雨馥蓮不忺摘。',138,'全唐诗/poet.song.186000.json','["東風飄花誰共惜，暑雨馥蓮不忺摘。", "琱欄倚露月千里，銅鋪鎖寒雪一尺。", "終年漢漏滴四時，屈指三百六十日。", "遠山蹙斷懶塗抹，怕開妝鏡鸞舞隻。", "怨淚闌干落離宮，纖玉彈珠香風濕。", "夢回想像巫山雲，簷鵲似傳天上音。", "便教粉黛近君側，未卜膠漆投君心。", "豈不聞東宮婕妤作歌悲團扇，又不聞長門阿嬌買賦捐黄金。"]'),
('763e54d8-b36c-4058-9f74-b94c0eefac4e','義獸行','趙汝鐩','宋','宋诗','song-poetry','','[]','君不見明皇有象能拜舞，看定祿山瞪目怒。',118,'全唐诗/poet.song.186000.json','["君不見明皇有象能拜舞，看定祿山瞪目怒。", "又不見昭宗有猴能起居，望見全忠奮臂呼。", "兩朝玩物固喪志，異類報國乃仗義。", "天寶大駕蜀道巡，開平初元唐祚傾。", "百僚奉賊身盡竄，宰相畏族神不寧。", "爾象爾猴忿且嗔，其面雖獸心則人。", "當時節士知有幾，壯哉義獸不怕死。"]'),
('6f20568e-2fe2-49fa-84ce-899212418a3d','征婦歎','趙汝鐩','宋','宋诗','song-poetry','','[]','蓮浴雙鴛鴦，梧棲雙鳳凰。',72,'全唐诗/poet.song.186000.json','["蓮浴雙鴛鴦，梧棲雙鳳凰。", "雙舞蝶度牆，雙飛燕歸梁。", "倚欄人顰翠，忍淚心暗傷。", "閉戶羅幃悄，孤燈耿空房。", "欲睡睡未得，獨坐理絲簧。", "彈吹不成調，征夫天一方。"]'),
('e4015611-56ef-40bf-a331-cfe8950faf1e','響卜辭','趙汝鐩','宋','宋诗','song-poetry','','[]','三六乘鸞初嫁君，琴瑟朝暮誓不分。',208,'全唐诗/poet.song.186000.json','["三六乘鸞初嫁君，琴瑟朝暮誓不分。", "酒酣使氣浪自許，片舌儀秦弄風雲。", "東吳西蜀幾千里，鴈來數年無幅紙。", "有便我必寄錦牋，豈應皆沉石頭水。", "酸風一點淚兩行，憑欄瞥過雙鴛鴦。", "霜花迫簾冷蠟焰，雨梧傍枕敲銀床。", "乞靈每日扣巫祝，更向靜處聽響卜。", "人言卯夜驗不差，又言元宵應尤速。", "二說果如神，俱占敢厭頻。", "齋心通我意，側步潜我身。", "或坼翠幌視，或靠綠窗避。", "兩夕行人語，字字還家意。", "羅襪走褪奔繡幃，懽喜無地魂天飛。", "小兒放嬌來牽衣，抱我門前接爺歸。"]'),
('d9af308d-d3f9-4fc8-b1b7-2d9da78bc343','君不見','趙汝鐩','宋','宋诗','song-poetry','','[]','君不見盧生枕上客邯鄲，君不見淳于穴中到槐安。',84,'全唐诗/poet.song.186000.json','["君不見盧生枕上客邯鄲，君不見淳于穴中到槐安。", "出將入相羣兒仕，賜爵錫邑公主貴。", "黄粱未熟已欠伸，清樽尚在遽驚起，人生榮華懽樂亦如此。", "雙轂晝飛夜旋一彈指，胡不看取二人夢中事。"]'),
('0b27864a-dce6-4467-971a-f1c4153592ea','翁媼歎','趙汝鐩','宋','宋诗','song-poetry','','[]','旱曦赫空歲不熟，炊甑飛塵煮薄粥。',162,'全唐诗/poet.song.186000.json','["旱曦赫空歲不熟，炊甑飛塵煮薄粥。", "翁媼饑雷常轉腹，大兒嗷嗷小兒哭。", "愁死未死此何時，縣道賦不遺毫釐。", "科胥督欠烈星火，詬言我已遭榜笞。", "壯丁偷身出走避，病婦抱子訴下淚。", "掉頭不恤爾有無，多寡但照帖中字。", "盤雞豈能供大嚼，杯酒安足直一醉。", "瀝血祈哀容貸納，拍案邀需仍痛詈。", "百請幸聽去須臾，衝夜搥門誰叫呼。", "後胥復持朱書急急符，預借明年一年租。"]'),
('de8ac60b-a0b9-43a4-8235-b3ab7f886425','寄遠曲','趙汝鐩','宋','宋诗','song-poetry','','[]','君馬踏邊塵，繡帷妾一身。',178,'全唐诗/poet.song.186000.json','["君馬踏邊塵，繡帷妾一身。", "仰天無過鴈，俯水無遊鱗。", "酒難獨自酌，蟻樽空浮春。", "食亦不知味，駝峰徒薦珍。", "憶昔送君君已醉，醉言更戍一年事。", "兜鍪北去幾寒暑，兩地肝腸摧萬里。", "別來容貌似舊無，寄去衣裳知到未。", "折柳絲絲紫塞心，對花片片青春淚。", "夜聞琴瑟鼓鄰家，人皆齊眉老年華。", "不忍恨君翻自恨，長吁矯首天之涯。", "幾度虛傳歸信息，愛聽乾鵲怕聽鴉。", "孤枕有時髣髴夢中見，覺來霜角咽梅花。"]'),
('827e79e8-15cf-4660-b621-615e0d710e2c','上馬曲','趙汝鐩','宋','宋诗','song-poetry','','[]','精神如熊氣如虹，夢寐思勒燕然功。',122,'全唐诗/poet.song.186000.json','["精神如熊氣如虹，夢寐思勒燕然功。", "龍泉寶鞘橫三尺，犀甲茸絛擐兩重。", "鳴鏑飛空挾霜遠，認旗貼身颭日紅。", "玉轡繡韉鞲驄馬，眼有紫焰炯雙瞳。", "誓縛單于獻天子，離觴不揮兒女淚。", "笳鼓動地歸來時，金印斗大肘後繫。", "君不見燕頷虎頸班超侯萬里，又不見風聲鶴唳謝玄破肥水。"]'),
('9c0fa00b-c438-4968-aba8-0dbb5d69b8bc','去婦辭','趙汝鐩','宋','宋诗','song-poetry','','[]','入得良人門，自誓終此身。',131,'全唐诗/poet.song.186000.json','["入得良人門，自誓終此身。", "掃室擁箕箒，進盥躬盤巾。", "采桑趨隴首，薦蘋潔澗濱。", "十年盡婦道，惟恐堂前嗔。", "上和下睦本無事，一二小姑恣萋斐。", "浸潤既深貝錦成，不棄不出譖不已。", "良人繾綣涕漣洏，父母之命安敢違。", "舉頭天邊指缺月，暫缺須有團圓時。", "君不聞章臺長條依舊垂，樂昌半鏡還復歸。"]'),
('a5997f00-6d0b-44df-a743-544295118d10','耕織嘆二首  其一','趙汝鐩','宋','宋诗','song-poetry','','[]','春催農工動阡陌，耕犂紛紜牛背血。',96,'全唐诗/poet.song.186000.json','["春催農工動阡陌，耕犂紛紜牛背血。", "種蒔已徧復耘耔，久晴渴雨車聲發。", "往來邏視曉夕忙，香穗垂頭秋登場。", "一年苦辛今幸熟，壯兒健婦爭掃倉。", "官輸私負索交至，勺合不留但糠秕。", "我腹不飽飽他人，終日茅簷愁餓死。"]'),
('8c4ca6d3-5781-45c2-9f32-0e2037a4890c','耕織嘆二首  其二','趙汝鐩','宋','宋诗','song-poetry','','[]','春氣熏陶蠶動紙，採桑女兒鬨如市。',96,'全唐诗/poet.song.186000.json','["春氣熏陶蠶動紙，採桑女兒鬨如市。", "晝飼夜餧時分盤，扃門謝客謹俗忌。", "雪團落架抽繭絲，小姑繰車婦織機。", "全家勤勞各有望，翁媼處分將裁衣。", "官輸私負索交至，尺寸不留但箱篚。", "我身不煖煖他人，終日茅簷愁凍死。"]'),
('e7c09af3-1fab-4b90-972b-720cc42a0901','短歌行','趙汝鐩','宋','宋诗','song-poetry','','[]','赤龍駕輪飛上天，倏東倏西晝夜旋。',108,'全唐诗/poet.song.186000.json','["赤龍駕輪飛上天，倏東倏西晝夜旋。", "流光萬古去不返，少壯翻手成華顛。", "閬風層城羽衣仙，方瞳綠髮耕芝田。", "玉樓貯春春不老，蟠桃一實三千年。", "我欲訪仙弱水隔，住世奈此急景煎，茫然無計相留連。", "打併萬事不放到眼前，右杯左蟹拍浮百斛船。"]'),
('acf721d2-f3ac-4219-bc74-d32ec8f50aca','漁父四時曲 春','趙汝鐩','宋','宋诗','song-poetry','','[]','霽江浮春新水肥，粼粼鴨綠東風微。',96,'全唐诗/poet.song.186000.json','["霽江浮春新水肥，粼粼鴨綠東風微。", "波心上下舴艋滑，釣車香餌卷落暉。", "纖鱗噞喁錦穿柳，半留賣錢半換酒。", "爛醉茅簷紅杏家，折花簪髮把兩手。", "沙岸尋芳青驄嘶，彈絲吹竹挾蛾眉。", "笑指漁父何寂寞，漁父掉頭我自樂。"]'),
('47483663-5157-45f2-8f51-51dfd659acea','漁父四時曲 夏','趙汝鐩','宋','宋诗','song-poetry','','[]','煙溪流碧浸炎空，滌濯袢蒸蒹葭風。',96,'全唐诗/poet.song.186000.json','["煙溪流碧浸炎空，滌濯袢蒸蒹葭風。", "大港小港凉世界，隔堤荷蕩香到篷。", "儂家生長舟一葉，豈識人間半點熱。", "青笠綠蓑山雨來，雨過波平夜撐月。", "水亭避暑冰玉肌，枕設珊瑚簟琉璃。", "笑指漁父何辛苦，漁父掉頭渾不顧。"]'),
('1fe71810-778a-423b-aac8-51466574ae93','漁父四時曲 秋','趙汝鐩','宋','宋诗','song-poetry','','[]','新鴈銜秋訪水涯，分屯洲渚傍蘆花。',96,'全唐诗/poet.song.186000.json','["新鴈銜秋訪水涯，分屯洲渚傍蘆花。", "停橈相約結溪社，來往無嫌同一家。", "酒酣把笛吹村曲，聲曳蘭風入山腹。", "釣竿到手萬事輕，孰是孰非孰榮辱。", "江樓邀月粉黛濃，簧璈嘈雜徹桂宮。", "笑指漁父何冷落，漁父掉頭吾豈錯。"]'),
('553a7d2e-1258-40a9-b504-623dd3ac4f64','漁父四時曲 冬','趙汝鐩','宋','宋诗','song-poetry','','[]','六花坼凍雲模糊，釣鈎空擲寒無魚。',96,'全唐诗/poet.song.186000.json','["六花坼凍雲模糊，釣鈎空擲寒無魚。", "繫舟枯柳歸茅舍，撥火煨薪擁地爐。", "賒鄰一榼醅醱玉，老稚分霑春回谷。", "重來解維放夜筒，橫風打向別港宿。", "溪館對雪歌妓圍，釜出駝峰酒羔兒。", "笑指漁父何憔悴，漁父掉頭但稱醉。"]'),
('e55ac241-47f9-4452-ae60-4bb775349026','仰山行','趙汝鐩','宋','宋诗','song-poetry','','[]','平生幾兩謝公屐，愛山愛水真成癖。',160,'全唐诗/poet.song.186000.json','["平生幾兩謝公屐，愛山愛水真成癖。", "集雲峰在指顧間，年來抗塵乃絕跡。", "西風從臾作意登，佛境未入心境清。", "九秋顥氣接嵐氣，五里松聲答泉聲。", "招提金碧壓深窈，鐘皷四時遞昏曉。", "梵音獨許山鳥聽，禪夢不驚胡蝶遶。", "土腴露飽蔬笋鮮，一粥一飯天上僧。", "伊蒲供罷日卓午，浮空半是烹茶煙。", "四藤欲知閣中味，萬字欲參堂上意。", "請將此事且姑置，坐看山雨濯晚翠。"]'),
('4fd9c050-5664-4374-9745-b363b75203df','東湖歌','趙汝鐩','宋','宋诗','song-poetry','','[]','湖光蕩綠春拍塞，百雉之東纔咫尺。',160,'全唐诗/poet.song.186000.json','["湖光蕩綠春拍塞，百雉之東纔咫尺。", "五步一亭十步榭，軒窗處處臨水闢。", "露濃晝淑花溜紅，煙嫩堤平草連碧。", "俯窺萍罅魚上下，仰聽木杪禽格磔。", "拂拭塵埃讀祖碑，摩挲峰竅憐盧石。", "中年懷抱多感慨，東西跳丸駒過隙。", "山林鐘鼎同一盡，可笑世網甘形役。", "甕邊吏部真得計，右酒左蟹船中拍。", "明朝風雨那可料，且對湖山醉今夕。", "沙鷗許我再尋盟，從此時携杖頭百。"]'),
('ad2889df-670e-4924-90a2-8e4ed1201a0e','禹穴行','趙汝鐩','宋','宋诗','song-poetry','','[]','浙江之東千巖出，參差半天氣葱鬰。',114,'全唐诗/poet.song.186000.json','["浙江之東千巖出，參差半天氣葱鬰。", "禹昔不返南巡車，越人交口說遺跡。", "日往月來三千春，宮有龍瑞洞陽明。", "搜深陟危辨舊穴，訛以傳訛終難尋。", "荒山一片老風雨，徘徊問山山無語。", "寒林朝號萬壑秋，冷煙暮結太古愁。", "誰能爲起馬遷死，指點當時所探何處是。"]'),
('92e2f6dd-0b61-4fdb-9a69-2b57f70baa08','蒙泉行','趙汝鐩','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','二十年前客中都，壁間誰掛蒙泉圖。',160,'全唐诗/poet.song.186000.json','["二十年前客中都，壁間誰掛蒙泉圖。", "天造地設有如此，果若所畫疑蓬壺。", "御風來遊洞庭北，此境突兀眼前出。", "荆門之外天下稀，翻思畫圖纔髣髴。", "山根寒源月一泓，細流循沼曲折分。", "天光倒影寫晴碧，對此洗我瀟灑心。", "雲木枕崖影濕翠，金蓮鋪鏡葩在水。", "流觴自是模蘭亭，山陰今日那得爾。", "向暮深林啼子規，柳花作團貼水飛。", "吟興未盡征馬嘶，他時清夢猶見之。"]'),
('82fd4609-666e-4f96-a559-ade30b62ac07','荆門行','趙汝鐩','宋','宋诗','song-poetry','','[]','去年曾問荆門途，雞鳴狗吠民耕鋤。',280,'全唐诗/poet.song.186000.json','["去年曾問荆門途，雞鳴狗吠民耕鋤。", "摇鞭重來意慘澹，前日井邑今丘墟。", "雲昏雨澀草堆碧，四野荒荒人跡疎。", "深山扶携皆露處，骨肉蕩沒况室廬。", "老農無力倚林卧，少定舉首來向余。", "官人且坐待儂說，未說泗涕先橫裾。", "老夫老豈識兵革，忽見遠近皆狂胡。", "懸崖絕壁魚貫進，飛馬上下爭馳驅。", "吾軍非是無身手，未鼓棄甲先奔趨。", "時平廩帛官不計，戰勝爵賞官不辜。", "進怯鋒鏑退焚掠，虜既難堪堪汝乎。", "歸來未暇正其罪，官有金幣還招呼。", "老夫莫曉軍旅事，但聞敗衄深嗟吁。", "我聽其言爲蹙頞，含悽獨下西山隅。", "金蓮似恨羶風染，蒙泉未洗血水污。", "九秋半破明月夕，照我孤憤行繞壁。", "天子嘗膽方仄席，微臣敢作楚囚泣，秋風一劔樓蘭國。"]'),
('2101195a-1d64-4649-bcb0-4a41888b916c','楚觀歌','趙汝鐩','宋','宋诗','song-poetry','','[]','吾聞楚鄉江山多勝處，今之楚觀尤得江山趣。',204,'全唐诗/poet.song.186000.json','["吾聞楚鄉江山多勝處，今之楚觀尤得江山趣。", "萬象排拶索應酬，丹青閣筆無所措。", "大則湘水小臨蒸，衆流合派銀河傾。", "陶寫秋氣浸明月，夜波爽透百雉城。", "右則鴈峰左石鼓，雙屏競秀蒼龍舞。", "吞吐嵐光飛亂雲，凉風暝送兩崖雨。", "江山之趣於此無不宜，朝暮變化愈出而愈奇。", "最愛鷗鷺甘冷淡，占斷汀渚供娛嬉。", "東塗西抹晚煙翠，漁父歸舟卷鈎餌。", "鼓枻而歌倚半醉，中有滄浪濯纓意。", "杜若一片迷芳洲，凭欄懷古生新愁。", "更上崔嵬千尺湘春樓，縱目乾坤盡見衡嶽秋。"]'),
('8b26e065-6ffa-4e5b-bbb3-1b0eccc12f9a','湘西行','趙汝鐩','宋','宋诗','song-poetry','','[]','吾嘗誦麓山盤紆句，又嘗誦深林玲瓏詩。',262,'全唐诗/poet.song.186000.json','["吾嘗誦麓山盤紆句，又嘗誦深林玲瓏詩。", "前有工部後吏部，拈出千古湘西奇。", "扶藜遊目逐蕭爽，捫蘿陟磴忘嶮巇。", "杉檜摇空蛟虬舞，嶺壑翳霧猿猱悲。", "晨昏兩鐘遞名剎，日月一壇老仙祠。", "摩幹徘徊憐晉柏，剝苔俯仰認唐碑。", "碧虛心照眼已闊，更上萬仞層臺危。", "楚濤左渺連七澤，蠻煙右湧迷九嶷。", "學宮岧嶢壓勝槩，百泉曲折流方池。", "英才涵濡教育樂，風雩慨想莫春時。", "登臨殊未徧幽境，殘陽木末墜紅影。", "松陰夾道倒接䍦，不遣前訶殺風景。", "小留一片瀟湘亭，雙鷺飛來妝秋屏。", "橘垂嫩顆匝洲青，芷紛柔葉飄岸馨。", "冥搜枯腸浪著語，對人欲舉不敢舉。", "拍欄但吟工部吏部兩大篇，水光山色俱欣然。"]'),
('be856529-f310-4444-8145-e222e20e7e45','八景歌  其一','趙汝鐩','宋','宋诗','song-poetry','','[]','嗷嗷哀鳴肅肅羽，魂清意爽愛湘楚。',82,'全唐诗/poet.song.186000.json','["嗷嗷哀鳴肅肅羽，魂清意爽愛湘楚。", "西風作惡陣脚散，斜行千點下煙浦。", "飛力已困日且晡，便欲就宿依寒蘆。", "大者居中圍以奴，丁寧緩急相驚呼。", "嗟此何景兮平沙鴈落，丹青欲盡未易著。"]'),
('c12be56e-c0c3-489a-8589-7927549b1f25','八景歌  其二','趙汝鐩','宋','宋诗','song-poetry','','[]','晚日放晴雨脚收，楚山千里江吞秋。',82,'全唐诗/poet.song.186000.json','["晚日放晴雨脚收，楚山千里江吞秋。", "上水風生荻花渚，漠漠幅蒲天際浮。", "輕雲驟掩目力斷，雲消似過芳洲半。", "危檣逐烏惟恐緩，燕子爭飛先到岸。", "嗟此何景兮遠浦帆歸，丹青欲盡殊堪嗤。"]'),
('063f4678-1ffd-4474-abf7-685a3f18308d','八景歌  其三','趙汝鐩','宋','宋诗','song-poetry','','[]','朝氛吐吞影模糊，嫩日隠見光卷舒。',82,'全唐诗/poet.song.186000.json','["朝氛吐吞影模糊，嫩日隠見光卷舒。", "湘巒滴翠石徑滑，遠近憧憧人趁虛。", "天風作意扶霽色，噓拂昏翳半明滅。", "槿籬髣髴橘林隔，一竿斜插酒旗揭。", "嗟此何景兮山市晴嵐，丹青欲盡良獨難。"]'),
('5d572064-ed7f-454a-94ae-5dc25757ebc6','八景歌  其四','趙汝鐩','宋','宋诗','song-poetry','','[]','雲擁黄昏朔風急，長空杳杳水拍拍。',82,'全唐诗/poet.song.186000.json','["雲擁黄昏朔風急，長空杳杳水拍拍。", "六花舞白徧三湘，失却寒峰翠千尺。", "片瓊屑玉響羣林，蘆叢蕭瑟聲更清。", "凍月開匳俄吐晴，銀宮一色上下明。", "嗟此何景兮江天暮雪，丹青欲盡不可得。"]'),
('c45085de-d1e4-4e95-a81b-355edeefb634','八景歌  其五','趙汝鐩','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','西顥沆碭露華白，河漢浩浩浴素魄。',82,'全唐诗/poet.song.186000.json','["西顥沆碭露華白，河漢浩浩浴素魄。", "平湖萬頃摇銀光，祇留君山一點碧。", "帝子揚靈駕飛龍，鼓瑟來遊水精宮。", "聲徹桂娥亦歛容，葉下北渚嫋嫋風。", "嗟此何景兮洞庭秋月，丹青欲盡那免拙。"]'),
('22ab6b56-2248-4c29-a33f-54911e46347d','八景歌  其六','趙汝鐩','宋','宋诗','song-poetry','','[]','楚天濃雲如墨潑，通宵滂沱翻江闊。',82,'全唐诗/poet.song.186000.json','["楚天濃雲如墨潑，通宵滂沱翻江闊。", "寒聲徧撼蒹葭林，要將秋容洗到骨。", "杜若洲有鴻鴈棲，震凌喧夢時驚疑。", "釣翁醉睡却不知，樁脫纜斷船偷移。", "嗟此何景兮瀟湘夜雨，丹青欲盡浪自苦。"]'),
('5ab85860-c4db-4d75-8a6a-6316631d7432','八景歌  其七','趙汝鐩','宋','宋诗','song-poetry','','[]','西嶺驟暗銷殘暉，芷岸蘭汀堆夕霏。',82,'全唐诗/poet.song.186000.json','["西嶺驟暗銷殘暉，芷岸蘭汀堆夕霏。", "數聲撞空九天半，知有招提隠翠微。", "風助餘音響崖谷，蕭蕭暝港孤舟宿。", "禪關棲鳥爭寒木，歸僧疾步穿山麓。", "嗟此何景兮煙寺晚鐘，丹青欲盡焉能窮。"]'),
('ea5d9b71-0162-475a-adaa-87ee8a2835bf','八景歌  其八','趙汝鐩','宋','宋诗','song-poetry','','[]','積雨初過湘水滿，夕陽蕩金接天遠。',82,'全唐诗/poet.song.186000.json','["積雨初過湘水滿，夕陽蕩金接天遠。", "影掛寒罾江步斜，紅殘茅簷沙巷晚。", "小艇澤畔收釣緡，鼓枻滄浪歌濯纓。", "醉眼西望送沉輪，繫纜籬根穿錦鱗。", "嗟此何景兮漁村落照，丹青欲盡無由妙。"]'),
('1e6be1e1-cc69-434d-bfd6-6c7b4e5bbb06','仙湖歌','趙汝鐩','宋','宋诗','song-poetry','','[]','湖之綠兮如藍，湖之明兮如鏡。',254,'全唐诗/poet.song.186000.json','["湖之綠兮如藍，湖之明兮如鏡。", "藍染晴空晚色鮮，鏡照天宇秋毫浄。", "乾坤兩間共開闢，魚鳥四時自飛泳。", "炎州著脚苦蒸鬰，對此恍入清凉境。", "其東羣木合抱森，觀政觀魚連秀陰。", "濂泉沸甃珠的皪，飲瓢洗我太古心。", "其西冰壺爽到骨，曉波澄秋夜印月。", "藏春園種雜花稠，分得庾梅攙先發。", "其南粉雉霄漢橫，旋補楊柳沿堤青。", "上下天光同一碧，我來拈出營新亭。", "其北千片石洲石，或虬或鳳或劔戟。", "環流軒館瘴霧收，簷影倒漾水底日。", "葛仙昔煉九轉丹，丹成飛上羅浮山。", "海邊亭外春萬里，御風忽挹仙翁袂。", "翁乘飈車擁霓旌，約我十二樓五城。", "翁言羽化世已久，問湖風月依舊否。"]'),
('1e4268a1-66d5-4857-a9c0-26bb4d11d9ea','蒲澗行','趙汝鐩','宋','宋诗','song-poetry','','[]','君不見少君詫安期海上之棗，又不見坡仙詠安期宅邊之蒲。',202,'全唐诗/poet.song.186000.json','["君不見少君詫安期海上之棗，又不見坡仙詠安期宅邊之蒲。", "棗失其種豈復得，蒲生於澗何時無。", "澗流涓涓淺可涉，牽蔓披沙搜九節。", "仙家自欲供仙餌，靈根不容凡齒齧。", "循澗探奇巖石幽，瀑音迎耳鏘琅球。", "陰壑常寒失炎熱，終日自雨鳴春秋。", "振衣策足崔嵬頂，跨歷列缺凌倒景。", "天風海濤撼宇宙，神清骨冷肝膽醒。", "聲傳九霄景泰鐘，更上上方梯晴空。", "兩眼有盡天不盡，滄溟浩與銀河通。", "指顧神山似非遠，弱水誰云隔三萬。", "乘風直到金銀臺，握手安期話蒲澗。"]'),
('0347ab7b-d595-49f3-a28d-58b2cad81be7','續蒲澗行','趙汝鐩','宋','宋诗','song-poetry','','[]','戊戌正月二十五，摇轡東風蒲澗去。',192,'全唐诗/poet.song.186000.json','["戊戌正月二十五，摇轡東風蒲澗去。", "年年今日是時節，飛蓋傾城車塞路。", "野亭山館坐不徧，幙天席地千百處。", "開壺設樏紛酒炙，擘蟹錐蠔間醢脯。", "笑言相續樂甚真，禮文不侈意則古。", "我亦隨衆窮勝覽，先訪安期登梵宇。", "入春少雨多是晴，穹巖寒溜僅一縷。", "白雲千級逼象緯，滄海萬里渺煙霧。", "倚欄方快心目遠，牛羊下山林壑暮。", "小兒隊隊逐歸騶，拍手呼舞趁簫鼓。", "遊人到晚懽未厭，徘徊不忍收樽俎。", "行穿梅嶺還江西，首爲南州詫風土。"]'),
('766b5592-de41-46ac-a8ae-2aaa14244d95','古劍歌','趙汝鐩','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭吞天天無風，月印一鏡星涵空。',222,'全唐诗/poet.song.186000.json','["洞庭吞天天無風，月印一鏡星涵空。", "波心千丈光五色，漁人嘖嘖疑垂虹。", "睨而視之寂不見，舉網下罩追遺蹤。", "須臾雷轟怒濤吼，鼓蕩六合雰溟濛。", "所得非魚亦非龍，炯然三尺貫當中。", "肉銷骨立精氣融，鏗鍧其聲韜其鋒。", "越砥稍稍加磨礲，壯士見之肝膽雄。", "雷煥已死不可起，有誰解識斗間氣。", "人疑龍泉或太阿，萬古凡劍空一洗。", "倚樓西北望邊城，連月亙天烽火明。", "隠憂枕上思請纓，夜半躍鞘床頭鳴。", "夢中見告若有神，吾價豈但直百金，吾勇豈但敵一人。", "知君素有擊楫中流心，誓當助君報國萬里清胡塵。"]'),
('9bd3dfb5-9b90-4ad9-aa78-e6bcb09634c0','瀛洲行','趙汝鐩','宋','宋诗','song-poetry','','[]','神山鼎峙滄海東，瑶池翠水環銀宮。',326,'全唐诗/poet.song.186000.json','["神山鼎峙滄海東，瑶池翠水環銀宮。", "朝霞夕霏自今古，飆車羽輪何憧憧。", "文館岧嶢霄漢立，群賢飛珮翔鵷鴻。", "人間風日總不到，逍遥宛在神山中。", "苕谿閩山兩仙伯，雙槎貫月凌溟濛。", "分光東壁筆摛錦，携手西崑氣垂虹。", "承明厭直江湖去，回首雲霧迷方蓬。", "風萍既散俄復聚，赤帷朱轓巧相逢。", "舊遊共說橫秋下，城隅勝槩髣髴同。", "寓意瀛洲規小築，軒楹突兀浮青紅。", "弱水休論三萬里，玉樓未羨十二重。", "洞門無鎖棠陰晝，太華吹香藕花風。", "夜藜吐耀來太乙，旨酒共飲煩壺公。", "臨汝自昔號仙窟，左有靈谷右峨蜂。", "浮丘老翁跨白鶴，魏壇元君携青童。", "欣聞瓊宙出金柅，往往挽袂來相從。", "祇恐濟世緣未了，一麾一節難久容。", "九天丹鳳銜雙詔，脩門並轡摇冬瓏。", "不但十八學士同步武，風雲廊廟兩兩登夔龍。", "共辦霖雨舟楫功，他年相與騎鯨追喬松。"]'),
('5a4c970b-b61f-4a1d-a7ba-0b47424e86e8','三珍行','趙汝鐩','宋','宋诗','song-poetry','','[]','西清平生雅好奇，夜則忘寐晝忘饑。',288,'全唐诗/poet.song.186000.json','["西清平生雅好奇，夜則忘寐晝忘饑。", "搜今抉古竭心力，常恐世間一物遺。", "雲霧軒窗煙月戶，萬寶彙列牙籤垂。", "循環邏視日千匝，拊摩拂拭心融怡。", "驚寇披猖變倉卒，六丁下取留毫釐。", "收拾售用自不足，尚輟三珍贈我爲。", "六幅之珍老坡字，印可誰氏參寥師。", "怒鵬九萬氣吞吐，驪珠百二光陸離。", "兩軸之珍雲子畫，李杜跨蹇將何之。", "華陰縣裏過門日，浣花溪上尋春時。", "一張之珍太古琴，孤桐斲削嶧陽枝。", "刻名漱玉世少比，較昔響泉彼堪嗤。", "銀鈎鐵畫貴楷正，此則倚醉飛蛟螭。", "寸馬豆人貴纖密，此則縱意隳藩籬。", "金徽玉軫貴音韵，此則得趣絕絃絲。", "天機皆由胸襟出，妙處莫以形迹窺。", "愛茲三珍每自隨，酒酣呼馿任倒騎。", "抱琴委轡烏角欹，琅然高吟夏夜詩。"]'),
('14c17cdc-2946-49ac-b4c2-7b6abdc0363d','泛洞庭','趙汝鐩','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','解維武陵岸，江肥雨新止。',288,'全唐诗/poet.song.186000.json','["解維武陵岸，江肥雨新止。", "兼程趨洞庭，勢疾建瓴比。", "銀光吞上下，莫辨天與水。", "我乃航其間，滉瀁藉一葦。", "吏塵貯兩袖，到此劃湔洗。", "黄昏打頭風，洪波半空起。", "舟子惶束手，喧呼互排詆。", "有篙無處著，有纜無地艤。", "鐵索二百丈，牽貓卧沙底。", "進難退不可，簸弄任所以。", "巨浪聲洪鐘，合力撞舟尾。", "一撞心一折，通夕不知幾。", "刻燭驗天明，狂勢稍披靡。", "卷索急飛櫓，半晝見涯涘。", "危命脫針孔，再生自今始。", "人言岳州程，風便五日耳。", "漂滯費半月，初意所不擬。", "粉堞俄在眼，層樓九霄峙。", "凭欄氣方豁，東望酸徹髓。", "前日我片帆，掀舞怒濤裏。", "羊腸百八盤，行路難如此。", "今知驚浪上，羊腸尚可履。", "在家貧亦好，身安門掃軌。", "鼾鼻喧午窗，風波儘千里。"]'),
('070a53d9-0c3b-4c0d-8108-571aaeabe871','贈閭丘廣文','趙汝鐩','宋','宋诗','song-poetry','','[]','奔走異軌轍，聚散水上萍。',144,'全唐诗/poet.song.186000.json','["奔走異軌轍，聚散水上萍。", "誰知風月夕，同登藕花亭。", "駒隙晝夜駃，塵埃鬢俱星。", "朋舊半埋玉，念此慨頹齡。", "天涯幸合席，相對談飄零。", "昔別君韋布，照眼袍今青。", "羣兒儼成行，誦書如建瓴。", "瞳人紛炯炯，捧斚傾綠醽。", "溪茹芹蓴美，秋核查梨馨。", "開口笑豈易，主人愁罄缾。", "命僕更沽覓，痛飲俱忘形。", "明日又分袂，眠食加丁寧。"]'),
('2a30e908-900d-4d55-bd51-c92fea029eb4','荆渚書懷','趙汝鐩','宋','宋诗','song-poetry','','[]','明鏡明於月，白髮白於雪。',180,'全唐诗/poet.song.186000.json','["明鏡明於月，白髮白於雪。", "月照雪轉添，使我心斷絕。", "連年事行役，曾不須臾歇。", "陟岡脚雙繭，凌湖舟一葉。", "五覿君山面，洪濤漲天闊。", "重倚南樓欄，遠鴈逐雲滅。", "西風落破帽，龍山酬九節。", "摇鞭荆門去，蒙泉弄清潔。", "游觀固不惡，奔走計則拙。", "眠指幾千里，意者遂休轍。", "困翮墮渚宮，因循入覊紲。", "天涯寒苦早，袖穿手龜裂。", "村沽酒力薄，連釂耳方熱。", "矯首飛白雲，杳杳望吳越。", "儒冠信誤身，鑄盡六州鐵。"]'),
('aa8f73e3-769d-4721-a57b-fd40a65b0592','憩農家','趙汝鐩','宋','宋诗','song-poetry','','[]','似陰還似晴，好風弄輕柔。',151,'全唐诗/poet.song.186000.json','["似陰還似晴，好風弄輕柔。", "土膏春犂滑，竹深鳴禽幽。", "農家頗瀟灑，{氵虢}{氵虢}氵清泉流。", "蹇余入茅簷，解带爲小留。", "荆釵三兩婦，競將機杼投。", "吹爐問官人，肯喫村茶不。", "羣兒窗下讀，千字文蒙求。", "余因拊其背，勸汝早休休。", "泓穎纔識面，白盡年少頭。", "耕食而鑿飲，胡不安箕裘。", "迺翁聽我言，急把書卷收。", "遣兒出門去，一人騎一牛。"]'),
('c889a554-9bf9-4321-9f3a-83a52693d820','隠者','趙汝鐩','宋','宋诗','song-poetry','','[]','卓庵遠入深林去，生怕世人知得處。',32,'全唐诗/poet.song.186000.json','["卓庵遠入深林去，生怕世人知得處。", "四邊剩却許多雲，重重塞斷山前路。"]'),
('2876acb2-cb05-4ce0-9e2d-ad53c8aab1f8','蝨','趙汝鐩','宋','宋诗','song-poetry','','[]','蝨形僅如麻粟微，蝨毒過於刀錐慘。',112,'全唐诗/poet.song.186000.json','["蝨形僅如麻粟微，蝨毒過於刀錐慘。", "上循鬢髮貫紺珠，下匿裳衣綴玉糝。", "呼朋引類極猖蹶，摇頭舉足恣餐啖。", "晴窗曉捫屢遷坐，雨床夜搔不安毯。", "急喚童子具湯沐，奔迸出沒似喪膽。", "童子蹙頞代請命，姑責戒勵後不敢。", "念其昔日到明光，曾遊相鬚經御覽。"]'),
('0a93acec-e542-4bee-9efb-7323463f38a6','尋僧不遇','趙汝鐩','宋','宋诗','song-poetry','','[]','捫蘿入石徑，野衲棲其間。',72,'全唐诗/poet.song.186000.json','["捫蘿入石徑，野衲棲其間。", "杖錫知何處，留雲守禪關。", "當戶走饑鼠，隔林巢白鷴。", "候久移晚照，困來漱寒灣。", "翛然非人世，欲去且復還。", "木杪猿一聲，六窗契山山。"]'),
('66c6d20f-659e-4b62-b2aa-99d1f04f7f90','有客','趙汝鐩','宋','宋诗','song-poetry','','[]','青春挽不回，白髮摘不盡。',120,'全唐诗/poet.song.186000.json','["青春挽不回，白髮摘不盡。", "減圍羞敝带，照面怯皎鏡。", "功名知儻來，肯問終南徑。", "榮枯默有數，豈待蓋棺定。", "人世如夢幻，具眼須猛省。", "毋爲塵埃役，而敗山林興。", "亭前富葵花，隔簾烜紅影。", "雨餘老苞困，欲謝若未忍。", "有客適過秋，對此惜芳景。", "從事在青州，呼兒往三請。"]'),
('90fdcf76-1eee-4b9c-8ba3-b07296dcd990','夢回','趙汝鐩','宋','宋诗','song-poetry','','[]','春意已深寒未了，夢回斗帳房櫳悄。',32,'全唐诗/poet.song.187000.json','["春意已深寒未了，夢回斗帳房櫳悄。", "五更五點殘月銷，山鳥一聲先破曉。"]'),
('c383455c-83ae-4ce2-bce9-624c1dd77697','水琴','趙汝鐩','宋','宋诗','song-poetry','','[]','盎缶停涵水一泓，中存雅意超器形。',132,'全唐诗/poet.song.187000.json','["盎缶停涵水一泓，中存雅意超器形。", "欲滴未滴天地寂，須臾宮商若相賡。", "妙趣不勞徽外索，泛聲不自絃上生。", "小點恩怨作兒語，大點九皋聞鶴鳴。", "疎數變化似有節，多是洋洋流水音。", "殘瀝斷續楚天曉，餘響勾引南風薰。", "平生筝笛厭鄭衛，羌借古韵洗古心。", "又不如齁{鼻合}北窗睡，兩耳不聽無虧成。"]'),
('962adcf6-9b20-4777-ab87-5cf81c76fb1c','小水寺','趙汝鐩','宋','宋诗','song-poetry','','[]','披霧入野寺，寒林響西風。',48,'全唐诗/poet.song.187000.json','["披霧入野寺，寒林響西風。", "誰遣僧出迎，山鳥爲我通。", "染衣松露香，照眼巖花紅。", "聊此息塵慮，歸騎毋怱怱。"]'),
('ace05abd-ef5e-4749-a644-c3d613cd68d5','訪山中友','趙汝鐩','宋','宋诗','song-poetry','','[]','披荆踏石訪山友，野鳥驚人閙枯柳。',128,'全唐诗/poet.song.187000.json','["披荆踏石訪山友，野鳥驚人閙枯柳。", "牧童爲我通姓名，一笑相迎鶴髮叟。", "結茅倚巖屋數間，塵埃辟易不用帚。", "竹厨貯書羅四五，土壁黏碑分左右。", "山中新醅未堪壓，携手邀我沽村酒。", "床前尚有著殘棋，忘記四圍關戶牖。", "日斜扶醉同歸來，但見黑白子紛糾。", "獼猴樹上周章走，莫是此曹來動否。"]'),
('bb45c733-09b2-46cc-8abb-7cce6814919f','聽琴','趙汝鐩','宋','宋诗','song-poetry','','[]','午睡誰扣門，隔籬喚童子。',84,'全唐诗/poet.song.187000.json','["午睡誰扣門，隔籬喚童子。", "童子走來報，一二琴道士。", "摘茗烹沙銚，推窗拂石几。", "高山流水音，屢彈不肯止。", "我心本虛淡，無用宮商洗。", "淵明未嘗絃，妙趣豈假此。", "道士頗不樂，拂衣抱琴起。"]'),
('0aa9e9b4-d37a-46e9-b409-c54a3113eb20','談禪','趙汝鐩','宋','宋诗','song-poetry','','[]','禪僧晚相投，貌古似落魄。',84,'全唐诗/poet.song.187000.json','["禪僧晚相投，貌古似落魄。", "說性說虛空，彫心苦摸索。", "千百則公案，信口無一錯。", "有蟬隔窗鳴，與僧恣酬酢。", "僧喝蟬不知，僧怒蟬不覺。", "蟬厭忽飛去，僧語無處著。", "呼兒掩柴扉，請僧自行脚。"]'),
('40d597f0-9818-4419-ba4b-09fee45b8b8d','題王才叔南館','趙汝鐩','宋','宋诗','song-poetry','','[]','南館著隠士，幽爽似僧舍。',72,'全唐诗/poet.song.187000.json','["南館著隠士，幽爽似僧舍。", "島紅野花繁，岸綠垂楊亞。", "人行鳥不驚，客至鶴先迓。", "林深自無暑，月到更宜夜。", "傾樽對賢聖，飛筆追鮑謝。", "興來即散策，無時不得暇。"]'),
('05718367-4904-43b7-a469-6337a2e361da','踏雪','趙汝鐩','宋','宋诗','song-poetry','','[]','玉壺一色天漫漫，亂雪飛春減却寒。',160,'全唐诗/poet.song.187000.json','["玉壺一色天漫漫，亂雪飛春減却寒。", "屑瓊篩瑰塞宇宙，柳絮如拳輥作團。", "却愁花木不禁冷，携筇問訊遍玉欄。", "老柯樛枝幸亡恙，紅苞半吐怯牡丹。", "更憐脩竹壓欲折，扶持敲撼聲珊珊。", "似醉忽醒僵忽立，森然再植青琅玕。", "群兒幻出兩獅子，頃刻堆削了不難。", "手持朱橘炯電眼，并刀巧剪金鈴安。", "老夫童心也自愛，卷簾移坐忍凍看。", "一杯暖寒不可再，饑腸轉雷未朝餐。"]'),
('60815c14-7a9d-4250-8abc-76a80a889a7e','讀離騷','趙汝鐩','宋','宋诗','song-poetry','','[]','琅然醉讀離騷經，一鶴聞之來中庭。',32,'全唐诗/poet.song.187000.json','["琅然醉讀離騷經，一鶴聞之來中庭。", "童子屢麾不肯去，直湊樽前側頂聽。"]'),
('9b2f88b3-03bf-4b93-a2b0-18c7d823a828','倚欄','趙汝鐩','宋','宋诗','song-poetry','','[]','倚欄有恨無人說，暮角吹梅寒聲咽。',32,'全唐诗/poet.song.187000.json','["倚欄有恨無人說，暮角吹梅寒聲咽。", "急風卷雨過鴈驚，吐下蘆花一枝雪。"]'),
('98687ae5-7ef5-4b61-aacb-34fc38e4f2e8','偶成','趙汝鐩','宋','宋诗','song-poetry','','[]','青雲得志士，頤指快所欲。',144,'全唐诗/poet.song.187000.json','["青雲得志士，頤指快所欲。", "萬事付杯酒，粉黛貯金屋。", "嗟我骨相窮，不受富貴逐。", "嗜欲人所同，有時未免俗。", "青奴頗專房，高卧擎老足。", "黄妳最如意，開卷醒困目。", "暖寒命脚婆，凍衾轉暘谷。", "開樽喚湯婦，新醅溫酃淥。", "始得此四人，明珠不計斛。", "呼之即來前，相娛不相觸。", "時人皆笑之，畫餠豈充腹。", "我亦翻自笑，竹窗聽戞玉。"]'),
('67089b7d-00c4-4009-aee3-cdb7f3589bf8','訪隠者不遇','趙汝鐩','宋','宋诗','song-poetry','','[]','兩腋乘西風，送我上高岑。',84,'全唐诗/poet.song.187000.json','["兩腋乘西風，送我上高岑。", "竹根一泉通，石徑萬木森。", "中有隠者居，敗屋莓苔侵。", "山空人不見，雲滿掛壁琴。", "兩鶴出候我，逢迎啄衣衿。", "應酬久頗厭，走避不可尋。", "誰伴山下去，明月升高林。"]'),
('6681d17a-91a8-4397-815f-d2693df9c1db','雪中徐檢法約登城樓不果','趙汝鐩','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','今年一雪恰一月，天工弄巧寒饕餮。',144,'全唐诗/poet.song.187000.json','["今年一雪恰一月，天工弄巧寒饕餮。", "朔風吹碎洞庭浪，細結瑶花遍銀闕。", "倚杖測試三尺强，平陸皓皓失凹凸。", "梅梢模糊裹寒香，鳥影伶俜棲凍葉。", "有客約上城南樓，膏吾車兮俄復輟。", "呼兒反關袁安巷，小窗風味寒於鐵。", "未須金帳斟羊羔，薄酒也能春兩頰。", "三杯五杯亦徑醉，曲肱一枕香雲絕。", "夢裏騎馿過灞橋，記得新詩醒時說。"]'),
('934b4f62-1ae1-4e49-b8fa-3940b11d70d5','送林伯虎除國子監丞赴闕  其一','趙汝鐩','宋','宋诗','song-poetry','','[]','山房高千仞，上與青雲齊。',87,'全唐诗/poet.song.187000.json','["山房高千仞，上與青雲齊。", "日從二仙遊，兩耳湔是非。", "北窗正齁{鼻合}，鋒車扣巖扉。", "猿鶴競作色，山人忘我爲。", "林泉雖云樂，出處蓋有時。", "平生經綸胸，憂國兩鬢絲。", "江天炯少微，安得不振衣。"]'),
('d7c549a5-d238-4096-a65d-d891fd7a14b7','送林伯虎除國子監丞赴闕  其二','趙汝鐩','宋','宋诗','song-poetry','','[]','璣衡占東南，老人方昭回。',84,'全唐诗/poet.song.187000.json','["璣衡占東南，老人方昭回。", "明庭聚耆德，公難卧蒿萊。", "行行出東門，丹心趨玉階。", "雪棹乘興爾，雲岫何心哉。", "了却濟世緣，應念金石臺。", "天街躍馬餘，就訪孤山梅。", "和靖有兩鶴，他日騎歸來。"]'),
('dca63afe-c293-4fb5-8c09-6f91efadf283','送絜齋倉使袁都官歸班','趙汝鐩','宋','宋诗','song-poetry','','[]','六轡按部朝出關，郵鈴插羽夜趣還。',204,'全唐诗/poet.song.187000.json','["六轡按部朝出關，郵鈴插羽夜趣還。", "詔字天飛紫泥濕，一點郎星歸拱北。", "鄉來翻動大壑魚，致君堯舜真須臾。", "金甌未啟請麾去，旋頒漢節登范車。", "先生有道出洙泗，派分象山接洛水。", "振鐸重席闡聖傳，此心之外無二理。", "先生有才輩伊周，胸襟百萬森戈矛。", "新亭肯作楚囚泣，誓楫一念清神州。", "此行豈但蘭再握，講帷欠公熙帝學。", "火城照空沙堤新，堂印押班運籌幄。", "絜齋牆仞世龍門，瓣香夙昔鑽仰心，邑債一了即歸耕。", "但當拭目天上新經綸，日與漁樵擊壤歌太平。"]'),
('2d7b583c-33cf-419e-b6ea-4416bb9bb9a5','飲通幽園','趙汝鐩','宋','宋诗','song-poetry','','[]','典却身上鷫鸘裘，買酒領客尋清遊。',160,'全唐诗/poet.song.187000.json','["典却身上鷫鸘裘，買酒領客尋清遊。", "欲洗胸襟塵萬斛，快上青雲展秋眸。", "晴沙翳天風動地，挈壺卷席移通幽。", "一沼鏡浄清可掬，千竿玉立塵不留。", "拒霜兩岸花爛熳，紅蓼錯雜爭開秋。", "人生適意未易得，癡兒了事何時休。", "陶寫豈必在絲竹，山有鳴禽水游鯈。", "酒酣題蕉競新句，景物辟易困雕搜。", "一梳凉月插空碧，樓頭暮角催歸騶。", "雙桂餘葩尚堪摘，便道肯訪勿翦不。"]'),
('72712624-67cc-4923-82cc-a9edd0cb570b','病中得鄔文伯書','趙汝鐩','宋','宋诗','song-poetry','','[]','北風卷地霰穿屋，光寒照几珠百斛。',128,'全唐诗/poet.song.187000.json','["北風卷地霰穿屋，光寒照几珠百斛。", "兒童呼舞健犢奔，病夫擁爐龜殻縮。", "打門寄書勤故人，五雲濕牖春生谷。", "片辭自可愈頭風，千金指迷况滿幅。", "年來塵埃不堪鏡，白髮一摘動盈掬。", "星出星入難養痾，安得閑邊半分福。", "病中畏酒如畏仇，詩囊亦遣高閣束。", "聞君新工千兔禿，君但寫來爲君讀。"]'),
('a77f7b7a-c04f-4d5f-9b2d-8b9c6bae2dee','送臨川王丞秩滿造朝','趙汝鐩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','我來學製君哦松，數月握手臭味同。',128,'全唐诗/poet.song.187000.json','["我來學製君哦松，數月握手臭味同。", "君今南浦我送客，水萍風雲何怱怱。", "別酒未釂白玉斝，椎鼓催發斜陽紅。", "青霄迫逐不少借，指日便入明光宮。", "祖鞭先著氣射斗，好吐平生經綸胸。", "臨汝詩卷如束筍，殿閣正欠賡薰風。", "自憐鱼遊沸釜中，羨君遇順如飛鴻。", "願寄一語隨君東，問訊西湖南北峰。"]'),
('cf3e11e9-85b5-4699-86f4-f8607eba9f96','馬上口占','趙汝鐩','宋','宋诗','song-poetry','','[]','平林塗煙山擎日，晚征漠漠客愁集。',64,'全唐诗/poet.song.187000.json','["平林塗煙山擎日，晚征漠漠客愁集。", "浮生隙駒忙裏過，虛名塞馬眼前失。", "古來戰場莫回首，一成一敗骨俱朽。", "柳岸人家摇酒帘，不妨小停春風鞭。"]'),
('c74777f2-c107-4fcf-9cdc-411c572d40a3','題下陽懷沈叔忱','趙汝鐩','宋','宋诗','song-poetry','','[]','夜雨曉方歇，薄霧隨征車。',48,'全唐诗/poet.song.187000.json','["夜雨曉方歇，薄霧隨征車。", "喬松二十里，翠微三五家。", "雙燕教羣雛，一牛馱兩鴉。", "故人不可見，回首天之涯。"]'),
('ffa91b45-0a2d-4941-82b8-9a735500ad36','宿康口漁家','趙汝鐩','宋','宋诗','song-poetry','','[]','陰雲議雪風颼颼，黄沙翳暝征人愁。',64,'全唐诗/poet.song.187000.json','["陰雲議雪風颼颼，黄沙翳暝征人愁。", "漁家假宿休疲骨，敗蘆紉壁茅蓋頭。", "行營鼓角聲動地，釣翁不慣皆掩耳。", "刺船火急入葭葦，問訊鷗鷺莫驚起。"]'),
('71cf2394-3d07-46c1-a71e-0f8a6f6f194a','姜子平鄭華父見訪留飲月下','趙汝鐩','宋','宋诗','song-poetry','','[]','敲門者誰子，二豪姜與鄭。',96,'全唐诗/poet.song.187000.json','["敲門者誰子，二豪姜與鄭。", "揚袖入長揖，掀髯略常敬。", "于時月當階，籟聲斷四聽。", "展席交股坐，劇談飛舌競。", "恃俠爭譽己，拈卷索分韵。", "呼兒注老瓦，酒力快辛硬。", "羶葷屏俗饌，梨栗錯村飣。", "杯行無不釂，恐犯詩壇令。"]'),
('4eecb557-28df-4280-8cf6-645a1e4d5c58','適意','趙汝鐩','宋','宋诗','song-poetry','','[]','右傾老瓦盆，左持離騷經。',48,'全唐诗/poet.song.187000.json','["右傾老瓦盆，左持離騷經。", "一杯讀一句，既醉還復醒。", "好月飛入坐，伴飲到天明。", "林下樂如許，鐘鼎鴻毛輕。"]'),
('d56b8779-cf6d-40cd-9067-b5899b0d0a2a','水閣秋夜','趙汝鐩','宋','宋诗','song-poetry','','[]','雲收一點無，秋洗四山浄。',72,'全唐诗/poet.song.187000.json','["雲收一點無，秋洗四山浄。", "野水吞長天，凉月分兩鏡。", "倚湖閣虛窈，緣石竹脩勁。", "孤斟領幽寂，新醪快村硬。", "露冷欺病骨，更闌瞻斗柄。", "欲去未屬饜，倚欄成短詠。"]'),
('8b3f1589-c48b-4201-b4f2-eac3f64c6d9f','十一月四日雪中小飲是月十日冬至','趙汝鐩','宋','宋诗','song-poetry','','[]','書雲猶七日，陰極剛未長。',108,'全唐诗/poet.song.187000.json','["書雲猶七日，陰極剛未長。", "風吹六花開，飛舞隘穹壤。", "一陽方欲來，和氣已摩盪。", "著地寂不聲，入林發餘響。", "與客同擁爐，寒威不到幌。", "洗杓開蟻尊，下筯飫熊掌。", "道舊驚物變，談空湔塵想。", "近詩稍閣筆，對此又技癢。", "踏雪訪梅花，更覺吟興爽。"]'),
('895f4c10-0b0e-4d80-9120-c67704acb79a','遊劉園分韵得峽字','趙汝鐩','宋','宋诗','song-poetry','','[]','園林十畝餘，此邦人推甲。',108,'全唐诗/poet.song.187000.json','["園林十畝餘，此邦人推甲。", "匝谷篔簹浄，循沼芙蓉夾。", "波暖遊鱼樂，機忘飛鷗狎。", "劇談互揮麈，曲欄憑鬭鴨。", "棋仙俱自負，國手未許插。", "酒膽各稱雄，觥船不留呷。", "半酣索分吟，韵嚴苦才乏。", "枯腸搜欲斷，險字終難壓。", "閣筆視諸公，詞源羨流峽。"]'),
('4a01aac6-5079-4d6b-9794-35910cf2936a','晚晴與何戶登水亭簡張丞','趙汝鐩','宋','宋诗','song-poetry','','[]','溪流兩岸秋，日落千山暮。',72,'全唐诗/poet.song.187000.json','["溪流兩岸秋，日落千山暮。", "一亭壓其間，登覽洗萬慮。", "胸襟富丘壑，方領此幽趣。", "擲餌來潜鱗，圍棋驚過鷺。", "酒壺展逸興，漁唱續遠浦。", "安得哦松來，撚髭同覓句。"]'),
('fc2fb0b0-569a-429a-a31f-4c39fca1b591','雪中觀客夜博','趙汝鐩','宋','宋诗','song-poetry','','[]','積雪深一尺，堆瓊迷山扉。',72,'全唐诗/poet.song.187000.json','["積雪深一尺，堆瓊迷山扉。", "豪客夜排闥，挑燈紅爐圍。", "成梟呼五白，轉勝賞四緋。", "舉觴無不釂，寒深酒力微。", "姑置博與酒，劇談木屑霏。", "坐久更寖闌，疎鐘到簾幃。"]'),
('e3ec7c10-8073-4e27-aad7-0f7a8672375e','山吟','趙汝鐩','宋','宋诗','song-poetry','','[]','梯磴捫絕壁，題詩紀幽臨。',72,'全唐诗/poet.song.187000.json','["梯磴捫絕壁，題詩紀幽臨。", "呵凍象管滑，墮崖千尺深。", "羣猿皆驚笑，看我攀蘿尋。", "石罅忽搜得，大書足前吟。", "誦詠猿側耳，頷頭似知音。", "吟罷下山去，猿亦歸他林。"]'),
('4e66bd31-a8e7-4bd1-8a73-342798594eee','金山','趙汝鐩','宋','宋诗','song-poetry','','[]','自古稱浮玉，更名爲得金。',48,'全唐诗/poet.song.187000.json','["自古稱浮玉，更名爲得金。", "一山藏寺腹，雙塔立江心。", "淮浙中流斷，風煙四岸侵。", "夢回禪榻悄，月午聽龍吟。"]'),
('c05fd309-2a3b-4485-aa8d-c478ccde7ba9','秋夕','趙汝鐩','宋','宋诗','song-poetry','','[]','秋風動梧井，無頓許多凉。',48,'全唐诗/poet.song.187000.json','["秋風動梧井，無頓許多凉。", "夜靜灘喧枕，窗開月到牀。", "道心便冷淡，世事莫思量。", "只被澆花累，朝朝却用忙。"]'),
('ff525467-5d22-4a49-8dc9-4821acbd468b','劉子愿山居','趙汝鐩','宋','宋诗','song-poetry','','[]','般向山邊住，蕭然茅數椽。',48,'全唐诗/poet.song.187000.json','["般向山邊住，蕭然茅數椽。", "平塘印星斗，深谷剩風煙。", "老不離書卷，貧誰乞酒錢。", "莫言無管待，頻取好茶煎。"]'),
('563bc73c-7c4b-4dcb-b869-dedd99ebdc8a','泊舟','趙汝鐩','宋','宋诗','song-poetry','','[]','前頭無泊處，且住荻花林。',48,'全唐诗/poet.song.187000.json','["前頭無泊處，且住荻花林。", "水沸知灘淺，煙蜂花在瓶。", "呼童治茶具，有客扣柴扃。", "共說山林話，休嗟兩鬢星。"]'),
('ffc32ed6-fa0f-45d8-a4bb-2104de7d6dad','送仲久之京口','趙汝鐩','宋','宋诗','song-poetry','','[]','纔歸又東去，且道幾時還。',48,'全唐诗/poet.song.187000.json','["纔歸又東去，且道幾時還。", "算路亦差遠，緣君不耐閑。", "江城登鐵甕，煙寺認金山。", "我昔經行地，詩牌掛壁間。"]'),
('a8752925-4d48-42b5-b566-84881e9d9b15','空師欲遊嶽往訪山寺','趙汝鐩','宋','宋诗','song-poetry','','[]','聞師遊嶽去，打急訪高岑。',48,'全唐诗/poet.song.187000.json','["聞師遊嶽去，打急訪高岑。", "躡屐若來晚，挑包不可尋。", "山寒梅意悄，林茂鳥聲深。", "行住無非道，何須枉費心。"]'),
('ddc1fb46-48ab-4842-b30b-f53d1dd510fd','送季逢過湘中','趙汝鐩','宋','宋诗','song-poetry','','[]','虀鹽三十載，刻苦戰文場。',48,'全唐诗/poet.song.187000.json','["虀鹽三十載，刻苦戰文場。", "燈火簡編夜，江湖髭鬢霜。", "鴈聲隨掛席，秋色欠遊湘。", "歸日無他物，惟詩滿古囊。"]'),
('344b7918-52b2-466f-bc50-bf9c753b996b','酬曹戶','趙汝鐩','宋','宋诗','song-poetry','','[]','奔走塵埃久，還山每嘆遲。',48,'全唐诗/poet.song.187000.json','["奔走塵埃久，還山每嘆遲。", "歲華驚鴈到，心事獨鷗知。", "夜對樽前月，晝尋花下棋。", "閑中滋味好，但欠子論詩。"]'),
('bc41c77b-86fa-4a6d-860c-5c85ebde6053','泊盧家步','趙汝鐩','宋','宋诗','song-poetry','','[]','泊舟葭葦岸，風喚夜凉生。',48,'全唐诗/poet.song.187000.json','["泊舟葭葦岸，風喚夜凉生。", "天遠星疑墜，秋清月倍明。", "傾杯浮蟻匝，把劍古蛟鳴。", "甚矣吾衰矣，功名念已輕。"]'),
('13f80b03-13df-46b8-b292-c87cfa22b6bf','同崔糾訪陳道士','趙汝鐩','宋','宋诗','song-poetry','','[]','尋幽過橋去，松徑入琳宮。',48,'全唐诗/poet.song.187000.json','["尋幽過橋去，松徑入琳宮。", "竹擺風簷綠，榴殘雨院紅。", "黏碑多古籀，插架獨參同。", "道士掀髯笑，詩聯石鼎工。"]'),
('34d74705-b72b-43a6-a6e2-84b21cc4024a','秋意','趙汝鐩','宋','宋诗','song-poetry','','[]','今年秋意早，夜傍井梧生。',48,'全唐诗/poet.song.187000.json','["今年秋意早，夜傍井梧生。", "怪得雨聲急，洗教山骨清。", "倚欄看葉舞，尋砌聽蛩鳴。", "舉目無非爽，吟詩易得精。"]'),
('dee0261c-8b5a-4b90-8627-2e5585592262','下程','趙汝鐩','宋','宋诗','song-poetry','','[]','下程疑頗早，店主勸予休。',48,'全唐诗/poet.song.187000.json','["下程疑頗早，店主勸予休。", "今晚莫貪路，明朝便到州。", "疎籬編馬眼，新笋護貓頭。", "六七歲童子，一人隨數牛。"]'),
('d6a62500-9460-4bbd-ba41-3b280926c243','訪上官道人庵','趙汝鐩','宋','宋诗','song-poetry','','[]','三十年居此，何嘗識酒葷。',48,'全唐诗/poet.song.187000.json','["三十年居此，何嘗識酒葷。", "柴扉人少到，草徑鹿同羣。", "雨足添新瀑，山深有剩雲。", "水瓢丹竈外，閑事不曾聞。"]'),
('4d5b8b35-762c-472a-856c-e43c6a31e25c','訪王廣文','趙汝鐩','宋','宋诗','song-poetry','','[]','未是閑時節，君言百念灰。',48,'全唐诗/poet.song.187000.json','["未是閑時節，君言百念灰。", "棲身庵竹石，適意杖莓苔。", "人老無由少，春歸却解來。", "呼兒烹苦笋，席地共銜杯。"]'),
('9d7d58c7-07be-4e22-94b8-5f2eaf2e2307','野望','趙汝鐩','宋','宋诗','song-poetry','','[]','一天秋色遠，千里病眸寬。',48,'全唐诗/poet.song.187000.json','["一天秋色遠，千里病眸寬。", "野曠牛羊小，樓高風露寒。", "掃愁嫌酒薄，少事欲心安。", "溪友門前過，留魚薦晚餐。"]'),
('d275b572-5896-43c6-ac9c-b04e3f02f10a','到農家','趙汝鐩','宋','宋诗','song-poetry','','[]','難得官人到，茅簷且駐車。',48,'全唐诗/poet.song.187000.json','["難得官人到，茅簷且駐車。", "自携鋤掘笋，更取網求魚。", "一媼來斟酒，諸童競挽裾。", "須臾對吾泣，科役苦追胥。"]'),
('2e9fba54-4461-42c8-9e38-f2e5623f9ad4','招賢渡溪閣晚望','趙汝鐩','宋','宋诗','song-poetry','','[]','溪流清到底，十頃浸秋光。',48,'全唐诗/poet.song.187000.json','["溪流清到底，十頃浸秋光。", "煙重山加色，風狂鴈失行。", "塵埃雙老鬢，天地幾斜陽。", "何處一聲笛，征人暗斷腸。"]'),
('f3df3d9d-360c-4671-838c-f2b8c0e1ee8d','琳宇','趙汝鐩','宋','宋诗','song-poetry','','[]','琳宇棲巖谷，翛然一徑深。',48,'全唐诗/poet.song.187000.json','["琳宇棲巖谷，翛然一徑深。", "風篁竿戛玉，霜橘顆垂金。", "是院皆扃戶，無人但聽琴。", "遶廊行數匝，聊以洗塵心。"]'),
('7bba566c-005b-46de-9ee4-ba0b5390ed12','維舟','趙汝鐩','宋','宋诗','song-poetry','','[]','望見人家了，猶須轉一坳。',48,'全唐诗/poet.song.187000.json','["望見人家了，猶須轉一坳。", "寺從灘背出，船向柳邊捎。", "問酒尋溪館，呼兒解臘包。", "三杯亦徑醉，世事且權拋。"]'),
('b578f55f-eecf-43a2-a506-58dd625338cb','贈隠居','趙汝鐩','宋','宋诗','song-poetry','','[]','遶屋垂垂柳，當軒小小江。',48,'全唐诗/poet.song.187000.json','["遶屋垂垂柳，當軒小小江。", "買魚尋晚釣，浮蟻倒春缸。", "山近雲侵坐，月來梅印窗。", "隠居誰似子，不羨鹿門龐。"]'),
('0b5540a5-cd23-45ab-94da-a11d77c876b7','弋陽道中','趙汝鐩','宋','宋诗','song-poetry','','[]','千里嘆行役，今朝方半途。',48,'全唐诗/poet.song.187000.json','["千里嘆行役，今朝方半途。", "橘肥霜後顆，松落雨中鬚。", "店嫗當壚問，官人要酒無。", "忻逢掃愁帚，沽了又還沽。"]'),
('d6c73448-2aa9-49db-a557-95f3722f35d8','倚樓','趙汝鐩','宋','宋诗','song-poetry','','[]','蒹葭秋色晚，百尺倚江樓。',48,'全唐诗/poet.song.187000.json','["蒹葭秋色晚，百尺倚江樓。", "日暗煙藏寺，風高浪拍舟。", "歸雲投遠嶺，饑鴈叫滄洲。", "心事非年少，塵埃白盡頭。"]'),
('bc4fa6ea-28dd-4785-9da6-7a750c4231f9','舟中','趙汝鐩','宋','宋诗','song-poetry','','[]','繫纜停征棹，斜陽古渡頭。',48,'全唐诗/poet.song.187000.json','["繫纜停征棹，斜陽古渡頭。", "風霜先遠客，天地獨扁舟。", "水鳥衝開浪，汀鴻占斷秋。", "在家貧亦好，何用出林丘。"]'),
('3e2e7976-5b88-4157-a82d-4b51758b8ef3','夏日普信寺江閣','趙汝鐩','宋','宋诗','song-poetry','','[]','到此全無暑，虛欄千里風。',48,'全唐诗/poet.song.187000.json','["到此全無暑，虛欄千里風。", "看飛雲度水，聽落石鳴空。", "日月忙烏兔，春秋遞燕鴻。", "一生塵裏過，煙艇羨漁翁。"]'),
('b2d98c87-7ccd-488e-8629-eae6ac3e84db','過寶雲寺訪密師','趙汝鐩','宋','宋诗','song-poetry','','[]','寺纔三二里，曳杖且徐行。',48,'全唐诗/poet.song.187000.json','["寺纔三二里，曳杖且徐行。", "晴塔松梢見，風鐘嶺半鳴。", "樵夫分道過，僧子就房迎。", "竹有千竿立，塵無一點生。"]'),
('d7bd2531-07c0-4b53-ba99-608c0f81a355','送翼之過天台','趙汝鐩','宋','宋诗','song-poetry','','[]','天台山水窟，人道是仙家。',48,'全唐诗/poet.song.187000.json','["天台山水窟，人道是仙家。", "白鶴掛寒溜，赤城飛暮霞。", "獨携筇杖過，莫畏石橋斜。", "牢記經行處，歸來向我誇。"]'),
('3ca9dc44-1e4b-4c79-bf6b-548c415813d4','晚泊','趙汝鐩','宋','宋诗','song-poetry','','[]','篙師言已晚，豈可更貪程。',48,'全唐诗/poet.song.187000.json','["篙師言已晚，豈可更貪程。", "風起且須泊，灘多未易撐。", "星河明夜色，葭葦撼秋聲。", "回首人千里，通宵夢不成。"]'),
('07f9daa3-b653-47ed-83c5-a0b14f0a3437','遣意','趙汝鐩','宋','宋诗','song-poetry','','[]','要靜靜不得，風吹竹打簷。',48,'全唐诗/poet.song.187000.json','["要靜靜不得，風吹竹打簷。", "欄摧呼匠葺，碑脫遣兒黏。", "夜短睡常欠，天陰病轉添。", "扶衰歸密室，更下面前簾。"]'),
('d3c392ee-aa08-432b-b91e-17777dd156f8','信步','趙汝鐩','宋','宋诗','song-poetry','','[]','午窗方睡起，信步過東畦。',48,'全唐诗/poet.song.187000.json','["午窗方睡起，信步過東畦。", "穴徙蟻知雨，巢穿燕補泥。", "路坍連草沒，果重壓枝低。", "村婦抱兒子，籠邊教喚雞。"]'),
('cedc22fb-ee8c-4e69-a424-dd5bed8d4974','安仁道中','趙汝鐩','宋','宋诗','song-poetry','','[]','半月離鄉井，家音杳不聞。',48,'全唐诗/poet.song.187000.json','["半月離鄉井，家音杳不聞。", "路危多半缺，橋朽忽中分。", "秋盡風搜葉，日沉巖宿雲。", "荒村店雖陋，店主頗殷勤。"]'),
('20cbefec-6f0b-4329-8c52-0dc56fa7b21d','送彥東還湘','趙汝鐩','宋','宋诗','song-poetry','','[]','湖南多爽處，羨子片帆還。',48,'全唐诗/poet.song.187000.json','["湖南多爽處，羨子片帆還。", "秋影清涵水，煙痕淡著山。", "蘭風香楚佩，竹淚冷湘斑。", "見說誅茅地，江頭只數間。"]'),
('20064ea1-9ad1-404f-9592-b0bdde097b1d','宿方家店','趙汝鐩','宋','宋诗','song-poetry','','[]','昏暮方投宿，敢嫌茅屋低。',48,'全唐诗/poet.song.187000.json','["昏暮方投宿，敢嫌茅屋低。", "池清月易入，林密鳥爭棲。", "買酒春篘甕，求蔬夜摘畦。", "路長莫貪睡，囑僕早聽雞。"]'),
('765b5611-50f5-443a-ba4a-e437bc29acca','贈悟上人','趙汝鐩','宋','宋诗','song-poetry','','[]','怪來趨向別，乃是拙庵孫。',48,'全唐诗/poet.song.187000.json','["怪來趨向別，乃是拙庵孫。", "秋色添禪寂，松聲奪俗喧。", "路行須避蟻，飯剩或呼猿。", "單鉢隨緣住，尋常懶出門。"]'),
('8425aac4-e06c-488d-8fdc-af10c97a73bf','秋居','趙汝鐩','宋','宋诗','song-poetry','','[]','入得秋來爽，何煩宋玉悲。',48,'全唐诗/poet.song.187000.json','["入得秋來爽，何煩宋玉悲。", "推窗對脩竹，開卷課諸兒。", "世事放輕著，人生無足時。", "年多自當老，不用染吟髭。"]'),
('6415c075-b028-45c2-9de5-2441f49a1bb0','暮行江上','趙汝鐩','宋','宋诗','song-poetry','','[]','江天詩眼闊，沙岸暮扶藜。',48,'全唐诗/poet.song.187000.json','["江天詩眼闊，沙岸暮扶藜。", "風怒來帆卸，林昏宿鳥迷。", "問魚前港有，沽酒小童携。", "夜客留同飲，添杯翦韭畦。"]'),
('a8796f26-af87-4fb0-9de1-d602aee5607d','贈慈上人','趙汝鐩','宋','宋诗','song-poetry','','[]','踏遍叢林後，歸來隠石崖。',48,'全唐诗/poet.song.187000.json','["踏遍叢林後，歸來隠石崖。", "任梅斜到牖，聽竹長侵街。", "掛壁塵堆笠，穿山雲惹鞋。", "真機須要悟，餘事是持齋。"]'),
('9424dd26-95e7-4660-a0d4-6ec82e834edd','送奇仲過霅川','趙汝鐩','宋','宋诗','song-poetry','','[]','少年湖海氣，近又負詩名。',48,'全唐诗/poet.song.187000.json','["少年湖海氣，近又負詩名。", "今忽擔簦去，誰非倒屣迎。", "雨茶烹顧渚，春酒醉烏程。", "有句茅亭著，蘋風洲上生。"]'),
('669b83bf-eb84-4698-bcd1-1f8421738ae8','登法雲寺','趙汝鐩','宋','宋诗','song-poetry','','[]','雲林擁深寂，山寺倚崔嵬。',48,'全唐诗/poet.song.187000.json','["雲林擁深寂，山寺倚崔嵬。", "童子請先坐，師僧恐便回。", "庭黄霜到橘，階綠雨滋苔。", "掛樹猿相玩，呼之却不來。"]'),
('b33aecf9-898f-4e6c-9fad-f2409d5fb4eb','春郊','趙汝鐩','宋','宋诗','song-poetry','','[]','數點綠楊風，春光是處同。',48,'全唐诗/poet.song.187000.json','["數點綠楊風，春光是處同。", "蜂喧搜蘂瘠，鳥閙聒山聾。", "聯句逢詩友，尋僧問牧童。", "家家辦農具，準擬試新工。"]'),
('bf106d75-b0cd-4e32-b95a-d7ca5f13271c','宿溪館','趙汝鐩','宋','宋诗','song-poetry','','[]','投宿溪頭館，途長主僕饑。',48,'全唐诗/poet.song.187000.json','["投宿溪頭館，途長主僕饑。", "濕薪難便著，惡米更須篩。", "風細帆來穩，山高月上遲。", "客懷正悽惻，漁笛蓼洲吹。"]'),
('d975b8cf-f147-4558-a76d-b6db5d919fd7','弦歌堂對雨','趙汝鐩','宋','宋诗','song-poetry','','[]','絕交詩酒客，撲面簿書塵。',48,'全唐诗/poet.song.187000.json','["絕交詩酒客，撲面簿書塵。", "汩沒朝連夜，怱忙雨過春。", "民寬殘稅欠，身受上官嗔。", "了却三年債，歸耕秀水濱。"]'),
('332b10f8-1d1b-4a6e-8df5-ae21ef03b38e','留客','趙汝鐩','宋','宋诗','song-poetry','','[]','闊疎方在念，飛蓋忽相過。',48,'全唐诗/poet.song.187000.json','["闊疎方在念，飛蓋忽相過。", "酒缺鄰堪覓，詩成子自哦。", "添羹挑野菜，包鮓就池荷。", "莫屢辭歸去，餘樽亦不多。"]'),
('f88e67fa-2f64-4f8b-938f-a258146c3878','送胡判官赴官永嘉','趙汝鐩','宋','宋诗','song-poetry','','[]','君赴蓮池戍，離愁正值秋。',48,'全唐诗/poet.song.187000.json','["君赴蓮池戍，離愁正值秋。", "持觴送南浦，鳴櫓下東甌。", "才俊推烏幕，風流訪謝樓。", "欲窮奇絕處，須上鴈山頭。"]'),
('44cd0a97-3f9c-4e70-ae6b-cfb302766eb1','醵飲劉園','趙汝鐩','宋','宋诗','song-poetry','','[]','隨意携盤饌，毋煩事禮文。',48,'全唐诗/poet.song.187000.json','["隨意携盤饌，毋煩事禮文。", "燕飛衝幕過，鶑語隔牆聞。", "興自樽前發，韵從花下分。", "詩成似供課，醉墨競紛紜。"]'),
('61f15ab2-bce5-4610-9986-50b5bbedfe4f','遣愁','趙汝鐩','宋','宋诗','song-poetry','','[]','愁來無可奈，散策小橋東。',48,'全唐诗/poet.song.187000.json','["愁來無可奈，散策小橋東。", "影轉松隨日，香殘花怯風。", "煙霞詩興裏，天地酒杯中。", "本自江湖客，生涯付釣篷。"]'),
('44c78fc7-4db5-4583-a235-072a896fdedd','次莊過荆渚以詩寄之','趙汝鐩','宋','宋诗','song-poetry','','[]','澤國遥千里，雲帆隔兩州。',48,'全唐诗/poet.song.187000.json','["澤國遥千里，雲帆隔兩州。", "醉行沙市月，吟破渚宮秋。", "魚嘆馮驩鋏，貂殘季子裘。", "人傳君入蜀，無事早歸休。"]'),
('a2b7253c-cad4-4b0d-adbc-023e0e3d5590','暑酌','趙汝鐩','宋','宋诗','song-poetry','','[]','天高殊未雨，暑盛絕無風。',48,'全唐诗/poet.song.187000.json','["天高殊未雨，暑盛絕無風。", "將酒渠心浸，有泉林下通。", "擘蓮房拍塞，雪藕孔玲瓏。", "量淺難禁醉，扶歸兩小童。"]'),
('adb496a7-4f59-4608-9208-f41f17eeb40b','劉簿約遊廖園','趙汝鐩','宋','宋诗','song-poetry','','[]','名園新整頓，樽酒約追隨。',48,'全唐诗/poet.song.187000.json','["名園新整頓，樽酒約追隨。", "春晚花飛少，牆高蝶度遲。", "注湯童煖酒，拍案客爭棋。", "寂寞鞦韆索，無人盡日垂。"]'),
('419b543a-8fdd-44b1-8006-68a6ced88098','秋夜懷歸','趙汝鐩','宋','宋诗','song-poetry','','[]','鄉里千山月，塵埃兩鬢星。',48,'全唐诗/poet.song.187000.json','["鄉里千山月，塵埃兩鬢星。", "秋聲雖是爽，客耳不堪聽。", "多淚風前燭，孤明竹外螢。", "吟蛩更亡頼，終夜幾曾停。"]'),
('d5b2a6da-0bf2-466f-891f-438d58414dd3','山莊','趙汝鐩','宋','宋诗','song-poetry','','[]','門掩斜陽岸，溪橫獨木橋。',48,'全唐诗/poet.song.187000.json','["門掩斜陽岸，溪橫獨木橋。", "山禽弄春舌，堤柳舞風條。", "世事雪雙鬢，生涯水一瓢。", "似聞鄰釀熟，自往不須招。"]'),
('8883d6ce-7b78-40f8-8e4e-3cbdd4c1d51a','避暑','趙汝鐩','宋','宋诗','song-poetry','','[]','炎赫無逃處，如何得雨來。',48,'全唐诗/poet.song.187000.json','["炎赫無逃處，如何得雨來。", "雲生應有望，風捲又還開。", "携簟尋池閣，傾醪注晚杯。", "堆盤粲紅顆，味不減棱梅。"]'),
('47fc6cde-f7ac-49b8-8af3-d410398e993c','冬日友人見過','趙汝鐩','宋','宋诗','song-poetry','','[]','荆扉終日閉，難得故人來。',48,'全唐诗/poet.song.187000.json','["荆扉終日閉，難得故人來。", "欲暖寒須酒，相携手問梅。", "艱危驚鬢雪，勳業嘆心灰。", "子負江湖氣，誰憐當世才。"]'),
('dbabb255-f569-407d-981f-9ef803b5d81e','秋日同王顯父趙子野何莊叟泛湖趙紫芝繼至分韵得秋字','趙汝鐩','宋','宋诗','song-poetry','','[]','雨餘湖更爽，載酒共清遊。',48,'全唐诗/poet.song.187000.json','["雨餘湖更爽，載酒共清遊。", "天浄倒涵水，峰高爭獻秋。", "風煙入吟筆，簫鼓自鄰舟。", "隄上詩人過，相邀便肯留。"]'),
('10f4a4f3-b63d-40fb-ab29-e4d848d84535','寄圓老聞欲移住他院','趙汝鐩','宋','宋诗','song-poetry','','[]','妄動生於念，禪床坐不牢。',48,'全唐诗/poet.song.187000.json','["妄動生於念，禪床坐不牢。", "舊窠元自好，新剎有何高。", "去住身如寄，奔馳足謾勞。", "挑包聞已决，應笑我忉忉。"]'),
('9a861aa1-21e0-439f-a262-4a135d0f1e88','鄔文伯歸自邵陽','趙汝鐩','宋','宋诗','song-poetry','','[]','賓主西遊久，賡詩日日傳。',48,'全唐诗/poet.song.187000.json','["賓主西遊久，賡詩日日傳。", "交情誰似此，歸興忽翩然。", "楚岸猿吟樹，湘江月載船。", "我窮君更甚，相助愧無錢。"]'),
('325da1be-9a90-4bf0-9423-97e734738f89','臨川縣治古桂兩大株與葉潜仲鄔文伯飲花下','趙汝鐩','宋','宋诗','song-poetry','','[]','雙桂相傳久，百年殊未衰。',48,'全唐诗/poet.song.187000.json','["雙桂相傳久，百年殊未衰。", "樹聯鋪葉密，根老著花遲。", "葩墜黏詩筆，香濃透酒巵。", "月中但孤影，安得兩交枝。"]'),
('0abc9eaa-1cbd-49ef-96ac-e797395464f2','宿古寺','趙汝鐩','宋','宋诗','song-poetry','','[]','黄昏投寺宿，古屋瞰荒江。',48,'全唐诗/poet.song.187000.json','["黄昏投寺宿，古屋瞰荒江。", "村酒沽春甕，山房耿夜釭。", "灘高聲撼枕，月落影收窗。", "僧老人皆玩，樓鐘曉未撞。"]'),
('8caca218-19e5-487c-bfa1-fe6880026059','舟中','趙汝鐩','宋','宋诗','song-poetry','','[]','離家俄十日，千里獨衰翁。',48,'全唐诗/poet.song.187000.json','["離家俄十日，千里獨衰翁。", "蓬響過雲雨，帆開逆水風。", "新沙增岸脚，小港隠蘆叢。", "客思難消遣，黄昏月一弓。"]'),
('30a9be62-54c5-475a-a8f4-913490e37478','雷潭寺','趙汝鐩','宋','宋诗','song-poetry','','[]','憶昔登臨日，今經二十年。',48,'全唐诗/poet.song.187000.json','["憶昔登臨日，今經二十年。", "崢嶸新棟宇，黼黻舊山川。", "魚響潭翻浪，鳥飛風送船。", "穴空龍已去，鱗爪跡依然。"]'),
('afc859c7-2b6e-4bfa-90ec-a7e8387efc2a','送宗上人歸閩','趙汝鐩','宋','宋诗','song-poetry','','[]','頂笠遍參請，平生志甚勤。',48,'全唐诗/poet.song.187000.json','["頂笠遍參請，平生志甚勤。", "耳方離嶽瀑，眼已接閩雲。", "宿嶺星辰近，渡溪煙霧分。", "勸師早休歇，禪不在多聞。"]'),
('6a9c6124-d0d0-4d4b-ac2c-b3d30d41d206','送曹深叟之越','趙汝鐩','宋','宋诗','song-poetry','','[]','幾時重握手，未可便輕離。',48,'全唐诗/poet.song.187000.json','["幾時重握手，未可便輕離。", "路指千巖去，程寬一月期。", "捫蘿窺禹穴，剝蘚讀曹碑。", "必自蘭亭過，方當春暮時。"]'),
('aaddd050-4983-407d-8098-237fefba4376','訪子益','趙汝鐩','宋','宋诗','song-poetry','','[]','揀得溪山住，三間草屋低。',48,'全唐诗/poet.song.187000.json','["揀得溪山住，三間草屋低。", "坐貧憂酒債，廢事悔棋迷。", "壁壞何時補，詩成無處題。", "留余余戒飲，白飯薦黄雞。"]'),
('7eb66c3e-f561-42b2-ad61-b50a8f3189c3','拍欄','趙汝鐩','宋','宋诗','song-poetry','','[]','偶把欄干拍，沙鷗水上驚。',48,'全唐诗/poet.song.187000.json','["偶把欄干拍，沙鷗水上驚。", "晚紅殘照在，秋碧遠山橫。", "盡被浮名役，皆從妄念生。", "不如歸去好，杖屨老柴荆。"]'),
('dc734f48-cdc4-412a-acc7-3c667e4d4339','東村','趙汝鐩','宋','宋诗','song-poetry','','[]','晴久全無雨，溪乾半是沙。',48,'全唐诗/poet.song.187000.json','["晴久全無雨，溪乾半是沙。", "風橫分鴈陣，日轉趣蜂衙。", "地僻草埋徑，籬摧菊卧花。", "橋西一林竹，瀟灑兩三家。"]'),
('4f2f8f4d-0427-4fd8-a760-1545ad1f55c0','醴陵道中','趙汝鐩','宋','宋诗','song-poetry','','[]','入得湖南界，皆嫌堠子長。',48,'全唐诗/poet.song.187000.json','["入得湖南界，皆嫌堠子長。", "煙巖松葉暗，風陌稻花香。", "橋斷人迂路，車鳴水卷塘。", "宿程雖不遠，木杪已斜陽。"]'),
('21a5da97-379c-483a-a319-6bee0d71435d','子開移居郊外','趙汝鐩','宋','宋诗','song-poetry','','[]','數間低矮屋，不可以擡頭。',48,'全唐诗/poet.song.187000.json','["數間低矮屋，不可以擡頭。", "嫌市塵埃濁，尋山泉石幽。", "門松霜幹古，窗竹露竿脩。", "辦此一廛了，從今何所求。"]'),
('83902dca-7017-4a8d-ab89-8253ff0a64e0','訪曇師','趙汝鐩','宋','宋诗','song-poetry','','[]','道人雲外住，小徑入庵幽。',48,'全唐诗/poet.song.187000.json','["道人雲外住，小徑入庵幽。", "幹老梅逾瘦，林疎竹自脩。", "揀茶相伴煮，補線且停抽。", "此事如何說，下山歸去休。"]'),
('14099171-9c40-43ab-a22a-cfb3b1377306','黯淡','趙汝鐩','宋','宋诗','song-poetry','','[]','黯淡四山暮，凄凉千里秋。',48,'全唐诗/poet.song.187000.json','["黯淡四山暮，凄凉千里秋。", "功名常嘆老，衰病豈禁愁。", "孤鴈影誰伴，亂蛩吟不休。", "一身天外客，雲盡是鄉州。"]'),
('f689dd18-00e3-459d-af52-02bf4d918125','訪皇甫道士','趙汝鐩','宋','宋诗','song-poetry','','[]','道人留淡話，竹院寂無聲。',48,'全唐诗/poet.song.187000.json','["道人留淡話，竹院寂無聲。", "沽酒童來緩，題窗詩已成。", "海珍紉紫菜，仙品漬黄精。", "移席臨簷月，焦桐膝上橫。"]'),
('d84dd46b-0459-4927-95e9-9fc8ca88ff6a','送聰上人歸四明','趙汝鐩','宋','宋诗','song-poetry','','[]','辦得四方遊，孜孜討入頭。',48,'全唐诗/poet.song.187000.json','["辦得四方遊，孜孜討入頭。", "歸雲起齋鉢，高浪送行舟。", "笠戴天童雨，鞋穿雪竇秋。", "平常心是道，莫更問人休。"]'),
('5aecf56d-d884-4577-b50b-e7d59c0b10f6','舟夜','趙汝鐩','宋','宋诗','song-poetry','','[]','夜泊楓林岸，江平萬籟收。',48,'全唐诗/poet.song.187000.json','["夜泊楓林岸，江平萬籟收。", "松崖猿裊月，蘆渚鴈眠秋。", "軒冕儻來爾，林泉歸去休。", "客愁正無奈，孤笛起漁舟。"]'),
('bbc1d2a9-458b-47b8-9505-296318a45f54','日融','趙汝鐩','宋','宋诗','song-poetry','','[]','日融風力軟，曳杖獨逍遥。',48,'全唐诗/poet.song.187000.json','["日融風力軟，曳杖獨逍遥。", "蜂去花心靜，鶑遷柳影摇。", "一年春易老，兩鬢雪難消。", "客至時留飲，無緣特地招。"]'),
('33356b9b-7123-4b00-bba5-37688f46b83d','題及之後山新築茅舍','趙汝鐩','宋','宋诗','song-poetry','','[]','瀟灑人間世，柴門夾兩槐。',48,'全唐诗/poet.song.187000.json','["瀟灑人間世，柴門夾兩槐。", "詩僧恰方去，俗客不曾來。", "翠合苔初長，紅嬌杏半開。", "南邊許多地，臘月竹須栽。"]'),
('59a00406-edf0-49bd-8a9f-f6c81b2deb25','送沈推赴官婺女','趙汝鐩','宋','宋诗','song-poetry','','[]','子抱風雲志，吾同筆硯遊。',48,'全唐诗/poet.song.187000.json','["子抱風雲志，吾同筆硯遊。", "衆皆尊大手，老尚客諸侯。", "清逼雙溪水，句涵三洞秋。", "儉僚非所處，有路在瀛洲。"]'),
('11ead119-8606-459f-9ad8-d0cf91fa600c','范園避暑','趙汝鐩','宋','宋诗','song-poetry','','[]','六月暑如炊，追凉此地宜。',48,'全唐诗/poet.song.187000.json','["六月暑如炊，追凉此地宜。", "棹舟荷柄颭，坐石竹陰移。", "籌貫壺雙耳，鼎烹茶一旗。", "小童供筆硯，醉客競賡詩。"]'),
('9423ad05-a189-4782-b1bb-20ea7b31f10b','新秋旅思','趙汝鐩','宋','宋诗','song-poetry','','[]','兩袖塵埃滿，千山道路勤。',48,'全唐诗/poet.song.187000.json','["兩袖塵埃滿，千山道路勤。", "曉清秋已到，葉落客先聞。", "鏡裏驚衰態，眉間添皺紋。", "人生閑第一，回首故山雲。"]'),
('0db7ed98-d6a4-4408-8e77-41156a1ba7a3','鄭氏莊','趙汝鐩','宋','宋诗','song-poetry','','[]','莊居深僻處，敲戶小童譍。',48,'全唐诗/poet.song.187000.json','["莊居深僻處，敲戶小童譍。", "此地清如許，前時到未曾。", "柳腰金裊娜，苔髮翠鬅鬙。", "山上茅亭子，扶衰爲一登。"]'),
('4b6927f4-4eb8-41f3-8d8e-8902829a1e17','夏夜與東叔昆仲小酌','趙汝鐩','宋','宋诗','song-poetry','','[]','入夏不爲淺，亭虛未甚炎。',48,'全唐诗/poet.song.187000.json','["入夏不爲淺，亭虛未甚炎。", "雲收風卷幕，月滿夜開匳。", "怕熱移燈遠，開懷索酒添。", "半酣詩興動，寫韵客分拈。"]'),
('9c4b2ef0-2eae-4ac8-b45a-e8007ded645b','訪次張廣上人繼至','趙汝鐩','宋','宋诗','song-poetry','','[]','都不見塵埃，園扉傍水開。',48,'全唐诗/poet.song.187000.json','["都不見塵埃，園扉傍水開。", "晴茵鋪碧草，風彈落黄梅。", "訪子因尋竹，呼童急辦杯。", "詩僧相繼至，罷酒把茶來。"]'),
('00d15a08-0d9b-49e7-a4fb-06d3ad3481fb','劉幹東園','趙汝鐩','宋','宋诗','song-poetry','','[]','築圃非容易，經營二十年。',48,'全唐诗/poet.song.187000.json','["築圃非容易，經營二十年。", "煙松迷五鬣，風柳起三眠。", "疊石連山麓，栽桃擬洞天。", "最爲瀟灑處，正在竹林邊。"]'),
('8720dc06-259f-48fc-a34f-bd26fd61136e','懷武陵王廣文','趙汝鐩','宋','宋诗','song-poetry','','[]','念子經年別，書嘗寄驛筒。',48,'全唐诗/poet.song.187000.json','["念子經年別，書嘗寄驛筒。", "每思談笑隔，或假夢魂通。", "師範新芹泮，騷情轉蕙風。", "拏舟訪秦洞，桃雨一川紅。"]'),
('9a299d7e-7042-4c39-a378-00b9b1d31d31','常山道中','趙汝鐩','宋','宋诗','song-poetry','','[]','寒謝春纔展，怱怱二月中。',48,'全唐诗/poet.song.187000.json','["寒謝春纔展，怱怱二月中。", "算來晴幾日，多是雨兼風。", "煙草迷村碧，山桃夾竹紅。", "浮名能役我，策馬幾回東。"]'),
('0ea639d3-6be5-449d-8eed-8790ce49f8c4','夏夜','趙汝鐩','宋','宋诗','song-poetry','','[]','今夕暑差甚，芒鞋階下行。',48,'全唐诗/poet.song.187000.json','["今夕暑差甚，芒鞋階下行。", "除燈簷月上，却扇竹風生。", "病骨坐怕久，靜吟詩易成。", "夜凉思睡去，樓鼓已三更。"]'),
('7f755dfc-63eb-46ff-a56d-4bb2839feafb','寄盧司戶','趙汝鐩','宋','宋诗','song-poetry','','[]','寂寞盧司戶，誅茅楚水東。',48,'全唐诗/poet.song.187000.json','["寂寞盧司戶，誅茅楚水東。", "幾年與君別，一字不余通。", "釣水空烹鯉，行汀屢扣鴻。", "夢魂還可託，握手片時同。"]'),
('46184bb6-cd04-4c21-8098-5772db1da2f9','宿山觀','趙汝鐩','宋','宋诗','song-poetry','','[]','昏暮無處宿，樵人指路頭。',48,'全唐诗/poet.song.187000.json','["昏暮無處宿，樵人指路頭。", "僕夫皆已困，道士幸相留。", "明月夜翻晝，陰崖暑變秋。", "聞雞便行路，定要到潭州。"]'),
('ebc6bf24-6068-4337-a2a5-ffcae02eda00','化成巖二首  其一','趙汝鐩','宋','宋诗','song-poetry','','[]','命友化成巖，同尋頃刻閑。',48,'全唐诗/poet.song.187000.json','["命友化成巖，同尋頃刻閑。", "半途瞻佛塔，數里入禪關。", "松動影移日，江清波漾山。", "衛公讀書處，有鷺宿其間。"]'),
('a636f130-33c4-4439-9372-deab29b4c514','化成巖二首  其二','趙汝鐩','宋','宋诗','song-poetry','','[]','一線沿崖路，衰殘步屧遲。',48,'全唐诗/poet.song.187000.json','["一線沿崖路，衰殘步屧遲。", "攀蘿衝霧上，倚檻俯空危。", "石佛像須久，山僧言不知。", "看來衆亭子，最是妙高奇。"]'),
('692ab0a3-187d-4c49-97b1-fc751197754d','乍晴','趙汝鐩','宋','宋诗','song-poetry','','[]','日色今朝穩，園林二月中。',48,'全唐诗/poet.song.187000.json','["日色今朝穩，園林二月中。", "池塘展晴綠，桃杏鬭春紅。", "犯險升高徑，扶衰藉小童。", "黄鸝怕人見，飛過野橋東。"]'),
('81416a6e-f781-4805-86d3-414525482600','江閣夜','趙汝鐩','宋','宋诗','song-poetry','','[]','小閣臨江迥，疎簾带霧鈎。',48,'全唐诗/poet.song.187000.json','["小閣臨江迥，疎簾带霧鈎。", "雲鴻遥影滅，灘月碎光流。", "詩思偏宜夜，衰髯不耐秋。", "漁燈三兩點，隠隠荻花洲。"]'),
('104f1ab8-3ecb-450a-aca7-e63f78ac6a80','晚興','趙汝鐩','宋','宋诗','song-poetry','','[]','是處牛羊下，喧嘩走牧童。',48,'全唐诗/poet.song.187000.json','["是處牛羊下，喧嘩走牧童。", "霽煙拖淡碧，夕照殞殘紅。", "老鬢日添雪，衰軀晚怕風。", "愁來無著處，分付酒杯中。"]'),
('5e63a0c8-62f5-4a40-ae1f-f6463e23a6c5','雪中尋僧','趙汝鐩','宋','宋诗','song-poetry','','[]','尋僧同踏雪，握手上鐘樓。',48,'全唐诗/poet.song.187000.json','["尋僧同踏雪，握手上鐘樓。", "初下寒飄屑，纔濃風輥毬。", "水波糊紙閤，春乳泛茶甌。", "片片看來好，龐公有話頭。"]'),
('9c6ac2c3-7d13-4500-89ae-fc7d12a24731','莊居','趙汝鐩','宋','宋诗','song-poetry','','[]','三四間茅屋，回環水石清。',48,'全唐诗/poet.song.187000.json','["三四間茅屋，回環水石清。", "雞催殘漏盡，月截半窗明。", "好句枕邊得，浮名身外輕。", "起來供日課，先遶藥畦行。"]'),
('2362efde-5bca-48cf-83dc-759499308c29','泊舟','趙汝鐩','宋','宋诗','song-poetry','','[]','舟泊似差早，篙工愛酒坊。',48,'全唐诗/poet.song.187000.json','["舟泊似差早，篙工愛酒坊。", "羊羣歸遠隴，柳影戀斜陽。", "澤國人千里，暮霞天一方。", "茶多不思睡，漁唱聽滄浪。"]'),
('a712cace-5e91-4158-bbce-59deed81320a','蠶舍','趙汝鐩','宋','宋诗','song-poetry','','[]','每到蠶時候，村村多閉門。',48,'全唐诗/poet.song.187000.json','["每到蠶時候，村村多閉門。", "往來斷親黨，啼叫禁兒孫。", "不惜兼旬力，將圖終歲溫。", "殷勤馬明祝，燈火謹朝昏。"]'),
('5136a33e-03e8-40bd-b272-c7b132a78c49','送同年李教秩滿歸閩','趙汝鐩','宋','宋诗','song-poetry','','[]','鴈塔同題久，相看兩鬢皤。',48,'全唐诗/poet.song.187000.json','["鴈塔同題久，相看兩鬢皤。", "功名皆分定，安樂直錢多。", "絳帳歸來後，青山住得麽。", "時流推老筆，冊府欠編摩。"]'),
('a7deb135-dbca-427a-a564-6204011efccf','同子嚴初夏飲山閤','趙汝鐩','宋','宋诗','song-poetry','','[]','綠陰千百頃，約我共登臨。',48,'全唐诗/poet.song.187000.json','["綠陰千百頃，約我共登臨。", "山翠含煙重，榴紅著雨深。", "行藏皆有命，計較謾勞心。", "病怕杯中物，憐余淺淺斟。"]'),
('08d2f076-8396-4812-8e8c-2ab8aee19b23','聞舟中笛','趙汝鐩','宋','宋诗','song-poetry','','[]','橫笛秋篷底，銜山夕照殘。',48,'全唐诗/poet.song.187000.json','["橫笛秋篷底，銜山夕照殘。", "孤音起水面，餘韵到雲端。", "吹怨蘆聲慘，含悽鴈影寒。", "有人江閣上，歛翠凭欄干。"]'),
('2ae5d738-a6c6-496f-887c-d77c49ae8308','寄友人','趙汝鐩','宋','宋诗','song-poetry','','[]','口信傳商賈，年前未得歸。',48,'全唐诗/poet.song.187000.json','["口信傳商賈，年前未得歸。", "湘沅淹異縣，日月老征衣。", "騷興遍芳渚，舊棲閑釣磯。", "思君不可見，獨自立斜暉。"]'),
('4af35f21-f048-42e8-a0b6-61abb1a09676','清明小飲','趙汝鐩','宋','宋诗','song-poetry','','[]','草草清明飲，惠風天氣和。',48,'全唐诗/poet.song.187000.json','["草草清明飲，惠風天氣和。", "身輕梁燕舞，舌巧柳鶑歌。", "但道三春好，其如兩鬢何。", "升沉付杯酒，由命不由他。"]'),
('fd00ac40-7b6d-4543-84ce-fe0536a576b2','過曹家渡','趙汝鐩','宋','宋诗','song-poetry','','[]','數篙撐過渡，雨後水添肥。',48,'全唐诗/poet.song.187000.json','["數篙撐過渡，雨後水添肥。", "山橘青迷樹，野花香襲衣。", "哀鴻悽遠客，鬭雀墮斜暉。", "童稚喧林壟，牛羊箇箇歸。"]'),
('5cc4b2eb-3b6f-4d34-ad21-7778199ee35d','午炊浰陽一館甚雅','趙汝鐩','宋','宋诗','song-poetry','','[]','誰料三家市，能令兩眼明。',48,'全唐诗/poet.song.187000.json','["誰料三家市，能令兩眼明。", "花喧叢蝶戀，簷午亂雞鳴。", "忙裏青春去，愁邊白髮生。", "摇鞭問歸路，更乞一旬晴。"]'),
('64b160f3-a18b-4a65-8119-3e305a5c9dcf','送同官葉榷院造朝二首  其一','趙汝鐩','宋','宋诗','song-poetry','','[]','新制重分司，誰云筦榷卑。',48,'全唐诗/poet.song.187000.json','["新制重分司，誰云筦榷卑。", "鵬摶終可料，鷃笑彼何知。", "細滿豈無待，橫飛亦未遲。", "催班天上去，黄色已浮眉。"]'),
('e245c970-604c-4e55-a963-6147c754ae1d','送同官葉榷院造朝二首  其二','趙汝鐩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','滿歲塵埃共，交情骨肉親。',48,'全唐诗/poet.song.187000.json','["滿歲塵埃共，交情骨肉親。", "我猶京口客，君已日邊人。", "波及無忘晉，渠成亦利秦。", "西湖約携手，兩岸柳摇春。"]'),
('423163e3-6de5-4494-a73e-87c93390f504','同楊濟翁唐季路陳純叟飲光風亭光風舊名招屈純叟席上鼓琴','趙汝鐩','宋','宋诗','song-poetry','','[]','江邊舊亭子，招屈改光風。',48,'全唐诗/poet.song.187000.json','["江邊舊亭子，招屈改光風。", "揭扁名雖異，懷人意則同。", "一篇漁父問，千古大夫忠。", "酒盡琴猶鼓，幽蘭曲未終。"]'),
('26656aab-e4da-46da-bfa7-5b0d6c2abed2','翁靈舒客臨川因經從訪之不遇聞過村居','趙汝鐩','宋','宋诗','song-poetry','','[]','聞道深村裏，結茅三四間。',48,'全唐诗/poet.song.187000.json','["聞道深村裏，結茅三四間。", "買田因種秫，移樹爲看山。", "詩好人皆誦，身安心自閑。", "有時思鴈蕩，依舊棹舟還。"]'),
('69210f1f-95e3-41cc-8405-ee34da896508','西湖訪梅','趙汝鐩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','久無梅信息，訪問到湖濱。',48,'全唐诗/poet.song.187000.json','["久無梅信息，訪問到湖濱。", "耐盡一冬冷，開殘千樹春。", "臨流轉風韵，與雪鬭精神。", "疎影暗香後，能吟有幾人。"]'),
('0bcc4ecf-35c7-4fc9-bb23-c6fcfe0faff3','漁舟','趙汝鐩','宋','宋诗','song-poetry','','[]','秋巘翠千疊，晴溪玉一灣。',24,'全唐诗/poet.song.187000.json','["秋巘翠千疊，晴溪玉一灣。", "漁舟三兩箇，來往釣其間。"]'),
('84935043-0f3c-4ad5-b7e1-400c63b2b5ab','出郊','趙汝鐩','宋','宋诗','song-poetry','','[]','二月垂楊岸，行春詩酒徒。',24,'全唐诗/poet.song.187000.json','["二月垂楊岸，行春詩酒徒。", "蒼頭前引道，拄杖掛葫蘆。"]'),
('0beb978b-4909-44d4-8a23-efe60aff94f5','不眠','趙汝鐩','宋','宋诗','song-poetry','','[]','刺齒搜新句，濡毫寫短牋。',24,'全唐诗/poet.song.187000.json','["刺齒搜新句，濡毫寫短牋。", "讀來疎脫少，懽喜不成眠。"]'),
('1b8daada-8ee9-42c3-8610-7df22310e685','登樓','趙汝鐩','宋','宋诗','song-poetry','','[]','地卑梅雨濕，氣壓篆煙低。',24,'全唐诗/poet.song.187000.json','["地卑梅雨濕，氣壓篆煙低。", "熟是披襟處，高樓百尺梯。"]'),
('4ea95f25-e4e0-4ee5-84ad-86265b364f27','贈定上人','趙汝鐩','宋','宋诗','song-poetry','','[]','談禪皆是病，參請不須忙。',24,'全唐诗/poet.song.187000.json','["談禪皆是病，參請不須忙。", "且看諸尊宿，相傳甚藥方。"]'),
('e6fa3b62-1268-46d1-b525-df2a1daaed9e','苦吟','趙汝鐩','宋','宋诗','song-poetry','','[]','幾度燈花落，苦吟難便成。',24,'全唐诗/poet.song.187000.json','["幾度燈花落，苦吟難便成。", "寒窗明月滿，樓上打三更。"]'),
('aa9430bf-8fef-46dc-a3a0-dc17b1742025','尋勝','趙汝鐩','宋','宋诗','song-poetry','','[]','老子携筇杖，小童挑酒壺。',24,'全唐诗/poet.song.187000.json','["老子携筇杖，小童挑酒壺。", "徧尋泉石勝，引路倩樵夫。"]'),
('ffc55890-f8e4-427a-8c4e-3617bf52f5b2','傷春','趙汝鐩','宋','宋诗','song-poetry','','[]','飛蝶捎風絮，鳴禽戀午簷。',24,'全唐诗/poet.song.187000.json','["飛蝶捎風絮，鳴禽戀午簷。", "不知春去未，但覺綠陰添。"]'),
('1c348be2-3b4c-4005-b3a7-17add52b8491','半夜','趙汝鐩','宋','宋诗','song-poetry','','[]','坐久香銷篆，更長燭屢花。',24,'全唐诗/poet.song.187000.json','["坐久香銷篆，更長燭屢花。", "一輪觀浴兔，兩部聽鳴蛙。"]'),
('dfb944f2-73ea-4e8d-bd8c-f8827b6ee435','踏青','趙汝鐩','宋','宋诗','song-poetry','','[]','四野春工遍，柔風動賞心。',24,'全唐诗/poet.song.187000.json','["四野春工遍，柔風動賞心。", "踏青喧柳陌，舉白醉花陰。"]'),
('0cc2b0ad-18fb-40a5-8a45-ad22ea4e3fc2','山礬','趙汝鐩','宋','宋诗','song-poetry','','[]','七里香風遠，山礬滿路開。',24,'全唐诗/poet.song.187000.json','["七里香風遠，山礬滿路開。", "野生人所賤，移動却難栽。"]'),
('f362a608-4683-44d5-8fee-a8980ada6d63','白髮','趙汝鐩','宋','宋诗','song-poetry','','[]','朱顔留不住，白髮自應生。',24,'全唐诗/poet.song.187000.json','["朱顔留不住，白髮自應生。", "摘了依然有，徒勞打鑷聲。"]'),
('009d0e3c-2320-4a1a-a36c-c7e25de53292','雨過','趙汝鐩','宋','宋诗','song-poetry','','[]','一霎荷塘雨，明珠翠蓋擎。',24,'全唐诗/poet.song.187000.json','["一霎荷塘雨，明珠翠蓋擎。", "柄危難得穩，稍側便須傾。"]'),
('dbd0a86b-c307-4aed-80e6-c51fc32f55e7','夜歸','趙汝鐩','宋','宋诗','song-poetry','','[]','爲愛清秋月，徘徊步水濱。',24,'全唐诗/poet.song.187000.json','["爲愛清秋月，徘徊步水濱。", "夜歸驚犬吠，錯認是生人。"]'),
('c56c1ee3-85bc-49c6-8aca-8aba4db4e3f6','山寺','趙汝鐩','宋','宋诗','song-poetry','','[]','樹暗常疑夜，山多易得雲。',24,'全唐诗/poet.song.187000.json','["樹暗常疑夜，山多易得雲。", "撞鐘最深處，嶺外不曾聞。"]'),
('70e4bdeb-ace0-4fb6-9dc8-9f19d22f0fc0','題莊舍壁','趙汝鐩','宋','宋诗','song-poetry','','[]','水深荷較晚，地僻草偏多。',24,'全唐诗/poet.song.187000.json','["水深荷較晚，地僻草偏多。", "佇立風前聽，樵夫隔隴歌。"]'),
('686a6a7a-120f-4e45-af42-7484ed47e7c9','無題','趙汝鐩','宋','宋诗','song-poetry','','[]','人與春俱老，花因雨易殘。',24,'全唐诗/poet.song.187000.json','["人與春俱老，花因雨易殘。", "天涯雲萬里，腸斷倚欄干。"]'),
('5d041e67-631c-4b6d-96af-be43eb45602c','後圃','趙汝鐩','宋','宋诗','song-poetry','','[]','澆花惟要早，芟草不知名。',24,'全唐诗/poet.song.187000.json','["澆花惟要早，芟草不知名。", "新竹生來巧，南牆補數莖。"]'),
('57609ec8-c6fd-415b-94fc-eb16407ff74e','夏日山中','趙汝鐩','宋','宋诗','song-poetry','','[]','瀑近書皆潤，林深簟更涼。',24,'全唐诗/poet.song.187000.json','["瀑近書皆潤，林深簟更涼。", "山中無一事，夏日覺尤長。"]'),
('c34a173f-08f6-485f-bdea-0953da8bdeaa','吟髭','趙汝鐩','宋','宋诗','song-poetry','','[]','壯歲髭如漆，年來暮景侵。',24,'全唐诗/poet.song.187000.json','["壯歲髭如漆，年來暮景侵。", "便令如雪白，撚斷不妨吟。"]'),
('a19a88a0-e664-4de1-858f-c187df860181','秋夜','趙汝鐩','宋','宋诗','song-poetry','','[]','秋到情懷惡，美人天一方。',24,'全唐诗/poet.song.187000.json','["秋到情懷惡，美人天一方。", "夜深窗轉月，夢斷角吹霜。"]'),
('3e7dea6e-61ce-4516-b190-e14443aab9e9','多景樓','趙汝鐩','宋','宋诗','song-poetry','','[]','北固危登最上層，身浮霄漢手捫星。',64,'全唐诗/poet.song.187000.json','["北固危登最上層，身浮霄漢手捫星。", "江連淮海東南勝，山出金焦左右青。", "天水精神清鴈骨，風煙圖畫入秋屏。", "蕭蕭古意憑欄久，目盡斜陽沒遠汀。"]'),
('57c5e15b-56e7-4a25-9578-e46b22e37161','岳陽樓','趙汝鐩','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','洞庭雄壓岳陽樓，萬里風煙萬里秋。',64,'全唐诗/poet.song.187000.json','["洞庭雄壓岳陽樓，萬里風煙萬里秋。", "左右江湖同浩蕩，東西日月遞沉浮。", "青蛇鳴袖神仙過，古瑟彈湘帝子遊。", "朝暮飛鷗千百點，送迎城下去來舟。"]'),
('0bbed158-262e-4659-a5bd-8942b5bff11b','再登岳陽樓','趙汝鐩','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','岳陽城下繫扁舟，與客同登百尺樓。',64,'全唐诗/poet.song.187000.json','["岳陽城下繫扁舟，與客同登百尺樓。", "尋遍詩牌追舊句，恍驚歲律嘆重遊。", "波涵君艑兩山翠，天落巴荆一鏡秋。", "北望邊烽猶未熄，敢忘後樂與先憂。"]'),
('dfb65e77-8130-4694-be53-f464f9fd6553','江樓會飲對月','趙汝鐩','宋','宋诗','song-poetry','','[]','層樓畫棟淩霄漢，檻外江流百頃清。',64,'全唐诗/poet.song.187000.json','["層樓畫棟淩霄漢，檻外江流百頃清。", "無一片雲但秋色，放千里月到天明。", "喚舟撒網鮮鱗美，擊鼓喧汀宿鷺驚。", "坐上有人懽未厭，酒闌連釂兩三觥。"]'),
('b0e82fc4-037f-4831-9aa7-1cfbaa94f3c9','訪別胡倅留飲水閣','趙汝鐩','宋','宋诗','song-poetry','','[]','故人知我已膏車，折簡殷勤祝訪渠。',64,'全唐诗/poet.song.187000.json','["故人知我已膏車，折簡殷勤祝訪渠。", "惜別怱怱留語笑，臨時草草治餚蔬。", "密遮池面荷千蓋，斜插雲頭月一梳。", "此夕憑欄又何日，鴈來莫惜數行書。"]'),
('7a89b2dd-2c12-4cfe-84cb-f95bbb1a1362','春嬉','趙汝鐩','宋','宋诗','song-poetry','','[]','十分晴色趁春嬉，鄰有灰馿惜我騎。',64,'全唐诗/poet.song.187000.json','["十分晴色趁春嬉，鄰有灰馿惜我騎。", "舌囀雖然聞翠柳，葉濃却不見黄鸝。", "小詩題壁同僧和，丫角携琴更鶴隨。", "傍水誰家亭子好，萬竿竹影浸琉璃。"]'),
('8baa6071-3e04-434f-b423-9a628aa5669d','豐城道中','趙汝鐩','宋','宋诗','song-poetry','','[]','雨後泥深馬費鞭，看來遵陸豈如船。',64,'全唐诗/poet.song.187000.json','["雨後泥深馬費鞭，看來遵陸豈如船。", "人行灘過無多水，鴈带雲飛不盡天。", "束擔侵晨離故縣，算程明日至臨川。", "長安鍾鼓何時聽，東望猶爭路一千。"]'),
('4c3d07ff-bcf7-45f3-a46d-f677d84b0a3a','送端叔遊淮','趙汝鐩','宋','宋诗','song-poetry','','[]','堂堂玉立鬚垂腹，談論逢人見肺肝。',64,'全唐诗/poet.song.187000.json','["堂堂玉立鬚垂腹，談論逢人見肺肝。", "手弄七絃琴韵古，腰橫三尺劍光寒。", "但將計策尋知己，肯學閭閻爲覓官。", "烏幕聞君定羅致，別樽不復話儒酸。"]'),
('dc49657f-98e9-4533-b739-c8567c685ab8','早征','趙汝鐩','宋','宋诗','song-poetry','','[]','店雞一唱接疎鍾，起整行裝尚夢中。',64,'全唐诗/poet.song.187000.json','["店雞一唱接疎鍾，起整行裝尚夢中。", "沙路踏殘征馬月，柳堤啼斷曉鶑風。", "水肥渡險添舟子，岸沒途窮問牧童。", "千里鄉人逢陌上，片時握手各西東。"]'),
('514ae9bf-5af9-4e3b-b74a-582125af0218','明皇','趙汝鐩','宋','宋诗','song-poetry','','[]','初年不是不聰明，勤政開元致太平。',64,'全唐诗/poet.song.187000.json','["初年不是不聰明，勤政開元致太平。", "一曲羽衣妃子進，三朝錦褓祿兒生。", "眼乾蜀道山川淚，膽碎漁陽鼙鼓聲。", "禍福興亡皆自取，信知女色解傾城。"]'),
('f58be278-3f3f-41dc-9168-e47c4ef2eefd','郊行同張宰','趙汝鐩','宋','宋诗','song-poetry','','[]','雨晴郊外共尋芳，細水交流注野塘。',64,'全唐诗/poet.song.187000.json','["雨晴郊外共尋芳，細水交流注野塘。", "花欲戀枝風不肯，柳纔舞影日還藏。", "轉添老態難於健，看得閑時少似忙。", "擬訪一僧共茶話，禪房扃鎖出遊方。"]'),
('3b87014f-fa4b-403b-81b8-0823323fdb93','謝人送端硯水沉','趙汝鐩','宋','宋诗','song-poetry','','[]','屏迹山林絕往還，忽傳軍將扣雲關。',64,'全唐诗/poet.song.187000.json','["屏迹山林絕往還，忽傳軍將扣雲關。", "十年憶別湖湘外，五朵驚飛几案聞。", "硯寄下巖鸜鵒眼，沉分上岸鷓鴣班。", "墨磨煙麝香橫霧，搜索詩腸愧我慳。"]'),
('e1167681-9a99-47b9-a98f-e886a3c1549d','湖亭夜飲會別友人','趙汝鐩','宋','宋诗','song-poetry','','[]','每聞嗟嘆無知己，定要携琴過浙東。',64,'全唐诗/poet.song.187000.json','["每聞嗟嘆無知己，定要携琴過浙東。", "莫訝醵樽俱草草，只因束擔去怱怱。", "竹篩夜影千竿月，荷送湖香萬朵風。", "早晚我尋京口戍，子歸或遇半途中。"]'),
('9daca97f-90fd-4107-81a5-f5c0013e9919','醵飲','趙汝鐩','宋','宋诗','song-poetry','','[]','出城二里野人居，最愛園亭傍室廬。',64,'全唐诗/poet.song.187000.json','["出城二里野人居，最愛園亭傍室廬。", "墨湧清池聚科斗，雪明碧嶂過舂鉏。", "興來醵友尋詩酒，忙裏携盤但醢蔬。", "新創小軒尤更爽，百來竿竹間椶櫚。"]'),
('2899ed7f-0294-4203-9bfe-896b49068e00','午炊徐坊嶺','趙汝鐩','宋','宋诗','song-poetry','','[]','途長力困時時歇，日影將中僕馬饑。',64,'全唐诗/poet.song.187000.json','["途長力困時時歇，日影將中僕馬饑。", "糴米荒年增價售，汲泉遠井得炊遲。", "竹稠亂笋穿開路，藤茂多花蓋盡籬。", "飯了店翁相送出，丁寧前面小橋危。"]'),
('387cf9d3-84af-4335-9497-10abf85440de','即事','趙汝鐩','宋','宋诗','song-poetry','','[]','十里東風摇羽葆，高低遠近萬株松。',64,'全唐诗/poet.song.187000.json','["十里東風摇羽葆，高低遠近萬株松。", "側身靠石牛揩癢，俛首穿林鹿護茸。", "樵子登山雲裏過，詩僧採藥澗邊逢。", "近傳有虎常來往，隔隴猶存舊脚蹤。"]'),
('435ec93b-6c6b-4a19-8dc0-0d52306adc36','縱步','趙汝鐩','宋','宋诗','song-poetry','','[]','久雨厭人妨野步，幾時便得此番晴。',64,'全唐诗/poet.song.187000.json','["久雨厭人妨野步，幾時便得此番晴。", "到橋喚僕來相助，過寺逢僧約共行。", "籬落一團飛蛺蝶，汀洲數點立鵁鶄。", "農家竹裏深深住，風度茅簷紡織聲。"]'),
('92500512-5b57-46b2-9952-9adef32db53e','題合江亭','趙汝鐩','宋','宋诗','song-poetry','','[]','石鼓山頭一小亭，乾坤萬里眼雙明。',64,'全唐诗/poet.song.187000.json','["石鼓山頭一小亭，乾坤萬里眼雙明。", "雖因刺史能尋勝，不遇昌黎豈得名。", "衡嶽雲開秋洗碧，蒸江湘合水爭清。", "書巖莫辨當時字，空積塵泥野草生。"]'),
('86f311f5-98c4-4dd5-afae-15b158963bcf','訪友野外','趙汝鐩','宋','宋诗','song-poetry','','[]','雨意方濃改作晴，杖藜野外訪柴荆。',64,'全唐诗/poet.song.187000.json','["雨意方濃改作晴，杖藜野外訪柴荆。", "爭尋桑葉占蠶熟，退立田塍避犢行。", "風過沙平收鳥迹，煙濃寺沒但鍾聲。", "小童走報余將至，一笑松間倒屣迎。"]'),
('24e8a02d-c2ee-4554-8b28-b5abd64a06c3','晚征','趙汝鐩','宋','宋诗','song-poetry','','[]','回首家山已十程，摇鞭自笑苦勞生。',64,'全唐诗/poet.song.187000.json','["回首家山已十程，摇鞭自笑苦勞生。", "雲先带暝巖邊宿，月獨伴人溪上行。", "草屋停驂難可意，店翁叱犬不容聲。", "明朝路遠起須早，第一雞啼是五更。"]'),
('c028d816-2a1b-4f96-bc87-a239341a408d','茶罷','趙汝鐩','宋','宋诗','song-poetry','','[]','茶罷晴簷唱午雞，偶騎馿去過東溪。',64,'全唐诗/poet.song.187000.json','["茶罷晴簷唱午雞，偶騎馿去過東溪。", "酒餚分倩樵夫挈，筆硯專令童子携。", "放目水亭欄獨倚，題詩僧舍壁新泥。", "興闌歸問來時路，到處蟬鳴日已西。"]'),
('a1afe144-f5e8-45b6-a8aa-6bdbabe17803','送魯卿之九江','趙汝鐩','宋','宋诗','song-poetry','','[]','歸自瀟湘方半月，挑燈酌酒又分襟。',64,'全唐诗/poet.song.187000.json','["歸自瀟湘方半月，挑燈酌酒又分襟。", "掛帆秋晚江湖客，握手歲寒松柏心。", "湓浦水流清一派，香爐峰濕翠千尋。", "西風遠想登臨處，日日携琴日日吟。"]'),
('9909e013-cfaf-4626-8ba9-2b2396c46b70','泊舟周家步','趙汝鐩','宋','宋诗','song-poetry','','[]','梢子商量乘早泊，向前十里不逢村。',64,'全唐诗/poet.song.187000.json','["梢子商量乘早泊，向前十里不逢村。", "卸帆歛柁依山脚，繫纜添樁傍樹根。", "月魄知風昏有暈，秋光入水浄無痕。", "五更露下欺孤枕，忽聽新鴻更斷魂。"]'),
('51bd5243-49ff-496e-8e11-6ac2174db54b','過黄園','趙汝鐩','宋','宋诗','song-poetry','','[]','黄家亭館人稱好，杖屨春風領客行。',64,'全唐诗/poet.song.187000.json','["黄家亭館人稱好，杖屨春風領客行。", "開放園門千嶂入，愛他山閣一溪橫。", "花迷粉翅雙飛蝶，柳露金衣百囀鶑。", "酒後著棋聊適興，未須屑屑較輸贏。"]'),
('f4bbba0f-f87b-445d-8a7f-d4e261fbbf1d','午炊溪店','趙汝鐩','宋','宋诗','song-poetry','','[]','草店臨流傍蓼汀，午炊於此片時停。',64,'全唐诗/poet.song.187000.json','["草店臨流傍蓼汀，午炊於此片時停。", "健農怗岸般卵石，幼婦汲泉携斗瓶。", "薦飯滿盂山芋美，開窗匝室野花馨。", "隔籬庵舍極瀟灑，萬竹中間著小亭。"]'),
('64849d89-686f-4620-8639-32b7a5d59262','訪友人溪居','趙汝鐩','宋','宋诗','song-poetry','','[]','數間屋子壓溪光，百十喬松列翠行。',64,'全唐诗/poet.song.187000.json','["數間屋子壓溪光，百十喬松列翠行。", "鶴爲聽琴朱頂側，鴨皆睡日綠頭藏。", "後園遣僕鋤冬筍，隔岸尋僧度野航。", "天色黄昏歸已晚，苦留夜話對胡牀。"]'),
('3f2992b3-d455-43d6-89aa-5b004952372c','野步','趙汝鐩','宋','宋诗','song-poetry','','[]','雨收日薄春容嫩，步步東風桃李蹊。',64,'全唐诗/poet.song.187000.json','["雨收日薄春容嫩，步步東風桃李蹊。", "香遞深林疑麝過，聲傳幽谷認鶑啼。", "路摧迂步行荒草，橋斷褰裳涉淺溪。", "歸遇田翁醉邀我，旋教買酒旋烹雞。"]'),
('3aac266f-51b8-495c-9bf3-74a00e44c55b','同官率遊鄭園','趙汝鐩','宋','宋诗','song-poetry','','[]','亭圍花木閣臨池，移席行杯處處宜。',64,'全唐诗/poet.song.187000.json','["亭圍花木閣臨池，移席行杯處處宜。", "藻裏漾春魚放子，竹間尋路鶴將兒。", "登山少俊誇先到，扶杖衰殘愧獨遲。", "所恨隔關歸去急，不容結果着殘棋。"]'),
('f9961b52-d6a7-4538-8548-a7bb6e4510f5','避暑溪上','趙汝鐩','宋','宋诗','song-poetry','','[]','不堪蝸舍暑如炊，何處清幽可杖藜。',64,'全唐诗/poet.song.187000.json','["不堪蝸舍暑如炊，何處清幽可杖藜。", "未約客須先覓酒，要尋凉必去臨溪。", "撐船訪洞林間港，坐石吟風柳下隄。", "晚網得魚似湖白，鑾刀鱠玉搗香齏。"]'),
('7da01293-71c3-4a96-bf38-b2a4708de9cf','宿橫山','趙汝鐩','宋','宋诗','song-poetry','','[]','頗厭東征道路長，回頭十日離鄉邦。',64,'全唐诗/poet.song.187000.json','["頗厭東征道路長，回頭十日離鄉邦。", "掃愁酌酒雖云獨，照影挑燈却暫雙。", "打併餘花風動地，遷延殘夜月留窗。", "店雞已唱催人起，更聽疎鐘隔水撞。"]'),
('609b6f80-234d-4ad7-8ff8-17bdd20e3df8','張園','趙汝鐩','宋','宋诗','song-poetry','','[]','幾年人說張園好，筇杖芒鞋欠我遊。',64,'全唐诗/poet.song.187000.json','["幾年人說張園好，筇杖芒鞋欠我遊。", "泉脈涓涓三里遠，山根匝匝四時流。", "鶴嫌竹密妨來往，蝶厭花多費應酬。", "臺館高低皆得所，松間亭子最清幽。"]'),
('057ac26a-07a9-446f-ad70-2d7d2025d81d','崇真觀東軒','趙汝鐩','宋','宋诗','song-poetry','','[]','東軒面水枕山阿，左右雲煙濕翠蘿。',64,'全唐诗/poet.song.187000.json','["東軒面水枕山阿，左右雲煙濕翠蘿。", "風度鶴聲聞遠壑，日移松影轉前坡。", "愁來獨靠清樽遣，老去休憎白髮多。", "道士罷琴揮醉筆，詩成自喚小童哦。"]'),
('fce9a4c2-b95b-4b04-8122-43e27f372fd7','溪上','趙汝鐩','宋','宋诗','song-poetry','','[]','一番雨過驟晴時，溪上春光色色奇。',64,'全唐诗/poet.song.187000.json','["一番雨過驟晴時，溪上春光色色奇。", "日暖花繁蝴蝶困，水清魚過鷺鷥隨。", "村翁開卷添黏紙，瓦鉢研朱自教兒。", "織婦倚機方嘆息，輸官尚欠二斤絲。"]'),
('30fcf2b0-4493-49c7-a4ec-e715ae016f15','懷徐教','趙汝鐩','宋','宋诗','song-poetry','','[]','憶昔相逢氣味投，興來無日不追遊。',64,'全唐诗/poet.song.187000.json','["憶昔相逢氣味投，興來無日不追遊。", "靜尋鷗鷺同溪社，醉挈乾坤入釣舟。", "湖海怱怱三歲別，塵埃汩汩幾時休。", "一丘彼此皆能辦，何用人間萬戶侯。"]'),
('e6fbe18b-366d-4b14-a00a-485160b5758f','同趙尉飲江亭','趙汝鐩','宋','宋诗','song-poetry','','[]','草草三間兩眼明，數峰如畫一江橫。',64,'全唐诗/poet.song.187000.json','["草草三間兩眼明，數峰如畫一江橫。", "風烏破浪帆檣急，野鶻過林鳥雀驚。", "蟻取浮篘尤有味，魚方出網正宜羹。", "流鶑憐我無歌者，簧舌頻翻柳上聲。"]'),
('0d54653b-2f08-4664-9c6e-eeed2e54fb57','遊曹園','趙汝鐩','宋','宋诗','song-poetry','','[]','先登東畔高亭子，洗却胸襟萬斛塵。',64,'全唐诗/poet.song.187000.json','["先登東畔高亭子，洗却胸襟萬斛塵。", "落片玉殘梅興盡，舊梢金吐柳芽新。", "倚林困鶴聊休足，巡食饑烏不避人。", "尚欲徘徊已燈火，歸騶屢趣入城闉。"]'),
('e5b2b3c5-09cb-43cc-b417-c7b7f9dcd36f','黄幹見約小飲就宿','趙汝鐩','宋','宋诗','song-poetry','','[]','病後何人慰寂寥，長鬚持簡忽相招。',64,'全唐诗/poet.song.187000.json','["病後何人慰寂寥，長鬚持簡忽相招。", "溪山見說爲樓爽，杖屨寧辭去郭遥。", "柳絮一天晴舞雪，松聲十里夜聞潮。", "談詩直到疎鐘動，酒困頻將茗椀澆。"]'),
('e47f415a-5cd4-4580-8480-02d77c85e814','懷亨父','趙汝鐩','宋','宋诗','song-poetry','','[]','兩年隻影瀟湘去，料想塵埃白髮侵。',64,'全唐诗/poet.song.187000.json','["兩年隻影瀟湘去，料想塵埃白髮侵。", "久雨千山秋得意，西風一鴈客關心。", "或於夢裏陪談笑，每向人前問信音。", "憶昔賡詩巖桂下，花開今日嘆孤斟。"]'),
('10d5c65f-ee81-4019-8f8c-717133dd28da','題村舍壁','趙汝鐩','宋','宋诗','song-poetry','','[]','柔風十里日曈矓，雨後陂塘野水通。',64,'全唐诗/poet.song.187000.json','["柔風十里日曈矓，雨後陂塘野水通。", "兩岸柳煙籠曉綠，數枝桃露滴春紅。", "明知鍾鼎衆皆羨，到了山林味不同。", "田父殷勤邀我坐，一盂白飯一盂菘。"]'),
('dd0e33a4-47ea-4722-aec3-d5c9340bac7d','旅次春眺','趙汝鐩','宋','宋诗','song-poetry','','[]','獨倚危欄春意遠，本無情緒强登臨。',64,'全唐诗/poet.song.187000.json','["獨倚危欄春意遠，本無情緒强登臨。", "一眉晚拂晴山黛，萬縷風摇岸柳金。", "久負故園泉石約，恍驚老鬢雪霜侵。", "兩年雙脚數千里，奔走塵埃損道心。"]'),
('d3b73e50-a829-42be-8df4-3f7c9ca7e91c','宿妙果寺贈洪上人','趙汝鐩','宋','宋诗','song-poetry','','[]','上人留我禪房宿，煮笋烹茶語夜闌。',64,'全唐诗/poet.song.187000.json','["上人留我禪房宿，煮笋烹茶語夜闌。", "鐵馬鳴風山牖寂，木魚敲雪曉廊寒。", "真筌但要此心悟，公案休將故紙鑽。", "若道吾言沒滋味，請師且去坐蒲團。"]'),
('89f2f45d-b795-4bba-b5b7-2a66055f711e','訪黄簿留飲','趙汝鐩','宋','宋诗','song-poetry','','[]','愛靜移家住水南，門排古木枕寒潭。',64,'全唐诗/poet.song.187000.json','["愛靜移家住水南，門排古木枕寒潭。", "鶴翎漸長呼童翦，麈尾頻揮對客談。", "旋切銀絲鱠鮮鯽，新嘗金顆擘香柑。", "惜余戒飲難陪伴，舉白掀髯子獨酣。"]'),
('2f22b007-50dc-487a-8a1e-f14d38718dfc','行春','趙汝鐩','宋','宋诗','song-poetry','','[]','綠楊裊裊草萋萋，緩步行春獨杖藜。',64,'全唐诗/poet.song.187000.json','["綠楊裊裊草萋萋，緩步行春獨杖藜。", "搜蘂蜂兒透花骨，增巢燕子砌芹泥。", "過溪野水衝橋版，覓路田塍穿菜畦。", "松竹林間僧揖我，謁茶携手上招提。"]'),
('b5923def-1530-4663-930d-d879b6cf34ef','泊舟黄家渡','趙汝鐩','宋','宋诗','song-poetry','','[]','溪流暴漲舟如箭，夜向深灣穩處停。',64,'全唐诗/poet.song.187000.json','["溪流暴漲舟如箭，夜向深灣穩處停。", "猛虎嘯風威動壑，飛鴻過月影移汀。", "青山入夢催歸棹，白髮欺人嘆暮齡。", "幸得還家玩光景，歠醨終日醉休醒。"]'),
('b55a3930-cb35-4112-99d0-f0d081ef3f74','隴首','趙汝鐩','宋','宋诗','song-poetry','','[]','隴首多逢採桑女，荆釵蓬鬢短青裙。',64,'全唐诗/poet.song.187000.json','["隴首多逢採桑女，荆釵蓬鬢短青裙。", "齋鍾斷寺雞鳴午，吟杖穿山犬吠雲。", "避石牛從斜路轉，作陂水自半溪分。", "農家說縣催科急，留我茅簷看引文。"]'),
('2051e4d8-00b5-4a02-94bb-84938377f645','社日','趙汝鐩','宋','宋诗','song-poetry','','[]','四郊社鼓響楓林，朝雨方晴晚復陰。',64,'全唐诗/poet.song.187000.json','["四郊社鼓響楓林，朝雨方晴晚復陰。", "稚子求聰多啖藕，佳人怕拙例停針。", "飯爭簇巧毋嫌雜，酒正逢時莫厭斟。", "爲問年年鴻與燕，去來相避果何心。"]'),
('46be4f7d-0026-4828-864a-0c8d9ed90ec8','遊目','趙汝鐩','宋','宋诗','song-poetry','','[]','遊目林坰信馬蹄，十來家住小橋西。',64,'全唐诗/poet.song.187000.json','["遊目林坰信馬蹄，十來家住小橋西。", "浮沉野水看晴鴈，唱和茅簷聽午雞。", "菜要遮欄增舊塹，田分蔭注作新隄。", "年豐米賤人人樂，農父相逢醉似泥。"]'),
('2048b426-d170-4146-b48d-8e5aaa6ce888','莊家','趙汝鐩','宋','宋诗','song-poetry','','[]','半掩柴門傍淺池，茅茨夾柳閙黄鸝。',64,'全唐诗/poet.song.187000.json','["半掩柴門傍淺池，茅茨夾柳閙黄鸝。", "舊倉坼去安新囤，新篠添來補舊籬。", "煎茗吹爐呼幼婦，持箕掃地命童兒。", "莊家無可將勤意，數片親舂糯米飺。"]'),
('8333ab5c-15c1-42af-8c42-21cc2aad2633','登樓野望','趙汝鐩','宋','宋诗','song-poetry','','[]','雲藏日影微吞吐，道是晴來又似陰。',64,'全唐诗/poet.song.187000.json','["雲藏日影微吞吐，道是晴來又似陰。", "秋色涵空醒醉眼，鴈聲到耳引歸心。", "暴流决岸危橋斷，古木堆煙遠寺深。", "自料短才無用處，任緣不復覓知音。"]'),
('b097783f-fedf-47e5-8bee-110a89cf8f12','題會稽用林帥侍韵','趙汝鐩','宋','宋诗','song-poetry','','[]','東越乾坤到眼邊，亂雲連壑草迷川。',64,'全唐诗/poet.song.187000.json','["東越乾坤到眼邊，亂雲連壑草迷川。", "五更城落千巖月，萬頃湖開一鏡天。", "鼓角聲殘秦望曉，樓臺影濕卧龍煙。", "舊時太史登臨處，每想風流爲慨然。"]'),
('2d9c6c5a-ee2a-41a6-b8db-fdca90337357','孫王渡','趙汝鐩','宋','宋诗','song-poetry','','[]','霽後泥途行尚艱，今年大率是晴慳。',64,'全唐诗/poet.song.187000.json','["霽後泥途行尚艱，今年大率是晴慳。", "春當濃處寒猶在，寒肯消時春漸還。", "木杪紅沉半輪日，波心碧浸兩邊山。", "渡頭不住人來往，共羨白鷗雲水閑。"]'),
('bd95dfdf-5758-477e-93f0-3647a0d2c70c','胡教醵杯觀畫圍棋','趙汝鐩','宋','宋诗','song-poetry','','[]','山餚野蔌且隨宜，約定同來最怕遲。',64,'全唐诗/poet.song.187000.json','["山餚野蔌且隨宜，約定同來最怕遲。", "朋友每思相聚樂，塵埃難得有閑時。", "春回畫筆丹青軸，雹落文楸黑白棋。", "醉客坐間誇俊逸，掀髯連寫數篇詩。"]'),
('1f06ff7f-fe20-48aa-8af2-bfb259f666e6','汪丞招飲問梅','趙汝鐩','宋','宋诗','song-poetry','','[]','把酒問梅開也未，巡簷搜見兩三枝。',64,'全唐诗/poet.song.187000.json','["把酒問梅開也未，巡簷搜見兩三枝。", "祇緣今歲寒差甚，故比常年花較遲。", "折向紛華筵畔看，輸他冷淡水邊時。", "含香嚼蘂清無奈，散入肝脾盡是詩。"]'),
('745c4614-b9ff-4575-b6b9-865d6674b096','沿檄宿虎山山家','趙汝鐩','宋','宋诗','song-poetry','','[]','高低田水曲通池，小小人家短短籬。',64,'全唐诗/poet.song.187000.json','["高低田水曲通池，小小人家短短籬。", "杜宇教唆春去早，陰雲遮蓋月明遲。", "年華只解催教老，公事從來了是癡。", "若不隨緣强煩惱，謾添兩鬢幾莖絲。"]'),
('ee98815d-7a66-412e-ba8c-a0f326147578','題萊公泉','趙汝鐩','宋','宋诗','song-poetry','','[]','馬鞍山下倚吟鞭，慨想前賢古道邊。',64,'全唐诗/poet.song.187000.json','["馬鞍山下倚吟鞭，慨想前賢古道邊。", "健筆南軒三大字，高風相國一泓泉。", "征途著句雖無暇，詩版留名自可傳。", "寺主相邀觀石刻，呼童汲水取茶煎。"]'),
('5bcae3c8-155c-48ef-bd0d-8df7b515b8bf','題戴洪甫愛竹軒','趙汝鐩','宋','宋诗','song-poetry','','[]','竹癖難憑俗眼看，琴書靜對翠光寒。',64,'全唐诗/poet.song.187000.json','["竹癖難憑俗眼看，琴書靜對翠光寒。", "秋聲鳴屋風初度，夜影翻牀月半殘。", "天乞幽人供嗜好，日呼稚子報平安。", "窗前幸有閑田地，分我雲梢四五竿。"]'),
('0139a468-c02f-4d5a-ad44-e5e1600f5077','田家嘆','趙汝鐩','宋','宋诗','song-poetry','','[]','破屋三間結草扉，柴根煨火闔家圍。',64,'全唐诗/poet.song.187000.json','["破屋三間結草扉，柴根煨火闔家圍。", "此生能得幾年活，薄命連遭兩歲饑。", "腸久鳴雷惟淡粥，體雖起粟尚單衣。", "晚來稚子總歡喜，報道小姑挑菜歸。"]'),
('64972200-143f-4ddf-86c1-ec0d2b620ff9','途中','趙汝鐩','宋','宋诗','song-poetry','','[]','雨中奔走十來程，風卷雲開陡頓晴。',64,'全唐诗/poet.song.187000.json','["雨中奔走十來程，風卷雲開陡頓晴。", "雙燕引雛花下教，一鳩喚婦樹梢鳴。", "煙江遠認帆檣影，山舍微聞機杼聲。", "最愛水邊數株柳，翠條濃處兩三鶑。"]'),
('090cddc5-902d-4687-842c-08c67ca90ced','和林守玉茗花韵','趙汝鐩','宋','宋诗','song-poetry','','[]','園名金柅多奇卉，古幹靈根獨異常。',64,'全唐诗/poet.song.187000.json','["園名金柅多奇卉，古幹靈根獨異常。", "耻與春花爭俗艷，故將雪質對韶光。", "天葩巧削崑山片，露蘂疑含建水香。", "當爲君侯好封植，角弓三嘆誓無忘。"]'),
('67c63a95-bec6-4dc4-8f3d-493cae1883ab','雪後徐廣文招同官小集分韵得明字','趙汝鐩','宋','宋诗','song-poetry','','[]','瞰江亭館約登臨，雪後憑欄景倍清。',64,'全唐诗/poet.song.187000.json','["瞰江亭館約登臨，雪後憑欄景倍清。", "波面玉虹千丈霽，寒邊冰鏡十分明。", "放懷共恨添杯少，分韵俄驚擊鉢成。", "對弈不知誰勝敗，醉中但聽子丁丁。"]'),
('d336d507-cf0f-48f8-a3c3-b2692101dfaa','杜鵑','趙汝鐩','宋','宋诗','song-poetry','','[]','纔聽今春第一啼，如何便道不如歸。',64,'全唐诗/poet.song.187000.json','["纔聽今春第一啼，如何便道不如歸。", "聲穿窗隙驚閨夢，血溜花梢濺客衣。", "叫斷寸腸誰接續，懶隨羣翼戀芳菲。", "田園荒盡腰猶折，我亦因君覺昨非。"]'),
('378677c3-796d-4567-ace0-a794c3013697','史鎮江丐祠得請仍進職  其一','趙汝鐩','宋','宋诗','song-poetry','','[]','兩載南徐屈從臣，笑談樽俎運精神。',64,'全唐诗/poet.song.187000.json','["兩載南徐屈從臣，笑談樽俎運精神。", "民無土木絲毫費，手挈江山表裏新。", "千里舳艫渠水利，一團錦繡閬風春。", "夾河柳接甘棠影，下有攀轅卧轍人。"]'),
('426f93a8-2994-4763-bab4-f6fbddff1435','史鎮江丐祠得請仍進職  其二','趙汝鐩','宋','宋诗','song-poetry','','[]','帝念承流欲報功，力祈閶闔請琳宮。',64,'全唐诗/poet.song.187000.json','["帝念承流欲報功，力祈閶闔請琳宮。", "固知槐鼎身將近，却愛蓴鱸味不同。", "寶閣風雲雖學士，滄洲煙雨且漁翁。", "到家宣室思前席，又使猿驚蕙帳空。"]'),
('d1d91c2f-661c-423e-8436-c500c4b7a641','郴州鹿鳴宴','趙汝鐩','宋','宋诗','song-poetry','','[]','連科已占十名前，行聽鴻臚第一傳。',64,'全唐诗/poet.song.187000.json','["連科已占十名前，行聽鴻臚第一傳。", "我俟合符留勸駕，君能摛藻預興賢。", "湘山點化名千佛，郴嶺飛昇傚九仙。", "此去瓊林天上宴，今朝先賦鹿鳴篇。"]'),
('0b05b4a9-0342-473e-8f6b-8d1bf516cd85','次韵袁州鄭守鹿鳴宴','趙汝鐩','宋','宋诗','song-poetry','','[]','詔增貢籍自端平，大比賢書拔衆英。',64,'全唐诗/poet.song.187000.json','["詔增貢籍自端平，大比賢書拔衆英。", "學備六經俱里選，賦推五色以文鳴。", "雖由黄卷能勤苦，皆藉朱轓與作成。", "來歲錦標先奪得，天街聽喝狀元聲。"]'),
('d963c7c9-0f82-4205-8c79-de3a9e603d5e','宿江閣','趙汝鐩','宋','宋诗','song-poetry','','[]','閣前眼界如圖畫，山色侵窗竹打簷。',64,'全唐诗/poet.song.187000.json','["閣前眼界如圖畫，山色侵窗竹打簷。", "雲带鴈聲移別浦，月將梅影進疎簾。", "壯懷自笑年年減，華髮無情日日添。", "夜半驟風天驟雪，貴家鼓舞客心嫌。"]'),
('c0a99390-01c9-496a-b22c-b527771e90df','久客寫懷','趙汝鐩','宋','宋诗','song-poetry','','[]','一身千里嘆飄零，鬢影蕭疎已半星。',64,'全唐诗/poet.song.187000.json','["一身千里嘆飄零，鬢影蕭疎已半星。", "雲鴈叫愁欄獨倚，秋風吹面酒初醒。", "塵埃南北何曾歇，日月東西不暫停。", "昏暮誰家數聲笛，含悽噴怨要人聽。"]'),
('82ba6c33-6301-46a7-a7f2-7058eb5f2b3b','清明日同傅元瞻閻才元周濟美曾原伯宇文子友宇文子英汪沖之王謙仲集櫻朱園分韵得食字二十韵','趙汝鐩','宋','宋诗','song-poetry','','[]','宦情隨推移，世事分限域。',240,'全唐诗/poet.song.187000.json','["宦情隨推移，世事分限域。", "帝城冠蓋會，千里或咫尺。", "賞僚盡英賢，了事即餘日。", "念我契闊情，招邀見懷憶。", "春事日光輝，湖山好顔色。", "徐行失前騎，可望不可即。", "徜徉大堤上，徙倚長橋側。", "游龍䀭生花，意極反寥闃。", "山房啟煙扉，僧話寄禪寂。", "同來妙人物，高論傾歷歷。", "朋簪忽逢會，並轡隨休適。", "將軍萬金園，花竹照燕席。", "高情發清曠，絕巘疲危陟。", "俯視天壤間，錦繡蒙山澤。", "太平豈無象，黔首何知德。", "須臾碧雲暮，過羽杯行疾。", "投林暝鴉還，隔浦燈火濕。", "呼車各零亂，紅燭明青壁。", "良辰尚多歡，整整三分一。", "後會儻相從，前言未應食。"]'),
('1d1910ec-b12d-4916-890e-484c4c39144e','訪鄭隠君不遇','趙汝鐩','宋','宋诗','song-poetry','','[]','行盡櫪林村，柴門閉夕曛。',48,'全唐诗/poet.song.187000.json','["行盡櫪林村，柴門閉夕曛。", "自來松下坐，閒想壁間文。", "守樹猿偷果，窺山犬吠雲。", "多應尋鶴去，祇隔暮溪濆。"]'),
('e3aa5af0-1b65-410a-81b7-459ee910767e','流杯池','趙汝鐩','宋','宋诗','song-poetry','','[]','分得蘭亭勝，今才二十年。',48,'全唐诗/poet.song.187000.json','["分得蘭亭勝，今才二十年。", "飛觴流石罅，曲水出天然。", "古意欠修竹，清香足舊蓮。", "嶙峋裂奇怪，兩獸卧山邊。"]'),
('7a49148b-d079-4a7d-991a-5abb50f7298e','句  其一','趙汝鐩','宋','宋诗','song-poetry','','[]','巧須出大造，清欲與秋爭。',12,'全唐诗/poet.song.187000.json','["巧須出大造，清欲與秋爭。"]'),
('c6b01324-d050-4a30-a486-a5d8ed3feeb9','句  其二','趙汝鐩','宋','宋诗','song-poetry','','[]','鳥殘桃見核，蟲蠹葉留痕。',12,'全唐诗/poet.song.187000.json','["鳥殘桃見核，蟲蠹葉留痕。"]'),
('ffc58444-7d21-42d6-b8ff-da8e8202802c','句  其三','趙汝鐩','宋','宋诗','song-poetry','','[]','涇有泉流安得暑，亭因風掃自無塵。',16,'全唐诗/poet.song.187000.json','["涇有泉流安得暑，亭因風掃自無塵。"]'),
('edcf34ce-8639-4286-bc18-2fd294dd2bd6','句  其四','趙汝鐩','宋','宋诗','song-poetry','','[]','鋤草就平眠鹿地，芟松勿損掛猿枝。',16,'全唐诗/poet.song.187000.json','["鋤草就平眠鹿地，芟松勿損掛猿枝。"]'),
('37037d1d-f8ff-4c19-bcbd-b80cf6e619b8','詩二首  其一','趙汝域','宋','宋诗','song-poetry','','[]','醉夢騰騰聽打衙，三年踪跡類瓠瓜。',32,'全唐诗/poet.song.187000.json','["醉夢騰騰聽打衙，三年踪跡類瓠瓜。", "如今不似穿雲子，一鉢隨身到處家。"]'),
('0c7fe891-27f3-4d60-8eb8-71e003348adc','詩二首  其二','趙汝域','宋','宋诗','song-poetry','','[]','數葉梧桐落短廊，一泓秋水湛銀塘。',64,'全唐诗/poet.song.187000.json','["數葉梧桐落短廊，一泓秋水湛銀塘。", "調琴獨奏猗蘭操，啜茗清飄茉莉香。", "涕泣兩年同賈傅，癡夢千載笑君房。", "於今不作武寧客，簑笠漁竿日月長。"]'),
('77a751bc-a246-4633-8ef1-405b49404dba','題栽梅桃','趙汝域','宋','宋诗','song-poetry','','[]','梅花開盡桃花開，兩朵春移小院栽。',32,'全唐诗/poet.song.187000.json','["梅花開盡桃花開，兩朵春移小院栽。", "索笑索吟殊未已，渾渾疑是故人來。"]'),
('45281bea-54db-4768-827c-8a58b8205dce','契友夜酌聯句','趙汝域','宋','宋诗','song-poetry','','[]','銀燭清談久，鄉情異路真。',48,'全唐诗/poet.song.187000.json','["銀燭清談久，鄉情異路真。", "醉能忘世故，狂欲靜風塵。", "細踏梅花月，長謳栗里春。", "不知時節換，詩句得來新。"]'),
('b61ec528-9391-47b5-a3a4-04d8bd1d28d4','落梅','鄭性之','宋','宋诗','song-poetry','','[]','夜來幾陣隔窗風，便恐明朝已掃空。',32,'全唐诗/poet.song.187000.json','["夜來幾陣隔窗風，便恐明朝已掃空。", "點在青苔真可惜，不如吹入酒杯中。"]'),
('b13baeb9-9f13-449d-87c5-ea9798641f61','梅花','鄭性之','宋','宋诗','song-poetry','','[]','先生多在山中宿，爲愛橫斜影上窗。',64,'全唐诗/poet.song.187000.json','["先生多在山中宿，爲愛橫斜影上窗。", "茁髮僧從深澗徙，赬肩奴過別峰扛。", "和羹宰相調金鼎，止渴將軍擁碧幢。", "空谷不知如許艷，沽來村酒且開缸。"]'),
('f64756a0-82ef-4ea1-96a8-ded4ec16a789','南枝開北枝未開','鄭性之','宋','宋诗','song-poetry','','[]','山北雲衣裹萼紅，山南莫恨雪乘風。',64,'全唐诗/poet.song.187000.json','["山北雲衣裹萼紅，山南莫恨雪乘風。", "眼前開謝人心別，醉裏吟哦我輩同。", "春意收香歸鼎實，月梢留影印階空。", "諸君行試調羹手，來歲花邊獨釣翁。"]'),
('e308e2c4-34c1-4b1f-8337-b5b636b9daab','恩波橋','陳延齡','宋','宋诗','song-poetry','','[]','富春勝趣景一幅，四面好山青簇簇。',160,'全唐诗/poet.song.187000.json','["富春勝趣景一幅，四面好山青簇簇。", "浙江逶迤向東來，千里平鋪鴨頭綠。", "老夫作官從此遊，恩波閣道如虹浮。", "凭欄夜半玩星斗，會稽分夜天南頭。", "是時萬籟寂不作，惟見翺翔雙白鶴。", "赤松正與董雙成，坐駕雲軿窮碧落。", "素娥海上來相迎，玉笙度曲鸞鳳鳴。", "商音嫋嫋洗人耳，驚起葛翁仙夢醒。", "走着氅衣忙草草，開門誤踢神爐倒。", "丹光飛起掩月明，虎嘯龍吟天地老。"]'),
('74e27530-66fc-4435-95dd-dcb59c17e576','浮覺院竹軒','陳延齡','宋','宋诗','song-poetry','','[]','山僧種竹數千個，堂戶清陰日日濃。',64,'全唐诗/poet.song.187000.json','["山僧種竹數千個，堂戶清陰日日濃。", "從便寄棲天外鳳，等閒夢化缽中龍。", "護餘貝葉雲無跡，刺破苔痕石有蹤。", "老去要盟蓮社約，一枝携取策龍鍾。"]'),
('d9a7b3c0-632c-4da7-b551-4fab65ae27b1','普明院','陳延齡','宋','宋诗','song-poetry','','[]','普明禪寺隠巖坰，狂客重來酒未醒。',64,'全唐诗/poet.song.187000.json','["普明禪寺隠巖坰，狂客重來酒未醒。", "雲氣竟拖龍尾白，山容盡比佛頭青。", "松林深處誰家屋，村墅斜陽若個亭。", "莫問笑談歸去晚，有詩留與赤松聽。"]'),
('9a73e155-9220-497c-88ed-dea63fb0fc39','丹霞觀','陳延齡','宋','宋诗','song-poetry','','[]','蒼筤林深羽人觀，正傍嚴陵舊釣臺。',64,'全唐诗/poet.song.187000.json','["蒼筤林深羽人觀，正傍嚴陵舊釣臺。", "山中白雲夜或起，洞口丹霞晝不開。", "雙成吹笛駕鸞下，葛翁擲杖爲龍來。", "仙風道骨我亦有，姹女嬰兒君可猜。"]'),
('01d765d7-3910-41bb-8769-338fe8bf74e6','大安院','陳延齡','宋','宋诗','song-poetry','','[]','詩人假榻古蘭若，松風澗水相泠泠。',64,'全唐诗/poet.song.187000.json','["詩人假榻古蘭若，松風澗水相泠泠。", "優婆塞傾椰子酒，須菩提講蓮花經。", "龍形老樹雨知翠，佛頭高山雲見青。", "借問仙人渺何許，飛昇一去三千齡。"]'),
('f5e0779c-66e1-4738-a4ee-919e7144222b','禱雨作  其一','高定子','宋','宋诗','song-poetry','','[]','牽絲晨謁玉皇家，喚起慵龍乞井花。',32,'全唐诗/poet.song.187000.json','["牽絲晨謁玉皇家，喚起慵龍乞井花。", "醒看滿山枝葉語，晚唐句子是萌芽。"]'),
('f7ab8c16-03b9-4d77-82b0-4233764c1225','禱雨作  其二','高定子','宋','宋诗','song-poetry','','[]','詩到眉山自一家，也將正命攝於邪。',32,'全唐诗/poet.song.187000.json','["詩到眉山自一家，也將正命攝於邪。", "巧裁大滌天成景，戲詠庭蛟與洞鴉。"]'),
('334db1bc-fc32-4c23-b49b-8b288161c84f','禱雨作  其三','高定子','宋','宋诗','song-poetry','','[]','兩閒灑落無塵著，萬象森羅觸處逢。',32,'全唐诗/poet.song.187000.json','["兩閒灑落無塵著，萬象森羅觸處逢。", "此意要令兒輩覺，擎天一柱愛中峰。"]'),
('2a133688-e851-4413-87bb-39a6f6c98ef3','句','高伯易','宋','宋诗','song-poetry','','[]','函顱謹勿爲終策，天下英雄暗破顔。',16,'全唐诗/poet.song.187000.json','["函顱謹勿爲終策，天下英雄暗破顔。"]'),
('a01e5c9b-b5d6-4d4c-a285-c80cb507cfea','句  其一','高載','宋','宋诗','song-poetry','','[]','擬約滄江異姓兄。',8,'全唐诗/poet.song.187000.json','["擬約滄江異姓兄。"]'),
('e59e38e2-6995-449b-b65e-3c68fab13ff7','句  其二','高載','宋','宋诗','song-poetry','','[]','自是去凶明國是，毋輕函首啟戎姦。',16,'全唐诗/poet.song.187000.json','["自是去凶明國是，毋輕函首啟戎姦。"]'),
('de58735e-050b-4bba-ae46-f9f2fcd87704','梅雪堂','盧孝孫','宋','宋诗','song-poetry','','[]','玄冬雪霰零，寒梅吐花白。',60,'全唐诗/poet.song.187000.json','["玄冬雪霰零，寒梅吐花白。", "皎皎冰玉姿，六出同一色。", "佳士開幽軒，於此心境悅。", "味澹志愈堅，冰霜勵高節。", "永言貞素心，千載共孤潔。"]'),
('14e6a4b7-d915-41da-aa34-bec68b6d741f','題畫竹石','張翼','宋','宋诗','song-poetry','','[]','嗟彼鳳去，空餘虎蹲。',20,'全唐诗/poet.song.187000.json','["嗟彼鳳去，空餘虎蹲。", "竹不可食，石不能言。"]'),
('e5a19c46-d37d-4fa8-bf09-ddff346d0089','百花巖','吳馹','宋','宋诗','song-poetry','','[]','靈巖競吐秀，百卉四時開。',24,'全唐诗/poet.song.187000.json','["靈巖競吐秀，百卉四時開。", "不假栽培力，天然錦繡堆。"]'),
('a9eddbb3-1fe4-4110-8d9e-c17c1dbd6cc3','登中梁山  其一','李儒用','宋','宋诗','song-poetry','','[]','浩蕩秋風使節歸，南山重與北山違。',64,'全唐诗/poet.song.187000.json','["浩蕩秋風使節歸，南山重與北山違。", "自來人物瞻烏帽，更共賓僚款綠衣。", "秦地關河纔咫尺，漢都風景尚依稀。", "壺漿迎處多遺老，絕歎登壇往事非。"]'),
('d794e584-ab58-47dd-a3ee-8ebd01bef963','登中梁山  其二','李儒用','宋','宋诗','song-poetry','','[]','路入梁州如砥平，登高遠目更增明。',64,'全唐诗/poet.song.187000.json','["路入梁州如砥平，登高遠目更增明。", "霜清木落千山瘦，潦盡江空一水橫。", "歲穩未寬憂國志，時危轉切望鄉情。", "英雄千載興王地，孺子堪憐此曳兵。"]'),
('7b07f03a-f035-4ab7-91e4-4d703011c684','題左翰林三友亭','黄棨','宋','宋诗','song-poetry','','[]','勁節虬枝水月香，軒前高坐勝尋常。',32,'全唐诗/poet.song.187000.json','["勁節虬枝水月香，軒前高坐勝尋常。", "翰林此意知非淺，曾有堅心秉雪霜。"]'),
('caea6d93-3beb-44fa-9f37-ed4613dd262e','過安仁','黄鑑','宋','宋诗','song-poetry','','[]','早發磐溪挂短篷，朔風吹雨曉濛濛。',64,'全唐诗/poet.song.187000.json','["早發磐溪挂短篷，朔風吹雨曉濛濛。", "潤含野色沾衣濕，暖逐春光養土融。", "圖畫宛然山遠近，人家對住水西東。", "驛亭記得停車處，楓樹曾連夕照紅。"]'),
('f5e8615f-83c3-43c2-a039-2f34c302c04d','壽趙仙尉','阮文卿','宋','宋诗','song-poetry','','[]','君不見苕溪有山號浮玉，降神儲瑞皆天族。',358,'全唐诗/poet.song.187000.json','["君不見苕溪有山號浮玉，降神儲瑞皆天族。", "又不見苕溪有水名水晶，地靈人傑盡維城。", "苕溪山川稱第一，孕秀梅仙尤傑出。", "我來席上揖清風，義氣相與吞長虹。", "見人須見大丈夫，縱是封侯亦不如。", "周官一卷長生籙，未必人間有此書。", "功名一入英雄手，彩棒暫持出浙右。", "摧奸抉隠李開府，夜月花村無吠狗。", "凜凜英風凌四豪，一同誰敢犯秋毫。", "不惟握髮勤延士，又且官清馬骨高。", "書生慣作無氈客，負篋南歸居最仄。", "何憐蹤迹苦奔馳，俾近淵明時請益。", "馬走暫停憇縣齋，晨昏黄嬭仍相陪。", "不覘王母蟠桃結，隔牆無得獻金杯。", "欣逢子月陽來復，一天佳氣回寒谷。", "蓂生九葉慶垂弧，僉將瑞應長庚宿。", "綠衣槐簡舞蹁躚，重拜萱堂王母仙。", "瑶池新革偷桃令，有子今如曼倩賢。", "不祝算如龜與鶴，願君早施江夏略。", "掃除羶穢□神京，長與長生同壽樂。", "不祝祿如山與丘，願君爵冠朱虛侯。", "今歸且定郟鄏鼎，長使卜世過成周。"]'),
('42f04913-1d91-44d7-ba39-34a5f57a2fef','春暮','劉鎮','宋','宋诗','song-poetry','','[]','春至又春暮，閒心成古心。',48,'全唐诗/poet.song.187000.json','["春至又春暮，閒心成古心。", "花光隨雨薄，草色共烟深。", "粉蝶稀狂影，黄鸝送好音。", "餘芳留不得，還共夕陽沈。"]'),
('bd0ffde1-a5a0-4916-a126-ef8644a7c82d','山中早行','劉鎮','宋','宋诗','song-poetry','','[]','嚴鐘將報曙，游子已登途。',24,'全唐诗/poet.song.187000.json','["嚴鐘將報曙，游子已登途。", "野火時明滅，星殘似有無。"]'),
('f0087608-4504-442c-9531-3ccc57ddbc78','八歲女善棋','劉鎮','宋','宋诗','song-poetry','','[]','慧黠過男子，嬌癡語未真。',48,'全唐诗/poet.song.187000.json','["慧黠過男子，嬌癡語未真。", "無心防敵手，有意惱詩人。", "得路逢師笑，輸機怕父嗔。", "汝還知世事，一局一回新。"]'),
('c874d4c8-a308-46ed-b1d0-e95e22bb8301','贈隠者','劉鎮','宋','宋诗','song-poetry','','[]','夫子生東野，經年不到城。',48,'全唐诗/poet.song.187000.json','["夫子生東野，經年不到城。", "愛吟無俗趣，貪畫得閒名。", "荒徑侵山影，虛堂出燕聲。", "我慚爲謫吏，泉石負幽情。"]'),
('121121d6-1f5e-4b0e-9e45-b2d103bac55e','太姥山','劉鎮','宋','宋诗','song-poetry','','[]','滾滾千山入馬蹄，出遊回首日平西。',64,'全唐诗/poet.song.187000.json','["滾滾千山入馬蹄，出遊回首日平西。", "人從杜宇鳴時別，天向蒹葭靜處低。", "白鳥得魚閒釣艇，黄蜂抱蘂閙花枝。", "好將太姥山前路，付與孤猿自在啼。"]'),
('27f2f459-75fc-4ad6-8b95-d1c7e6697c21','嚴子陵釣臺','劉鎮','宋','宋诗','song-poetry','','[]','漢業重恢百戰閒，君王側席歎才難。',32,'全唐诗/poet.song.187000.json','["漢業重恢百戰閒，君王側席歎才難。", "故人可是擎天手，肯放桐江把釣竿。"]'),
('dfc74b78-d171-4018-a164-97e09175ade7','浮膺山','劉鎮','宋','宋诗','song-poetry','','[]','馬頭過了又馿頭，何處飛來海上洲。',32,'全唐诗/poet.song.187000.json','["馬頭過了又馿頭，何處飛來海上洲。", "絕頂試窮千里目，烟波深處是琉球。"]'),
('0a33ffa9-52a6-4410-83b1-2e13586da758','句','劉鎮','宋','宋诗','song-poetry','','[]','始終無玷缺，出處最光明。',12,'全唐诗/poet.song.187000.json','["始終無玷缺，出處最光明。"]'),
('e8640175-6878-445f-a81c-8c94faf4a37a','李侍郎修路','陳褎','宋','宋诗','song-poetry','','[]','路餘百里兩山間，水驛山程總不安。',64,'全唐诗/poet.song.187000.json','["路餘百里兩山間，水驛山程總不安。", "誰把千金平滑蹬，免教一葉委驚灘。", "行人感歎何時已，賢守功名百世看。", "次第吾閩都似掌，却嗤蜀道號泥盤。"]'),
('ae10ff52-46f2-4643-ac07-2603634c401f','瑪瑙寶勝寺','陳俞','宋','宋诗','song-poetry','','[]','雨霽佛屋明，苔逕深曲折。',48,'全唐诗/poet.song.187000.json','["雨霽佛屋明，苔逕深曲折。", "樹摇高露驚，草密暗泉咽。", "前林忽清磬，煙燈遠欲滅。", "寄謝塵中人，與君從此別。"]'),
('58bec2af-84c0-4688-9a77-1e368f3fd0ed','雨後過瑪瑙寺','陳俞','宋','宋诗','song-poetry','','[]','借屋傍精廬，無事數來往。',48,'全唐诗/poet.song.187000.json','["借屋傍精廬，無事數來往。", "披草通泉流，刻樹記筍長。", "微風四山落，小立領松響。", "詎名息諸緣，暫喜脫塵網。"]'),
('6ea706d9-2e86-4b24-b5e9-1de88476e51d','重遊','陳俞','宋','宋诗','song-poetry','','[]','覺聞浴鼓聲，衆散我徐赴。',48,'全唐诗/poet.song.187000.json','["覺聞浴鼓聲，衆散我徐赴。", "石槽溫泉涌，赤脚躡雲霧。", "振衣新筍林，岸幘古松樹。", "脫然得輕安，水因本無悟。"]'),
('8de1194f-018b-4fd6-b6a0-bf56e49479cc','午睡瑪瑙起赴壽星浴','陳俞','宋','宋诗','song-poetry','','[]','達人心鏡明，直道略委折。',48,'全唐诗/poet.song.187000.json','["達人心鏡明，直道略委折。", "重來犬不驚，到家蟬聲咽。", "君吟有造化，我唱無生滅。", "法界即大都，山川幾回別。"]'),
('59884c70-547c-4798-8f5d-9c61a13c8d2e','贈畫魚賈兄','陳俞','宋','宋诗','song-poetry','','[]','春江浩蕩春江闊，夜半湖聲湧新沫。',224,'全唐诗/poet.song.187000.json','["春江浩蕩春江闊，夜半湖聲湧新沫。", "曉風吹斷碧雲根，萬頃滄波带晴豁。", "浪花瀲灩翻紅桃，群魚出沒乘輕濤。", "悠揚得意鼓鱗鬣，十十五五同爲曹。", "昔曾觀瀾知此意，真樂胸中渺無際。", "常嗟物理難形容，幸有賈君得精藝。", "巨魚奮迅凌江湖，纖鱗錯雜依菰蒲。", "精神萬狀幻新筆，巧與造化論錙銖。", "朅來過我示奇作，數幅生綃圖縱壑。", "呼童展向虛堂中，恍若當年見魚樂。", "如君畫思幾通神，眼高世俗空無人。", "石臺去後今幾載，毫端彷彿留芳塵。", "又宜學取洞清拔，寫龍不寫潛波鮪。", "徒能畫魚不畫龍，空使饞夫吐饞水。"]'),
('0c015747-5839-496b-9156-937926972496','訪僧歸雲菴','陶崇','宋','宋诗','song-poetry','','[]','閒過選佛場，歸雲翠如潑。',108,'全唐诗/poet.song.187000.json','["閒過選佛場，歸雲翠如潑。", "入門偶有言，啟頰師便喝。", "掩耳煨芋爐，但把火深撥。", "呼童酌玉虹，注之旃檀鉢。", "噓灰然微紅，橫鐺水煎活。", "茶酣登甲亭，雙眸爲之豁。", "鳥啼空山幽，翔來集木末。", "風月一何佳，團圞共披抹。", "悠然澹忘歸，于茲得解脫。"]'),
('7d3386f6-f818-4481-91d5-0aa27878dae5','筆山','陶崇','宋','宋诗','song-poetry','','[]','晚來設色霞成綺，秋至回文鴈作行。',32,'全唐诗/poet.song.187000.json','["晚來設色霞成綺，秋至回文鴈作行。", "借問墨池何處是，一江環遶潄琳琅。"]'),
('aa048a7c-9027-4f10-b872-86737a2b2b20','遊都梁賦','沈誠','宋','宋诗','song-poetry','','[]','昔中原兮今邊頭，抱良圖兮氣干牛。',32,'全唐诗/poet.song.187000.json','["昔中原兮今邊頭，抱良圖兮氣干牛。", "窺泗城兮辨古汴，臨清浦兮思白溝。"]'),
('e323132d-83f2-44f6-bddd-1c7fb300bde2','句','楊昕','宋','宋诗','song-poetry','','[]','二八玉泉分派泠，三千銀界出塵清。',16,'全唐诗/poet.song.187000.json','["二八玉泉分派泠，三千銀界出塵清。"]'),
('40fe8895-c2bb-4111-85bd-5f8ded5b80b7','三高祠  其一','劉寅','宋','宋诗','song-poetry','','[]','江流東去日滔滔，誰把功名等一毫。',32,'全唐诗/poet.song.187000.json','["江流東去日滔滔，誰把功名等一毫。", "若使今人同古調，不應江上只三高。"]'),
('e1dc1c75-c82f-4954-bd43-6514c1267fde','三高祠  其二','劉寅','宋','宋诗','song-poetry','','[]','人謂吳癡信不虛，建崇越相果何如。',32,'全唐诗/poet.song.187000.json','["人謂吳癡信不虛，建崇越相果何如。", "千年亡國無窮恨，只合江邊祀子胥。"]'),
('95707f94-2d7c-4273-bebf-20fb1c1f1e9f','題靈龜洞','張安修','宋','宋诗','song-poetry','','[]','何年六丁驅霹靂，蒼龍驚起穿崖石。',160,'全唐诗/poet.song.187000.json','["何年六丁驅霹靂，蒼龍驚起穿崖石。", "拏雷掣電卷波濤，來與真仙分窟宅。", "上崖窅深如側甕，下崖谽谺如空洞。", "不知泉脈從何來，百面鼙鼓長洶湧。", "大靈闖首浮中流，背隠八卦開雙眸。", "似聞夏潦不能沒，疑有神仙司諸幽。", "我曾雁蕩觀龍鼻，半日纔通涓滴水。", "豈如六月散甘霖，靈泉滾滾無窮已。", "惜哉埋沒荒煙中，車馬來稀三疊重。", "若教遺向飛來峰，龍井冷泉皆下風。"]'),
('ce4559c1-7b6a-46ce-845c-9e5277024be4','鳳凰臺','王遂','宋','宋诗','song-poetry','','[]','天連宮闕雲煙濕，地接淮山日月低。',32,'全唐诗/poet.song.187000.json','["天連宮闕雲煙濕，地接淮山日月低。", "不知何處兩黄鵠，飛向白雲雲外歸。"]'),
('0373e666-1565-4337-9692-986e08736310','中秋飲鳳凰臺上','王遂','宋','宋诗','song-poetry','','[]','天上十分月，人間一半秋。',48,'全唐诗/poet.song.187000.json','["天上十分月，人間一半秋。", "笙歌傳小寨，燈火認層樓。", "酒怕初斟滿，碁欣未了收。", "分明渾似水，只是欠雙鷗。"]'),
('3432681f-b89a-4601-801f-3d63c5fcbbfe','會平江兩倅六邑宰','王遂','宋','宋诗','song-poetry','','[]','守令張官本爲民，恫{疒眾}無異切吾身。',67,'全唐诗/poet.song.187000.json','["守令張官本爲民，恫{疒眾}無異切吾身。", "但令六縣皆朱邑，何必黄堂有信臣。", "田里要須興孝弟，閭閻謹勿致嚬呻。", "與君共舉一盃酒，化作人家點點春。"]'),
('2dbe1af1-80ef-4362-9737-d70ef878d3dc','謁梓潼廟訪黄蘗泉試茶','王遂','宋','宋诗','song-poetry','','[]','居然三伏景，宛若九秋凉。',48,'全唐诗/poet.song.187000.json','["居然三伏景，宛若九秋凉。", "蒼翠瞻神力，熉黄燭夜光。", "龍眠安舊隠，螢冷近書堂。", "不爲看黄蘗，吹來稻欲香。"]'),
('1c9c36d8-c96d-4ef9-893a-8184838ccbda','會徐侍郎蔡提舉','王遂','宋','宋诗','song-poetry','','[]','初度曾同歲攝提，德雖不競得年齊。',64,'全唐诗/poet.song.187000.json','["初度曾同歲攝提，德雖不競得年齊。", "徐卿鸞鳳今標準，蔡令壎箎舊品題。", "西府十連新眷遇，北園三徑共提携。", "丈夫出處無他願，但欲長歌歸去兮。"]'),
('2e2b0c20-7ea6-446a-a5bd-c94cda77edb3','順寧憶弟','王遂','宋','宋诗','song-poetry','','[]','猶憐膝下競兒嬉，歲月光陰去若馳。',32,'全唐诗/poet.song.187000.json','["猶憐膝下競兒嬉，歲月光陰去若馳。", "閑倚闌干思舊事，却如故老話淳熙。"]'),
('ac9f35f0-3e5a-4559-a10c-88086339fcb8','贈青陽士友','王遂','宋','宋诗','song-poetry','','[]','離紅百顆橘千頭，何似南枝雪未收。',64,'全唐诗/poet.song.187000.json','["離紅百顆橘千頭，何似南枝雪未收。", "國爲和羹思是晏，士因止渴憶興周。", "笑談谷口終當隠，出處胸中要熟籌。", "夜月九華浮動處，癡頑寧復照齋丘。"]'),
('726e1b84-b4c7-4b61-a8a4-418fcce3617e','贈薛道士','王遂','宋','宋诗','song-poetry','','[]','覿面逢幽侶，裝懷解吏紛。',144,'全唐诗/poet.song.187000.json','["覿面逢幽侶，裝懷解吏紛。", "曾敲筠戶月，屢宿柳塘雲。", "離索知餘恨，來過謝子勤。", "山中新雨足，幾處未耕耘。", "入道猶將母，人心信秉彜。", "每能圖樂事，誰與寫時思。", "欲覓徵君筆，難當幼婦辭。", "只應憂世切，聊此覺良知。", "周詩山寺滿，騎馬□中尋。", "淡泊人無識，吟嗟子獨深。", "動中觀造化，靜處養靈襟。", "且學渠根本，篇章莫費吟。"]'),
('0278136b-e7ec-411a-b5b0-0b8f0a005321','贈無夢道人','王遂','宋','宋诗','song-poetry','','[]','中人有夢君無夢，樂思幽懷事不同。',32,'全唐诗/poet.song.187000.json','["中人有夢君無夢，樂思幽懷事不同。", "爲問曲肱高卧日，如何合眼見周公。"]'),
('bae74704-6a50-4aa9-884f-166cd498dee2','贈陳師宓客陳兄','王遂','宋','宋诗','song-poetry','','[]','疾雷破柱識忠臣，急雨衝泥見故人。',32,'全唐诗/poet.song.187000.json','["疾雷破柱識忠臣，急雨衝泥見故人。", "斗酒爲澆新意氣，老夫筆底亦精神。"]'),
('e619333d-5ae8-402a-9867-827207e4e946','贈肖巖  其一','王遂','宋','宋诗','song-poetry','','[]','曾因肖象下箕星，夢寐猶應右武丁。',32,'全唐诗/poet.song.187000.json','["曾因肖象下箕星，夢寐猶應右武丁。", "顧我本非鍾鼎相，不應端笏侍天庭。"]'),
('cc2025e1-b426-4d67-963c-6859f164851a','贈肖巖  其二','王遂','宋','宋诗','song-poetry','','[]','居住梁谿古道傍，分明木石最堂堂。',32,'全唐诗/poet.song.187000.json','["居住梁谿古道傍，分明木石最堂堂。", "丹青能染成形貌，猶有心源未易量。"]'),
('65a090ee-1885-4a29-a98f-38b190e7eefa','贈肖巖  其三','王遂','宋','宋诗','song-poetry','','[]','强栽髭鬢較錙銖，眼底精神不解枯。',32,'全唐诗/poet.song.187000.json','["强栽髭鬢較錙銖，眼底精神不解枯。", "許我蒼顔殿諸老，可能同讀遠游無。"]'),
('730e5331-b3d6-457a-bec4-e20ddc5754a6','寄昭武諸友','王遂','宋','宋诗','song-poetry','','[]','荆州得士一人半，信矣苻堅取太多。',64,'全唐诗/poet.song.187000.json','["荆州得士一人半，信矣苻堅取太多。", "汗馬已先馳峻坂，冥鴻猶有避雲羅。", "本心皎日千年在，外物青天一鳥過。", "別後令名俱日起，倦予晞髮向山阿。"]'),
('efef7f30-9759-465e-80b0-55852a52abc4','寄聰自聞','王遂','宋','宋诗','song-poetry','','[]','參天定林木，無地妙高臺。',48,'全唐诗/poet.song.187000.json','["參天定林木，無地妙高臺。", "每憶金陵去，誰同玉局來。", "乾坤新潤澤，河洛久風埃。", "十里南州路，荷香獨棹回。"]'),
('cb988e46-d0d0-4aa1-bb7e-b79792feaa85','寄劉後村王臞軒','王遂','宋','宋诗','song-poetry','','[]','君子仁柔義也剛，須知自勝乃爲强。',64,'全唐诗/poet.song.187000.json','["君子仁柔義也剛，須知自勝乃爲强。", "書因雁斷疑天遠，詩带梅來特地香。", "一鶚先從雲外去，四鴻寧久橘中藏。", "聖朝出處非無意，衣錦何由戀故鄉。"]'),
('266fd09a-0373-4707-9756-44c2971c5af9','寄九江宗族','王遂','宋','宋诗','song-poetry','','[]','手劚三茅印月痕，却思廬麓接雲根。',64,'全唐诗/poet.song.187000.json','["手劚三茅印月痕，却思廬麓接雲根。", "便將百戰開勳業，何似丹心遺子孫。", "行盡義豐思古跡，舊曾敷淺出高原。", "因思百事俱閑外，惟有人間道最尊。"]'),
('bec0fc23-959d-4618-920f-196641814553','寄呈飯牛翁','王遂','宋','宋诗','song-poetry','','[]','早計關防意氣觕，莫教露盡草頭枯。',64,'全唐诗/poet.song.187000.json','["早計關防意氣觕，莫教露盡草頭枯。", "芒寒甯戚謳歌怨，色自涪翁牧養圖。", "露地相忘無踐稼，縣官雖巧不催租。", "時人欲識其中趣，山木巃嵷夜氣蘇。"]'),
('6989c565-b649-404d-8710-80a8d85a6a44','謝趙廬州送淮白  其一','王遂','宋','宋诗','song-poetry','','[]','淮源千古貫中州，南北分來九十秋。',32,'全唐诗/poet.song.187000.json','["淮源千古貫中州，南北分來九十秋。", "欲放此鱗歸縱壑，要留佳瑞入王舟。"]'),
('5889a8ca-11bb-415d-8e2d-fb557653aff5','謝趙廬州送淮白  其二','王遂','宋','宋诗','song-poetry','','[]','淮泗曾經禹决餘，斯民無復懼爲魚。',32,'全唐诗/poet.song.187000.json','["淮泗曾經禹决餘，斯民無復懼爲魚。", "魚枯却識江南岸，應有臨淵羨不如。"]'),
('d1062e37-0b03-4aff-82f2-e7006eec284e','謝二吳書見訪','王遂','宋','宋诗','song-poetry','','[]','緇衣之後賦無衣，王室安知晉鄭依。',64,'全唐诗/poet.song.187000.json','["緇衣之後賦無衣，王室安知晉鄭依。", "淝水八千思偃伯，丹徒十萬盡忘饑。", "喜看猿鶴從公樂，更覺蓴鱸到處肥。", "泉楮未通民力乏，夢懷遠志憶當歸。"]'),
('419566fb-10c9-4d7c-8880-97a5fe08d71e','以台柑寄漫塘報以詩用韵謝之','王遂','宋','宋诗','song-poetry','','[]','屈平作頌獨稱渠，曾比西山立懦夫。',32,'全唐诗/poet.song.187000.json','["屈平作頌獨稱渠，曾比西山立懦夫。", "君子得輿知有待，高林碩果未嘗無。"]'),
('821dc2a1-8e46-4e12-aefa-06a811d25c37','瑞香','王遂','宋','宋诗','song-poetry','','[]','曉見花開意味長，夜深放出紫荷囊。',32,'全唐诗/poet.song.187000.json','["曉見花開意味長，夜深放出紫荷囊。", "須知睡裏真香足，猶錫佳名號瑞香。"]'),
('09290325-0ee4-4432-96d9-e51f56acdc82','枕上聞鐘','王遂','宋','宋诗','song-poetry','','[]','南來聽是保寧鍾，鍾送風來風送鍾。',32,'全唐诗/poet.song.187000.json','["南來聽是保寧鍾，鍾送風來風送鍾。", "氣只與聲無間斷，此心何况與人同。"]'),
('392a7612-6ca7-42bd-b65b-3351bc5a381d','謝章季思惠鏡屏','王遂','宋','宋诗','song-poetry','','[]','客從東南西，遺我古鏡屏。',216,'全唐诗/poet.song.187000.json','["客從東南西，遺我古鏡屏。", "圓明絕點滓，表裏無遁形。", "云是舊太守，思之我爲銘。", "吾惛不能進，何敢陳諸庭。", "我聞生民初，五常具函靈。", "器質欠推廣，物欲加凋零。", "眉睫近莫睹，稍遠何能聽。", "君子抱明德，止善湛中扃。", "靜如晝有夜，動若渭流涇。", "坐令方寸地，目睫何晶熒。", "上天方於昭，皎彼垂日星。", "五官屬宰制，萬化隨指令。", "留之千百載，猶足存典刑。", "余心豈昧此，一念存芳馨。", "在昔聖敬主，丹書刻方欞。", "近者摩鏡帖，字字炳丹青。", "夫君往教意，大寐如得醒。", "置之敬義堂，與世猶說鈴。"]'),
('581b4da8-3c4d-48a7-b5f7-0e320820ece7','宛陵道院成用吳尚書韵  其一','王遂','宋','宋诗','song-poetry','','[]','儷然位望亞陪京，大作山川小作城。',64,'全唐诗/poet.song.187000.json','["儷然位望亞陪京，大作山川小作城。", "堡障百年寬北顧，耕桑千里慶西成。", "和風溫若生庭戶，明月飛來入棟楹。", "道院依然無一事，只須空洞養心誠。"]'),
('f90a43c2-0d69-47f7-9568-00ea792aba47','宛陵道院成用吳尚書韵  其二','王遂','宋','宋诗','song-poetry','','[]','傳街軋軋度車聲，夾道翩翩共雁行。',64,'全唐诗/poet.song.187000.json','["傳街軋軋度車聲，夾道翩翩共雁行。", "色養正須誇獨樂，真廉何得似雙清。", "便當坐進傳吾道，何必求爲身後名。", "大字已煩呵妙手，一犂依舊作勝氓。"]'),
('cf87ab31-0b80-41be-8719-0946858cd7f0','謁子真祠  其一','王遂','宋','宋诗','song-poetry','','[]','漢朝容默獨危言，吳市逃名耻自全。',32,'全唐诗/poet.song.187000.json','["漢朝容默獨危言，吳市逃名耻自全。", "千古無人知此意，浪將姓字作梅仙。"]'),
('d2a34355-4454-4570-888d-93e9e4282b24','謁子真祠  其二','王遂','宋','宋诗','song-poetry','','[]','梅山梅市梅家墺，總得嘉名爲子真。',32,'全唐诗/poet.song.187000.json','["梅山梅市梅家墺，總得嘉名爲子真。", "張禹孔光俱已矣，豈無遺跡但埃塵。"]'),
('451e4783-fbb2-4818-8523-73bf09ab0a20','吳大帝廟','王遂','宋','宋诗','song-poetry','','[]','曾是東南第一王，眼看此地六興亡。',64,'全唐诗/poet.song.187000.json','["曾是東南第一王，眼看此地六興亡。", "東緣有酒登京口，西爲無魚憶武昌。", "非復虎臣陪殿上，空餘猩鬼泣祠旁。", "何年並建琅玡廟，共對淮山草木長。"]'),
('801bf0f2-f0e2-49f3-8458-9f29d359b923','寧考神御奉安原廟  其一','王遂','宋','宋诗','song-poetry','','[]','經旬風雨陡新晴，一夜蟾光直到明。',32,'全唐诗/poet.song.187000.json','["經旬風雨陡新晴，一夜蟾光直到明。", "清曉衣冠原廟去，分明眷佑似平生。"]'),
('ed0e5b0e-e2f7-4c63-b260-4f9fd5197aff','寧考神御奉安原廟  其二','王遂','宋','宋诗','song-poetry','','[]','鹵簿蕭蕭鼓吹鳴，屬車前導乘輿輕。',32,'全唐诗/poet.song.187000.json','["鹵簿蕭蕭鼓吹鳴，屬車前導乘輿輕。", "□□殿裏朱門閟，無復傳呼輦路聲。"]'),
('cfb943d2-025b-4243-92c9-4f90f4acfe12','寧考神御奉安原廟  其三','王遂','宋','宋诗','song-poetry','','[]','太室祼將嚴體薦，景靈朝獻薦牙盤。',32,'全唐诗/poet.song.187000.json','["太室祼將嚴體薦，景靈朝獻薦牙盤。", "九重黼坐盤盂固，四海蒼生奠枕安。"]'),
('50d34fb6-c3bf-4215-a5ee-d85ebf66ec50','寧考神御奉安原廟  其四','王遂','宋','宋诗','song-poetry','','[]','儉慈三十一年主，已不自知其至尊。',32,'全唐诗/poet.song.187000.json','["儉慈三十一年主，已不自知其至尊。", "時向道傍逢故老，但能垂淚不能言。"]'),
('b6f1b1cd-aef2-45a5-8f9c-8bc52b292993','寧考神御奉安原廟  其五','王遂','宋','宋诗','song-poetry','','[]','禁殿薰風傳賜敕，宮門曉日緩催班。',32,'全唐诗/poet.song.187000.json','["禁殿薰風傳賜敕，宮門曉日緩催班。", "小臣未報君恩重，耿耿孤君入夢間。"]'),
('41556ab0-663e-4fe8-91dd-d28a2a1e216e','道上','王遂','宋','宋诗','song-poetry','','[]','夾道香煙笑語歡，老翁扶立小兒觀。',32,'全唐诗/poet.song.187000.json','["夾道香煙笑語歡，老翁扶立小兒觀。", "書生未有絲毫力，定憶前回去長官。"]'),
('357e9f5b-5b24-408d-8d82-d5e24d3127e2','牛渚曲','王遂','宋','宋诗','song-poetry','','[]','岷江赴東海，牛渚鎮中流。',288,'全唐诗/poet.song.187000.json','["岷江赴東海，牛渚鎮中流。", "古來濟渡處，落日迷滄洲。", "江東名勝士，清談付悠悠。", "氛埃更五閏，毒烈遍九州。", "六龍起當天，爝火不敢留。", "長繩繫佛塔，鐵纜濟王舟。", "執玉朝群后，職方登九丘。", "民生三代後，不數李與劉。", "太平二百年，內寧忘外憂。", "一馬飛渡江，王氣東南浮。", "誰爲逆胡計，敢作明神羞。", "飲水昧佛狸，投鞭效堅頭。", "蕭蕭楊林渡，寒日風颼飀。", "煙雨出蒙衝，霜雪揮戈矛。", "夜半虜帳驚，明日無胡酋。", "笑談折樽俎，心膽落氈裘。", "諸夷戒謀夏，三邊罷防秋。", "時從老校問，吃吃談不休。", "創業道何盛，中興德幾侔。", "禹績渺千載，武功待人收。", "天方厭此虜，吾忍忘其仇。", "偷安固大患，幸勝非良籌。", "外防固難弛，內政何當修。", "兩山點蛾眉，攢此千古愁。"]'),
('84fafe42-e75c-42fb-bf1f-20d36a7b4af3','堂後梅','王遂','宋','宋诗','song-poetry','','[]','阿母親栽白玉堂，分明雪色變青黄。',32,'全唐诗/poet.song.187000.json','["阿母親栽白玉堂，分明雪色變青黄。", "不須徙倚橫枝看，留作江南第一香。"]'),
('3ede8722-1176-4d10-8332-839f5d64cf7c','題卷舒堂竹','王遂','宋','宋诗','song-poetry','','[]','月淡星疏子夜清，獨騎黄鶴下吹笙。',32,'全唐诗/poet.song.187000.json','["月淡星疏子夜清，獨騎黄鶴下吹笙。", "當時只許風聽得，學與行雲佩玉聲。"]'),
('17cc24ad-663a-490a-b1a2-f4ab08d4ba9b','木犀答二吳書  其一','王遂','宋','宋诗','song-poetry','','[]','過盡人間百草芳，尚留寒菊對風光。',64,'全唐诗/poet.song.187000.json','["過盡人間百草芳，尚留寒菊對風光。", "月華已下中天白，香樹初摇滿院凉。", "金粟遠看千尺影，犀皮近種百年香。", "聖朝二桂真雙玉，王謝猶當著紫囊。"]'),
('55e94909-bd89-480b-86e4-385ab4a071b7','木犀答二吳書  其二','王遂','宋','宋诗','song-poetry','','[]','月窟何因左右探，猶容坐客競躋攀。',64,'全唐诗/poet.song.187000.json','["月窟何因左右探，猶容坐客競躋攀。", "渾疑移種從天上，又似分香入酒間。", "每爲高秋成感慨，却□清味得幽閑。", "先生燕坐真奇絕，願作淮南庾子山。"]'),
('5dad4a94-827d-410a-9d80-2ed70d3a35a7','飲御園梅下','王遂','宋','宋诗','song-poetry','','[]','主人鐵石廣平心，白玉堂中特細吟。',64,'全唐诗/poet.song.187000.json','["主人鐵石廣平心，白玉堂中特細吟。", "已覺江南得春晚，懸知塞北更寒深。", "放開清影登文局，寫出孤芳入素琴。", "保養陽和調鼎實，歲寒莫受雪霜侵。"]'),
('c89be65c-5098-420b-a07e-87881f125c1c','聞杜鵑有感','王遂','宋','宋诗','song-poetry','','[]','人物同爲氣所乘，良心露處即良能。',32,'全唐诗/poet.song.187000.json','["人物同爲氣所乘，良心露處即良能。", "天津有此驚康節，西蜀無之感少陵。"]'),
('c80f3437-8b50-49e1-b220-682318183997','題順寧庵','王遂','宋','宋诗','song-poetry','','[]','千章松檜護泉臺，無復牛羊日下來。',32,'全唐诗/poet.song.187000.json','["千章松檜護泉臺，無復牛羊日下來。", "安有良心親付授，却教容易着塵埃。"]'),
('af68936c-4073-4d95-ab80-07bacb6dc614','題蔣少閔雲巢','王遂','宋','宋诗','song-poetry','','[]','欲向雲端問子巢，陵虛騖遠恐疲勞。',32,'全唐诗/poet.song.187000.json','["欲向雲端問子巢，陵虛騖遠恐疲勞。", "懸知實地平如掌，何處人間有此高。"]'),
('a566d60e-9789-4a01-ae0d-200ede1c352a','秦丞相府','王遂','宋','宋诗','song-poetry','','[]','公府潭潭莫近前，絕憐荒草廢池邊。',64,'全唐诗/poet.song.187000.json','["公府潭潭莫近前，絕憐荒草廢池邊。", "骨藏黄壤今成土，樓入青雲舊格天。", "零落故家成不去，消磨名士向南遷。", "百年心事無人識，祇有雞林賈客傳。"]'),
('46c43053-bdd6-455a-913e-6047c310e4d6','登縣圃小樓','王遂','宋','宋诗','song-poetry','','[]','山有青黄臼紵山，謝公已起謫仙還。',32,'全唐诗/poet.song.187000.json','["山有青黄臼紵山，謝公已起謫仙還。", "至今猶有文章焰，放入高樓戶牖間。"]'),
('1e8fe7f2-34fb-4292-8837-6b9d1bb544f3','登尊經閣','王遂','宋','宋诗','song-poetry','','[]','月到長贏麥已秋，閑將心事付滄洲。',64,'全唐诗/poet.song.187000.json','["月到長贏麥已秋，閑將心事付滄洲。", "但慚一着輸先手，欲爲諸公讓出頭。", "山畔翩翩疑過雁，水邊帖帖似飛鷗。", "丈夫家法無多子，後樂須爲天下憂。"]'),
('e0e3d345-1c33-4ac2-a76e-c97f677d6db9','登楊府風雲閣','王遂','宋','宋诗','song-poetry','','[]','傑閣入風雲，分明是得君。',24,'全唐诗/poet.song.187000.json','["傑閣入風雲，分明是得君。", "湖山盡行樂，愁殺岳將軍。"]'),
('f81f9ea0-e111-4e7f-8e71-41c293be120d','登釣臺','王遂','宋','宋诗','song-poetry','','[]','老倦無心上將壇，桐江千尺一漁竿。',64,'全唐诗/poet.song.187000.json','["老倦無心上將壇，桐江千尺一漁竿。", "共時翻手功名易，自許經心歲月寬。", "禮樂三千輝冕輅，風雲四七盛衣冠。", "上虞人物饒娥路，贏得清高照歲寒。"]'),
('cd0297ff-8de5-4394-b4d7-2d541709d65b','登鳳臺','王遂','宋','宋诗','song-poetry','','[]','無覓臺城處，巋然却此臺。',48,'全唐诗/poet.song.187000.json','["無覓臺城處，巋然却此臺。", "青山三面立，白鳥半天回。", "有酒同僧上，無詩喚友來。", "謫仙騎鳳去，應是歎時哉。"]'),
('c9769674-2f45-4c03-a7f7-f9428fff61ff','題順寧壁  其一','王遂','宋','宋诗','song-poetry','','[]','養得翔鸞舞鳳枝，不知雨露幾含滋。',32,'全唐诗/poet.song.187000.json','["養得翔鸞舞鳳枝，不知雨露幾含滋。", "但同櫟社長無用，留作明堂柱石姿。"]'),
('dbddf7be-7e00-4e45-a0cc-1e13285c0670','題順寧壁  其二','王遂','宋','宋诗','song-poetry','','[]','墓道深衣自涕洟，分明入耳似聞詩。',32,'全唐诗/poet.song.187000.json','["墓道深衣自涕洟，分明入耳似聞詩。", "月征日邁求無忝，盡是臨深履薄時。"]'),
('cd4c1369-7eb8-4b57-b2bf-cd246d82f9ab','題順寧壁  其三','王遂','宋','宋诗','song-poetry','','[]','膝下當年憶教忠，此身卜與棄捐同。',32,'全唐诗/poet.song.187000.json','["膝下當年憶教忠，此身卜與棄捐同。", "睿思夜半憂民切，羞見東窗日半紅。"]'),
('ba374d26-66a6-4615-80eb-96d2d950abf2','題順寧壁  其四','王遂','宋','宋诗','song-poetry','','[]','小日寒窗共賦文，一時洛下看機雲。',32,'全唐诗/poet.song.187000.json','["小日寒窗共賦文，一時洛下看機雲。", "自知只道歸耕手，不比斯人解致君。"]'),
('3d250ae6-77c7-450f-b571-3609e08c8780','題順寧壁  其五','王遂','宋','宋诗','song-poetry','','[]','宿草初生木未陰，自栽松柏待成林。',32,'全唐诗/poet.song.187000.json','["宿草初生木未陰，自栽松柏待成林。", "後來剪伐應無忍，記取當時怵惕心。"]'),
('b8f228fa-c8df-4cae-ab15-cfed0b552c0e','題順寧壁  其六','王遂','宋','宋诗','song-poetry','','[]','道德文章滿足翁，曾將佳句詠茅峰。',32,'全唐诗/poet.song.187000.json','["道德文章滿足翁，曾將佳句詠茅峰。", "燒丹煉藥非吾事，孝友神仙第一功。"]'),
('cd691d76-f00b-4b0a-b05b-58e4ced1d7e8','題順寧壁  其七','王遂','宋','宋诗','song-poetry','','[]','江東山望說茅廬，庵爲康家孝子居。',32,'全唐诗/poet.song.187000.json','["江東山望說茅廬，庵爲康家孝子居。", "豈肯人間名教地，却容釋老說清虛。"]'),
('92179fa8-7f27-4548-a1f9-73750374867d','題順寧窗  其一','王遂','宋','宋诗','song-poetry','','[]','風生松檜雨生杉，抖擻泥塵恨滿衫。',32,'全唐诗/poet.song.187000.json','["風生松檜雨生杉，抖擻泥塵恨滿衫。", "從此便膺君命重，亦須昭穆葬江南。"]'),
('15275c75-ab92-45f0-9d94-abf0183db368','題順寧窗  其二','王遂','宋','宋诗','song-poetry','','[]','雲從西去又還東，不逐天回却逐風。',32,'全唐诗/poet.song.187000.json','["雲從西去又還東，不逐天回却逐風。", "春日豈無晴晝永，掃除陰翳出長空。"]'),
('72036ca8-c2d6-42f2-8785-28fb5b6cf9b3','夜宿鎮城寺','王遂','宋','宋诗','song-poetry','','[]','風挾潮頭上，雷將雨脚俱。',48,'全唐诗/poet.song.187000.json','["風挾潮頭上，雷將雨脚俱。", "天應念民物，地得限江湖。", "鑿堰流平未，頹堤浪入無。", "不眠頻問曉，白欲上人鬚。"]'),
('9610425f-2d70-40cd-8a69-664dd0edd443','夜宿梅山寺','王遂','宋','宋诗','song-poetry','','[]','山寺逢晚秋，郊原带雨餘。',48,'全唐诗/poet.song.187000.json','["山寺逢晚秋，郊原带雨餘。", "禾收將有耳，民病化爲魚。", "陰沴何當掃，兵氛苦未除。", "豈無吳市隠，封事至公車。"]'),
('d1b0039f-ad0d-4fdb-bfd4-2a0151be7200','口伐','王遂','宋','宋诗','song-poetry','','[]','口伐歸來戰馬閑，詩書只守一編殘。',32,'全唐诗/poet.song.187000.json','["口伐歸來戰馬閑，詩書只守一編殘。", "治安策裏多流涕，莫作興亡異代看。"]'),
('e35d97a6-14bc-41b7-bfc9-3e368030bfda','方丈壁讀胡邦衡書草','王遂','宋','宋诗','song-poetry','','[]','僧房高揭諫和書，知是高人意不虛。',32,'全唐诗/poet.song.187000.json','["僧房高揭諫和書，知是高人意不虛。", "我亦今年三十七，閉門畏禍獨何如。"]'),
('6a50d37e-fb07-4574-8069-4aa7a06ff4eb','戲題胡淡菴諫和書後','王遂','宋','宋诗','song-poetry','','[]','溪翁死後諫書焚，怪得和戎近有孫。',32,'全唐诗/poet.song.187000.json','["溪翁死後諫書焚，怪得和戎近有孫。", "寄語岳家新宰士，當時謝表幾行存。"]'),
('30be0df4-cdb9-470d-8421-7c1034df083d','敬亭山檢受御書','王遂','宋','宋诗','song-poetry','','[]','晉宋風流自不凡，天令此地爲回環。',64,'全唐诗/poet.song.187000.json','["晉宋風流自不凡，天令此地爲回環。", "市藏白水風煙外，路入高林紫翠間。", "字炳日星摇翰墨，敬存銘刻在心顔。", "須知太守緣民樂，來歲勤農在此山。"]'),
('daed806b-bf93-45fe-9de2-0ea933b5d04a','讀武侯傳','王遂','宋','宋诗','song-poetry','','[]','馬踏渭濱春草亂，鳥啼白帝夕陽深。',32,'全唐诗/poet.song.187000.json','["馬踏渭濱春草亂，鳥啼白帝夕陽深。", "漢家渾是皇天做，渠是通天一寸心。"]'),
('30d49ddd-9351-408b-891e-674d47c701b8','讀黨錮傳','王遂','宋','宋诗','song-poetry','','[]','須知明哲異全身，錯認中庸誤殺人。',64,'全唐诗/poet.song.187000.json','["須知明哲異全身，錯認中庸誤殺人。", "若使不爲群小惡，定應須有善人嗔。", "平生豈爲干名字，此念猶當質鬼神。", "劉氏興亡雖不補，却扶天地立君臣。"]'),
('bc4b14ab-f550-4fba-b6cb-e5611b0fd167','舟中誦陶詩及諸葛傳  其一','王遂','宋','宋诗','song-poetry','','[]','扣舷細讀淵明句，出聽還疑是水神。',32,'全唐诗/poet.song.187000.json','["扣舷細讀淵明句，出聽還疑是水神。", "江上只逢名利客，人間無復有斯人。"]'),
('8b62c758-643d-43ca-ae8b-187b38bd212b','舟中誦陶詩及諸葛傳  其二','王遂','宋','宋诗','song-poetry','','[]','隆中氣象接莘磻，心術精微日月寒。',32,'全唐诗/poet.song.187000.json','["隆中氣象接莘磻，心術精微日月寒。", "學到聖賢無盡處，一毫人力不容安。"]'),
('d8a13c36-51e0-439a-ab59-e9d6a633ed9b','讀文公壬子聞雷詩','王遂','宋','宋诗','song-poetry','','[]','五陽未决尚存陰，底事先王卧竹林。',32,'全唐诗/poet.song.187000.json','["五陽未决尚存陰，底事先王卧竹林。", "絕口不談當世務，對天惟有格君心。"]'),
('29e74d8c-dec8-40e4-a209-e9442478ae87','題游默齋詞後','王遂','宋','宋诗','song-poetry','','[]','游公已去今安在，學步虛聲過午清。',32,'全唐诗/poet.song.187000.json','["游公已去今安在，學步虛聲過午清。", "最喜高談言太極，一輪放下月華明。"]'),
('1b068d95-161d-4c79-887f-5d4ac6b41211','讀天寶諸公事  其一','王遂','宋','宋诗','song-poetry','','[]','當時群枉誤朝廷，血染長安草木腥。',32,'全唐诗/poet.song.187000.json','["當時群枉誤朝廷，血染長安草木腥。", "四罪不誅三宅去，依前肝腦是生靈。"]'),
('e89bdb78-43e9-4926-a013-e106b708c6cf','讀天寶諸公事  其二','王遂','宋','宋诗','song-poetry','','[]','忠賢赴國方憂北，姦黨全身却落南。',32,'全唐诗/poet.song.187000.json','["忠賢赴國方憂北，姦黨全身却落南。", "禍福難從當世問，是非時有老農談。"]'),
('b1b41f7b-4032-4376-9b08-166bdcd78e77','舟中坐讀鳶飛魚躍','王遂','宋','宋诗','song-poetry','','[]','欲晦又明天外山，水邊鷗鳥去復還。',32,'全唐诗/poet.song.187000.json','["欲晦又明天外山，水邊鷗鳥去復還。", "流行盡是鬼神迹，妙處不在鳶鳥間。"]'),
('4cf0c278-f675-4106-8ae1-6dac61d071bb','送浩翁赴梁縣','王遂','宋','宋诗','song-poetry','','[]','當年受氣便神明，未必冰壺有此清。',64,'全唐诗/poet.song.187000.json','["當年受氣便神明，未必冰壺有此清。", "自是胸中少凡近，猶須境外立功名。", "謫居歲月能聞道，多病工夫近養生。", "尚記漫塘曾有語，弟才無用不如兄。"]'),
('19d396d6-54f7-4c73-afe8-a48ed404498b','送李果州歸蜀','王遂','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','大原發鄒魯，功德被九州。',288,'全唐诗/poet.song.187000.json','["大原發鄒魯，功德被九州。", "迢迢數千年，伊洛乘其流。", "去之又百載，武夷闡諸幽。", "斯文代顯晦，天意非人謀。", "正脈遠相續，何必並世遊。", "峩峩陵陽山，下鎮西南陬。", "師法自心得，如親接前修。", "一氣妙亭毒，小大各有求。", "惟此生息機，不隔春與秋。", "皎皎冰雪姿，高疑揖浮丘。", "太虛麗日月，纖翳無停留。", "本根自深茂，况復加窮搜。", "微言析脈理，要指會衿喉。", "工夫自中積，應物乃其優。", "漢庭高論著，周原出咨諏。", "耿耿惻隠心，若將納諸溝。", "拳拳敬王義，敢有非嘉猷。", "俯視不義貴，如比空雲浮。", "所虞素學負，豈願清名收。", "閶闔入雲端，蜀天方阻修。", "西上香爐峰，江流去悠悠。", "問學久不明，風俗日以偷。", "塞口謹勿言，令人但深憂。", "世如大膏肓，終當待公瘳。"]'),
('eaafd0a5-9edc-4ff5-b1bc-bafbdbca5ec3','送三八弟歸九江  其一','王遂','宋','宋诗','song-poetry','','[]','堂堂襄敏公，揚旌上熙河。',48,'全唐诗/poet.song.187000.json','["堂堂襄敏公，揚旌上熙河。", "竹帛有時盡，勳業誰能磨。", "珍重紫陽翁，一言定群訛。", "世德遠如此，吾曹當若何。"]'),
('5164d2a9-9dab-4bf6-b255-1e8e543a3fa2','送三八弟歸九江  其二','王遂','宋','宋诗','song-poetry','','[]','義豐一世師，才識鮮其比。',48,'全唐诗/poet.song.187000.json','["義豐一世師，才識鮮其比。", "斯文張朱氏，稱許異諸子。", "不肯趨權門，南走雁山死。", "嗣子尚勉旃，興大庶有以。"]'),
('777b553c-27cc-4dde-b3f2-823d25872ed2','送三八弟歸九江  其三','王遂','宋','宋诗','song-poetry','','[]','弟從尋陽來，四閲槐庭夏。',48,'全唐诗/poet.song.187000.json','["弟從尋陽來，四閲槐庭夏。", "謹重子所優，淑艾吾猶寡。", "拜官京洛裏，歸思康廬下。", "學力要日新，聖言當具寫。"]'),
('6a86ac8e-747c-4a92-b8d3-1dd5b1038c04','送三八弟歸九江  其四','王遂','宋','宋诗','song-poetry','','[]','江公與二敏，同葬敷山陰。',48,'全唐诗/poet.song.187000.json','["江公與二敏，同葬敷山陰。", "下有虎豹藏，上有猩鼯吟。", "頗聞梁柱姿，時受斤斧侵。", "展轉不成寐，令人若爲心。"]'),
('74432956-0288-4215-a69c-96b3d23b5c0a','送三八弟歸九江  其五','王遂','宋','宋诗','song-poetry','','[]','燕公最繁盛，子孫十三支。',48,'全唐诗/poet.song.187000.json','["燕公最繁盛，子孫十三支。", "默數半凋零，坐愈成傷悲。", "學不足贏糧，貧或無置錐。", "先君尚有言，孫謀敢忘貽。"]'),
('519ca0f4-e812-4017-bbb5-4ea593c29d24','送三八弟歸九江  其六','王遂','宋','宋诗','song-poetry','','[]','北風馬猶感，首丘狐所思。',48,'全唐诗/poet.song.187000.json','["北風馬猶感，首丘狐所思。", "雙林去杳靄，荆溪對漣漪。", "春秋同社人，半是新相知。", "勳賢拊遺址，終當遂營茲。"]'),
('f94c6a32-e60a-4f4e-932d-7811e573232f','送三八弟歸九江  其七','王遂','宋','宋诗','song-poetry','','[]','濂溪周堂長，正學有源派。',48,'全唐诗/poet.song.187000.json','["濂溪周堂長，正學有源派。", "司直既高明，東湖更孤介。", "從遊欠勇往，思之令人灑。", "子歸日親炙，一一記言話。"]'),
('5d2ac820-1330-4e50-ac14-fe1d66071a19','送三八弟歸九江  其八','王遂','宋','宋诗','song-poetry','','[]','陸侯與鄒令，善政時所尊。',48,'全唐诗/poet.song.187000.json','["陸侯與鄒令，善政時所尊。", "爲我謝契闊，寄言托諸昆。", "送子華陽道，迤邐白下門。", "懷言欲贈別，臨別又忘言。"]'),
('9e5b63b4-ce53-49de-9753-440e9df955c0','送林幹榮滿歸莆','王遂','宋','宋诗','song-poetry','','[]','天向東南聚衆剛，義精仁熟乃真强。',64,'全唐诗/poet.song.187000.json','["天向東南聚衆剛，義精仁熟乃真强。", "清名去作明時重，鯁論來爲諫紙香。", "使指尚疑遲力薦，老夫何事不深藏。", "斯文歸有王劉重，胡不騎雲反帝鄉。"]'),
('05cb3760-1e37-4f22-8bc3-9333be61d170','送馮卿歸無錫  其一','王遂','宋','宋诗','song-poetry','','[]','天欲吾民起困窮，就教自擇孰如公。',64,'全唐诗/poet.song.187000.json','["天欲吾民起困窮，就教自擇孰如公。", "歡顔疾痛呻吟後，樂意耕桑隴畝中。", "儘有深長開幕畫，若無華藻到邊功。", "只今未覺詩書力，去久猶當說大馮。"]'),
('5d681bd5-7d87-4d6a-891b-f50394e824f2','送馮卿歸無錫  其二','王遂','宋','宋诗','song-poetry','','[]','浮雲出處泊無情，來輒成違去輒明。',64,'全唐诗/poet.song.187000.json','["浮雲出處泊無情，來輒成違去輒明。", "解后一時如失計，崢嶸千古却收名。", "靜修香火寧非願，歸對漁樵更覺榮。", "旋汲惠泉烹顧渚，春風杖屨及山行。"]'),
('790eab3e-db26-4d84-a6f3-a5e52bdd3526','送王冠卿罷郡歸  其一','王遂','宋','宋诗','song-poetry','','[]','自是經帷舊諫官，諫書字字吐忠肝。',64,'全唐诗/poet.song.187000.json','["自是經帷舊諫官，諫書字字吐忠肝。", "聲名尚作中朝重，事任寧辭舉世難。", "廩粟未紓民瘼急，邊烽誰解上憂寬。", "湖上佳處歸行樂，只恐憂時鼻轉酸。"]'),
('9cde9840-0386-4d5e-9e23-46eced03ab60','送王冠卿罷郡歸  其二','王遂','宋','宋诗','song-poetry','','[]','書生作縣本非才，天遣仁侯特爲來。',64,'全唐诗/poet.song.187000.json','["書生作縣本非才，天遣仁侯特爲來。", "民志少伸緣假借，軍諮無補愧招來。", "五湖舟楫聞催具，千乘旌旗莫挽回。", "若論親民須是令，先當斥免謝天災。"]'),
('350a7611-1275-47f2-a6bf-ca9e5fa6d94f','送黄叔向歸永嘉  其一','王遂','宋','宋诗','song-poetry','','[]','玉麟堂上共論兵，衆裏逢君眼爲明。',64,'全唐诗/poet.song.187000.json','["玉麟堂上共論兵，衆裏逢君眼爲明。", "自愧腐儒寧有用，却憐志士竟無成。", "學書不作千人敵，歸計猶餘一葉輕。", "何必封狼方快意，只須垂世用詩名。"]'),
('a7178fef-86e9-44ca-a4d4-67a9dff23d30','送黄叔向歸永嘉  其二','王遂','宋','宋诗','song-poetry','','[]','傳聞索米向長安，疎影寒香得細看。',64,'全唐诗/poet.song.187000.json','["傳聞索米向長安，疎影寒香得細看。", "檄羽風生常事急，舉頭霜滿致身難。", "五湖莫辦鴟夷計，四壁誰憐范叔寒。", "今代淮西宜糴穀，懸知一見定交驩。"]'),
('508ea746-b415-449d-975f-4a935d9893f4','送李兄謁揚州帥','王遂','宋','宋诗','song-poetry','','[]','天生忠定公，爲宋作柱石。',288,'全唐诗/poet.song.187000.json','["天生忠定公，爲宋作柱石。", "扶日起東南，擎天補西北。", "戎和不肯受，國蹙欲日闢。", "坐收兩河心，可制百年狄。", "誰能七十日，有此功赫奕。", "汪黄信血指，老檜甘愧色。", "云胡張趙間，不使虎而翼。", "循環起丁未，運至丁未極。", "成書遺後代，曰此寄庵力。", "思皇陳了翁，直諫少與匹。", "大科得聞孫，不救元符阨。", "讜議竟莫伸，嗟哉有何益。", "令人讀遺事，一飯三歎息。", "某昔守樵川，尊俎折群賊。", "烏洲聚名勝，花陰滿光澤。", "通鑑揭綱目，國錄爲刊刻。", "嗟嗟斯文喪，吾道有餘脈。", "感傷念理亂，同事異今昔。", "新從姑蘇歸，疾病久成癖。", "齊雲標傑閣，鵲橋記歸宅。", "偉哉子章子，爲我得佳客。", "母是了翁孫，身爲寄庵適。", "相求不相值，訪我茅山側。", "父昔仕九江，橫金悲易簀。"]'),
('ad0d295b-5c53-4647-bd34-ef28a8e02945','題端明蘇子瞻書天慶觀乳泉賦後','王遂','宋','宋诗','song-poetry','','[]','天一生兮上浮，羽人俟兮丹丘。',28,'全唐诗/poet.song.187000.json','["天一生兮上浮，羽人俟兮丹丘。", "遡儋耳兮東注，夾昆侖兮倒流。"]'),
('e88c8188-077f-4ae3-9291-83915e24162e','題朝散郎劉公廟','王遂','宋','宋诗','song-poetry','','[]','文而博兮樂且有餘，武有勇兮莫之測窺，閩之南兮江之西。',88,'全唐诗/poet.song.187000.json','["文而博兮樂且有餘，武有勇兮莫之測窺，閩之南兮江之西。", "俯視鼎鑊兮猶一潢池，士怯且惰兮若奉驕兒。", "一夫死兮百將莫支，提千人兮左右以之。", "嗟平生之志兮馬革裹屍，使畏死而偷生兮將形骸焉依。"]'),
('b9fd4732-d2c4-4441-903f-127306d75630','青溪橋','王遂','宋','宋诗','song-poetry','','[]','倬彼清溪兮山高水長，上承黟歙兮下接錢唐。',152,'全唐诗/poet.song.187000.json','["倬彼清溪兮山高水長，上承黟歙兮下接錢唐。", "雨稍漸漬兮衆流湯湯，家具舟楫兮商旅伏藏。", "繄四海以爲家兮何獨困此一方，視己同溺兮用造舟以爲梁。", "顧一歲之一新兮歲旱則亡，眷令長之遠慮兮不間雨暘。", "晴日當空兮余備不忘，帝用時以安下民兮余敢不强。", "雖傾余之囊橐兮使皆即乎康莊，彼慮如近憂兮令雖法而何傷。", "公雖憂而民喜兮百世烝嘗。"]'),
('eb15ec25-73f0-47b4-b5da-e941d5616de7','歲在辛酉改元嘉泰庚伏之末拉親友姚述之鮮長源黎元實逃暑南巖講河朔故事也聰山主從遊竟日因摘東坡山谷詩句集成四章題石壁以紀行','蘇植','宋','宋诗','song-poetry','','[]','江山松柏深復深，清風一榻抵千金。',128,'全唐诗/poet.song.187000.json','["江山松柏深復深，清風一榻抵千金。", "人間熱惱無處洗，借我一庵聊洗心。", "世上功名何日是，我生百事常隨緣。", "吟哦相對忌三伏，歌罷曲肱還醉眠。", "水邊林下逢衲子，我亦來追六月涼。", "傳得黄州新句法，茗搜文字響枯腸。", "作箇生涯終未是，誰能鐵裏鬭錚錚。", "相看領會一談勝，山自白雲江自橫。"]'),
('5ead5f21-14f5-41d8-8f86-60317f7b6078','詩一首','黄崇義','宋','宋诗','song-poetry','','[]','澗水之西我所家，結亭新借白鷗沙。',64,'全唐诗/poet.song.187000.json','["澗水之西我所家，結亭新借白鷗沙。", "旋移騷國春風木，滿種陶籬晚節花。", "陪客常留煨芋火，課兒頻煮讀書茶。", "清波迥與黄塵隔，一笑人生自有涯。"]'),
('d8075765-e3c0-4be6-ad0f-ec45715b35c0','龍壽山萬歲寺','樂章','宋','宋诗','song-poetry','','[]','風波暄白晝，雲雨暗空山。',48,'全唐诗/poet.song.187000.json','["風波暄白晝，雲雨暗空山。", "楚客驚停棹，湘妃慘濕鬟。", "化成羣木杪，砥柱衆流間。", "肸蠁通精意，行人易往還。"]'),
('09a1be62-f757-458a-9cd2-a16a903da02d','琵琶洲','饒魯','宋','宋诗','song-poetry','','[]','潯陽江上譜無傳，化作沙汀越水邊。',32,'全唐诗/poet.song.187000.json','["潯陽江上譜無傳，化作沙汀越水邊。", "一段遺音人不識，夜深幽咽下灘泉。"]'),
('585342de-7cd1-494c-8600-7dae92f3c579','石潭急峽','饒魯','宋','宋诗','song-poetry','','[]','兩山夾石湍風急，勢吼春雷鬼神泣。',128,'全唐诗/poet.song.187000.json','["兩山夾石湍風急，勢吼春雷鬼神泣。", "行人登舟不敢渡，疑有毒龍深處蟄。", "嶮巇彷彿若霅川，又如三峽傾潺湲。", "水竅恐是神禹鑿，石骨未遇秦皇鞭。", "飛流濺沫弄寒玉，赴壑奔灘勢何速。", "直須流入鏡湖心，如遇平夷舟免覆。", "垂楊覆陰沙岸高，將軍喚渡多英豪。", "中流擊楫思祖逖，當清宇宙無辭勞。"]'),
('f381ea4a-b5e1-416d-9d01-72f42b026e54','重湖夜月','饒魯','宋','宋诗','song-poetry','','[]','昔聞放翁歌鏡湖，船尾有酒船頭書。',128,'全唐诗/poet.song.187000.json','["昔聞放翁歌鏡湖，船尾有酒船頭書。", "又聞鑑湖賜賀老，剡川一曲春風好。", "番陽之東有重湖，風光與此真不殊。", "澄波湛湛秋瑩潔，碧月一片沈冰壺。", "彩舟蕩漾摇畫槳，上下天光映虛幌。", "踏歌搥鼓樂者誰，武陵樵客來湖上。", "賦詩橫槊何英雄，氣概或誇前兩翁。", "我思此景勞夢寐，東望咄咄徒書空。"]'),
('eb93cf50-f5e1-4815-8e8e-b9ac0d6aa76d','稠山茅屋','饒魯','宋','宋诗','song-poetry','','[]','亂山堆翠如削玉，中有幽人結茅屋。',128,'全唐诗/poet.song.187000.json','["亂山堆翠如削玉，中有幽人結茅屋。", "柴扉寂寂掩蒼苔，書院蕭蕭倚修竹。", "閒雲滿塹白日長，吚唔朝暮聲琅琅。", "芸窗紙破漏月影，石硯水滿涵天光。", "風塵頻動遍丘壑，此處怡然有真樂。", "門靜應無俗客過，茅深不怕秋風惡。", "高人有才濟當路，會見徵賢日三顧。", "愧我飄蓬石洞人，茅屋青山在何處。"]'),
('78c9a2c2-61fc-4b15-bb26-96633f7ae6fe','遠浦棹歌','饒魯','宋','宋诗','song-poetry','','[]','片帆雨霽飛烟江，漁翁停棹歌滄浪。',128,'全唐诗/poet.song.187000.json','["片帆雨霽飛烟江，漁翁停棹歌滄浪。", "一聲欵乃山水綠，浪中驚起雙鴛鴦。", "雙鴛鴦情一何美，同宿同飛在秋水。", "不似人生苦別離，女嫁征夫男戰死。", "五湖烟景方紛爭，聞歌頓欲思昇平。", "鄰舟短笛應風響，落日淡淡波冥冥。", "美人春詞誇艷麗，皓齒朱唇楚腰細。", "江樓富貴今如何，不似滄浪真趣味。"]'),
('bd531a1f-476b-4f59-afa4-c1faa3eca17f','春水番湖','饒魯','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','春湖浩浩無津涯，銀河之水天上來。',128,'全唐诗/poet.song.187000.json','["春湖浩浩無津涯，銀河之水天上來。", "波瀾萬頃清復濁，日光雲影相昭回。", "雄吞宇宙何寥廓，欲度冥鴻勢還却。", "南通海氣北長江，月出東兮日西落。", "當時神禹別九州，彭蠡之澤居上流。", "千年人物餘潤澤，況乃雄秀光潜虬。", "洪濤如山駕樓樐，春風夜夜喧鼙鼓。", "誰是江湖歸去人，扁舟范蠡隨漁父。"]'),
('ca0bf4b4-7c21-407c-a4ee-2f47f4e1fe9b','詠迎春黄胖','韓某','宋','宋诗','song-poetry','','[]','脚踏虛空手弄春，一人頭上要安身。',32,'全唐诗/poet.song.187000.json','["脚踏虛空手弄春，一人頭上要安身。", "忽然綫斷兒童手，骨肉都爲陌上塵。"]'),
('1e6555bf-d719-4b55-8724-7565c7733a87','遊淡巖陽華','毛方平','宋','宋诗','song-poetry','','[]','蜂房湒湒流石乳，綫竇涓涓細蛩語。',128,'全唐诗/poet.song.187000.json','["蜂房湒湒流石乳，綫竇涓涓細蛩語。", "門前乃作三峽聲，似與幽人商出處。", "何年結閣溷天真，危柱下侵蛟蜃怒。", "坐令空洞驚勃谿，仙鬼不無號帝所。", "要須濯足跨玉淵，枕石漱流滌塵務。", "手持白蓮騎赤鯶，萬壑千巖自風雨。", "窮荒秘穴天所靳，希有中州人訪古。", "山谷不來次山來，未可歉然懷不遇。"]'),
('d3d17623-3590-45e6-9eba-7ab55fdade9c','歸耕亭','楊承祖','宋','宋诗','song-poetry','','[]','决意歸耕景最佳，還珠門外足生涯。',64,'全唐诗/poet.song.187000.json','["决意歸耕景最佳，還珠門外足生涯。", "數椽卜築欣成趣，一水流通不用車。", "負郭有田宜䆉稏，繞城何處不荷花。", "柴門半掩誰來往，幸有隣僧可覓茶。"]'),
('159abfb3-6be6-4d3b-af15-8c3a5bd5d7f9','𤱶畝不忘君堂','楊承祖','宋','宋诗','song-poetry','','[]','一官落拓幾星霜，身遠朝廷心下忘。',64,'全唐诗/poet.song.187000.json','["一官落拓幾星霜，身遠朝廷心下忘。", "屢拜黄書叨試郡，何慚白首未爲郎。", "雲山縹緲如招隠，花木欣榮亦向陽。", "感激先皇曾賜對，至今朝服带天香。"]'),
('7be1f49d-6d8a-4360-a0f7-421f7b379e03','歸耕亭二首  其一','楊承祖','宋','宋诗','song-poetry','','[]','乘興登臨弗杖藤，絕巔未已覺身輕。',64,'全唐诗/poet.song.187000.json','["乘興登臨弗杖藤，絕巔未已覺身輕。", "新開竹徑從風入，小坐松岡待月生。", "江上數峰攢壁立，林間一閣礙雲行。", "凭欄朗誦昌黎句，水碧雙增遠目明。"]'),
('112e1c60-eb2a-4a33-96a5-bb52d276d536','歸耕亭二首  其二','楊承祖','宋','宋诗','song-poetry','','["\u897f\u6e56"]','丹青模寫費毫端，此景居然兩寺間。',64,'全唐诗/poet.song.187000.json','["丹青模寫費毫端，此景居然兩寺間。", "半嶺松陰觀鶴憇，一泓雪影照人顔。", "及時行樂恐無地，何事歸休始買山。", "多謝好風吹妙語，西湖處士棹舟還。"]'),
('840d69bd-49db-407e-916b-ee582bc9b98b','隠逸','趙庚夫','宋','宋诗','song-poetry','','[]','落魄蕉衫戴道冠，菖蒲滿案浸清寒。',64,'全唐诗/poet.song.187000.json','["落魄蕉衫戴道冠，菖蒲滿案浸清寒。", "有錢即買丹砂煉，無病猶將素問看。", "連日遊山僧共住，頻年乞米鶴同餐。", "世間不朽非鍾鼎，曾與高人靜處觀。"]'),
('88d6f1ff-9496-4736-8a14-3dead55b0f4f','道中逢潛夫','趙庚夫','宋','宋诗','song-poetry','','[]','相逢投草舍，對雨話移時。',48,'全唐诗/poet.song.187000.json','["相逢投草舍，對雨話移時。", "衣濕全無火，囊空各有詩。", "客程樵可問，日課僕皆知。", "未別情先惡，那堪遠別離。"]'),
('391fdd77-393e-4e73-84df-203610e10f45','習氣','趙庚夫','宋','宋诗','song-poetry','','[]','習氣年來已盡除，一窗長是讀方書。',64,'全唐诗/poet.song.187000.json','["習氣年來已盡除，一窗長是讀方書。", "家因護竹厨無筍，住偶隣僧飯有蔬。", "老去情懷多感舊，貧來親故不如初。", "幾時深入青山隠，木葉爲衣穩跨馿。"]'),
('fac38257-9d96-4b36-97f7-924c96069ba6','歲除即事','趙庚夫','宋','宋诗','song-poetry','','[]','連夜縫紉辦，今朝杵臼頻。',48,'全唐诗/poet.song.187000.json','["連夜縫紉辦，今朝杵臼頻。", "買花簪稚女，送米贈窮鄰。", "宦薄唯名在，年華與鬢新。", "桃符詩句好，恐動往來人。"]'),
('e1f0a12b-a069-4d95-9bd5-8a1a68f86cd7','讀曾茶山詩集','趙庚夫','宋','宋诗','song-poetry','','[]','茶山八十二癯仙，千首新詩手自編。',64,'全唐诗/poet.song.187000.json','["茶山八十二癯仙，千首新詩手自編。", "吟到瘴烟因避寇，貴登從橐只棲禪。", "新於月出初三夜，澹比湯煎第一泉。", "咄咄逼人門弟子，劍南已見祖燈傳。"]'),
('4ff6b840-6a36-424c-a166-1a7e68d1c74f','鬢髭','趙庚夫','宋','宋诗','song-poetry','','[]','鬢髭漸漸長霜莖，老聽山中雀唳聲。',64,'全唐诗/poet.song.187000.json','["鬢髭漸漸長霜莖，老聽山中雀唳聲。", "九死得生尤可重，百年幾日更多營。", "自參梵夾機心息，專食藜羹胃氣清。", "檢點依然魔障在，草堂釣艇未忘情。"]'),
('6785249f-98fa-4f8a-809e-29a36d370346','心宇','趙庚夫','宋','宋诗','song-poetry','','[]','心宇今無一點塵，面毛徑寸垢生鱗。',64,'全唐诗/poet.song.187000.json','["心宇今無一點塵，面毛徑寸垢生鱗。", "齋時野雀臨薌几，定裏山蜂立葛巾。", "欲喚羲黄談太古，自疑嵇阮即前身。", "兒童共指深衣笑，問是秦人是晉人。"]'),
('04ec6c43-e4ff-4350-b244-c75d226dd235','病足','趙庚夫','宋','宋诗','song-poetry','','[]','老病侵陵藥不靈，雪窗燈火冷如螢。',64,'全唐诗/poet.song.187000.json','["老病侵陵藥不靈，雪窗燈火冷如螢。", "未應安隠青蓮足，便學蹁躚病鶴形。", "意恐夢中輕獻璞，怒思天上去鞭霆。", "露華水泡何堪惜，獨念名山未徧經。"]');
